document.addEventListener("dragstart", handleGlobalDragStart);
document.addEventListener("dragover", handleGlobalDragOver);
document.addEventListener("drop", (event) => {
  void handleGlobalDrop(event).catch((error) => {
    handleEditorRuntimeError(error, "拖拽导入");
  });
});
document.addEventListener("dragend", handleGlobalDragEnd);

if (refs.assetImportDropzone) {
  refs.assetImportDropzone.addEventListener("dragenter", handleAssetDragEnter);
  refs.assetImportDropzone.addEventListener("dragover", handleAssetDragOver);
  refs.assetImportDropzone.addEventListener("dragleave", handleAssetDragLeave);
  refs.assetImportDropzone.addEventListener("drop", (event) => {
    void handleAssetDrop(event);
  });
}

if (refs.storyBlockList) {
  refs.storyBlockList.addEventListener("dragstart", handleStoryBlockDragStart);
  refs.storyBlockList.addEventListener("dragover", handleStoryBlockDragOver);
  refs.storyBlockList.addEventListener("drop", (event) => {
    void handleStoryBlockDrop(event);
  });
  refs.storyBlockList.addEventListener("dragend", handleStoryBlockDragEnd);
}

if (refs.previewStage) {
  refs.previewStage.addEventListener("click", handlePreviewStageClick);
  refs.previewStage.addEventListener("contextmenu", handlePreviewStageContextMenu);
}

installEngineDialogBridge();
init();

async function init() {
  try {
    setProjectChromeEnabled(false);
    state.projectCenter = await loadProjectCenter();
    refs.loadingState.classList.add("is-hidden");
    refs.errorState.classList.add("is-hidden");
    openProjectCenter({ keepStatus: true });
  } catch (error) {
    state.loadErrorStage = "editor_startup";
    setSaveStatus("载入失败", true);
    refs.loadingState.classList.add("is-hidden");
    refs.errorState.classList.remove("is-hidden");
    refs.errorMessage.textContent = getEditorStartupErrorMessage(error);
    focusErrorStatePrimaryAction();
    console.error(error);
  }
}

function getEditorStartupErrorMessage(error) {
  const detail = getErrorDetailMessage(
    error,
    "编辑器没有载入成功，请确认编辑器服务仍在运行，然后刷新重试。"
  );
  return `编辑器没有载入成功。\n\n${detail}\n\n可以确认启动窗口没有关闭，或重新运行启动脚本后刷新页面。`;
}

async function fetchEditorResource(url, options = {}, contextLabel = "请求") {
  try {
    return await fetch(url, options);
  } catch (error) {
    throw new Error(`${contextLabel}无法连接到编辑器后端，请确认编辑器服务仍在运行，然后刷新重试。`);
  }
}

async function loadProjectCenter() {
  const response = await fetchEditorResource(API_PROJECT_CENTER, {}, "读取项目列表");
  const result = await readJsonResponse(response, { contextLabel: "读取项目列表" });
  const resultObject = result && typeof result === "object" ? result : {};

  if (!response.ok) {
    throw new Error(resultObject.error ?? `读取项目列表失败，状态码 ${response.status}`);
  }

  return {
    activeProjectId: resultObject.activeProjectId ?? null,
    projects: Array.isArray(resultObject.projects) ? resultObject.projects : [],
  };
}

async function loadProjectData() {
  const response = await fetchEditorResource(API_PROJECT_DATA, {}, "读取项目数据");
  const result = await readJsonResponse(response, { contextLabel: "读取项目数据" });
  const bundle = result && typeof result === "object" ? result : {};

  if (!response.ok || bundle.ok === false) {
    const loadError = new Error(bundle.error ?? `读取项目数据失败，状态码 ${response.status}`);
    loadError.recovery = bundle.recovery ?? null;
    throw loadError;
  }

  const project = bundle.project ?? {};
  const chapters = bundle.chapters ?? [];
  const assetList = bundle.assets?.assets ?? [];
  const characters = bundle.characters?.characters ?? [];
  const variables = bundle.variables?.variables ?? [];
  const scenes = [];
  const scenesById = new Map();
  const chaptersById = new Map();
  const assetsById = new Map(assetList.map((asset) => [asset.id, asset]));
  const charactersById = new Map(characters.map((character) => [character.id, character]));
  const variablesById = new Map(variables.map((variable) => [variable.id, variable]));

  chapters.forEach((chapter) => {
    chaptersById.set(chapter.chapterId, chapter);
    (chapter.scenes ?? []).forEach((scene) => {
      scenes.push({
        ...scene,
        chapterId: chapter.chapterId,
        chapterName: chapter.name,
      });
      scenesById.set(scene.id, {
        ...scene,
        chapterId: chapter.chapterId,
        chapterName: chapter.name,
      });
    });
  });

  const assetUsage = buildAssetUsageMap({
    chapters,
    characters,
    charactersById,
  });

  return {
    project,
    currentProject: bundle.currentProject ?? null,
    history: bundle.history ?? null,
    sessionRecovery: bundle.sessionRecovery ?? null,
    chapters,
    chaptersById,
    scenes,
    scenesById,
    assetList,
    assetsById,
    characters,
    charactersById,
    variables,
    variablesById,
    assetUsage,
  };
}

function setProjectChromeEnabled(enabled) {
  refs.projectNavButtons.forEach((button) => {
    button.disabled = false;
    button.classList.toggle("is-project-locked", !enabled);
    if (!enabled) {
      button.title = "先新建或打开一个项目后可用";
    } else {
      button.removeAttribute("title");
    }
  });
}

function getSafeProjectSessionRecovery(recovery = state.projectSessionRecovery) {
  if (projectHistoryTools?.getSafeProjectSessionRecovery) {
    return projectHistoryTools.getSafeProjectSessionRecovery(recovery);
  }

  if (!recovery || typeof recovery !== "object") {
    return {
      noticeActive: false,
      lastUnexpectedExitAt: "",
      lastUnexpectedExitStartedAt: "",
      lastEndedReason: "",
      message: "",
    };
  }

  return {
    noticeActive: Boolean(recovery.noticeActive),
    lastUnexpectedExitAt: String(recovery.lastUnexpectedExitAt ?? "").trim(),
    lastUnexpectedExitStartedAt: String(recovery.lastUnexpectedExitStartedAt ?? "").trim(),
    lastEndedReason: String(recovery.lastEndedReason ?? "").trim(),
    message: String(recovery.message ?? "").trim(),
  };
}

function getSafeProjectHistory(history = state.projectHistory) {
  if (projectHistoryTools?.getSafeProjectHistory) {
    return projectHistoryTools.getSafeProjectHistory(history);
  }

  if (!history || typeof history !== "object") {
    return {
      totalSnapshots: 0,
      currentIndex: -1,
      canUndo: false,
      canRedo: false,
      currentSnapshot: null,
      previousSnapshot: null,
      nextSnapshot: null,
      recentSnapshots: [],
      timelineSnapshots: [],
    };
  }

  return {
    totalSnapshots: Number(history.totalSnapshots ?? 0),
    currentIndex: Number(history.currentIndex ?? -1),
    canUndo: Boolean(history.canUndo),
    canRedo: Boolean(history.canRedo),
    currentSnapshot: history.currentSnapshot ?? null,
    previousSnapshot: history.previousSnapshot ?? null,
    nextSnapshot: history.nextSnapshot ?? null,
    recentSnapshots: Array.isArray(history.recentSnapshots) ? history.recentSnapshots : [],
    timelineSnapshots: Array.isArray(history.timelineSnapshots) ? history.timelineSnapshots : [],
  };
}

function getHistorySnapshotByIndex(targetIndex, history = state.projectHistory) {
  if (projectHistoryTools?.getHistorySnapshotByIndex) {
    return projectHistoryTools.getHistorySnapshotByIndex(targetIndex, history);
  }

  const safeHistory = getSafeProjectHistory(history);
  const numericIndex = Number(targetIndex);
  if (Number.isNaN(numericIndex)) {
    return null;
  }
  return safeHistory.timelineSnapshots.find((snapshot) => Number(snapshot.index) === numericIndex) ?? null;
}

function getHistoryKindLabel(kind) {
  if (projectHistoryTools?.getHistoryKindLabel) {
    return projectHistoryTools.getHistoryKindLabel(kind);
  }

  if (kind === "manual") {
    return "手动检查点";
  }
  if (kind === "baseline") {
    return "项目基线";
  }
  return "自动快照";
}

function getHistoryKindTone(kind) {
  if (projectHistoryTools?.getHistoryKindTone) {
    return projectHistoryTools.getHistoryKindTone(kind);
  }

  if (kind === "manual") {
    return "good";
  }
  if (kind === "baseline") {
    return "soft";
  }
  return "warn";
}

function getSafeHistoryFilterMode(value) {
  if (projectHistoryTools?.getSafeHistoryFilterMode) {
    return projectHistoryTools.getSafeHistoryFilterMode(value);
  }

  return ["all", "manual", "auto", "baseline", "current"].includes(value) ? value : "all";
}

function getHistoryFilterLabel(value) {
  if (projectHistoryTools?.getHistoryFilterLabel) {
    return projectHistoryTools.getHistoryFilterLabel(value);
  }

  const labels = {
    all: "全部版本",
    manual: "只看检查点",
    auto: "只看自动快照",
    baseline: "只看基线",
    current: "只看当前版本",
  };
  return labels[getSafeHistoryFilterMode(value)] ?? labels.all;
}

function getHistoryChangeKindLabel(kind) {
  if (projectHistoryTools?.getHistoryChangeKindLabel) {
    return projectHistoryTools.getHistoryChangeKindLabel(kind);
  }

  if (kind === "created") {
    return "新增";
  }
  if (kind === "removed") {
    return "移除";
  }
  return "改动";
}

function getFilteredHistorySnapshots(history = state.projectHistory) {
  if (projectHistoryTools?.getFilteredHistorySnapshots) {
    return projectHistoryTools.getFilteredHistorySnapshots(history, {
      searchQuery: state.historySearchQuery,
      filterMode: state.historyFilterMode,
      formatDate,
    });
  }

  const safeHistory = getSafeProjectHistory(history);
  const query = String(state.historySearchQuery ?? "").trim().toLowerCase();
  const filterMode = getSafeHistoryFilterMode(state.historyFilterMode);

  return (safeHistory.timelineSnapshots ?? []).filter((snapshot) => {
    if (filterMode === "manual" && snapshot.kind !== "manual") {
      return false;
    }
    if (filterMode === "auto" && snapshot.kind !== "auto") {
      return false;
    }
    if (filterMode === "baseline" && snapshot.kind !== "baseline") {
      return false;
    }
    if (filterMode === "current" && !snapshot.isCurrent) {
      return false;
    }
    if (!query) {
      return true;
    }

    const haystack = [snapshot.label, getHistoryKindLabel(snapshot.kind), formatDate(snapshot.createdAt)]
      .filter(Boolean)
      .join(" ")
      .toLowerCase();
    return haystack.includes(query);
  });
}

function renderHistorySnapshotCard(snapshot, options = {}) {
  return projectHistoryTools.renderHistorySnapshotCard(snapshot, {
    ...options,
    escapeHtml,
    formatDate,
    getDashboardTaskToneClass,
  });
}

function renderHistoryTimeline(history = state.projectHistory, options = {}) {
  return projectHistoryTools.renderHistoryTimeline(history, {
    ...options,
    escapeHtml,
    formatDate,
    getDashboardTaskToneClass,
  });
}

function formatHistoryRestorePreview(preview) {
  if (projectHistoryTools?.formatHistoryRestorePreview) {
    return projectHistoryTools.formatHistoryRestorePreview(preview);
  }

  if (!preview || typeof preview !== "object") {
    return "恢复后会把项目回到你选中的那个时间点。";
  }

  const changedFileCount = Number(preview.changedFileCount ?? 0);
  if (changedFileCount <= 0) {
    return "当前版本和目标版本没有差异。";
  }

  const changedItems = Array.isArray(preview.changedItems) ? preview.changedItems : [];
  const detailLines = changedItems
    .slice(0, 6)
    .map((item) => `- ${item.label ?? item.path ?? "未知内容"}（${getHistoryChangeKindLabel(item.kind)}）`);
  const hiddenCount = Math.max(changedItems.length - detailLines.length, 0);
  return [
    `恢复后会影响 ${changedFileCount} 处内容。`,
    detailLines.length > 0 ? "" : null,
    ...detailLines,
    hiddenCount > 0 ? `- 另外还有 ${hiddenCount} 处变化` : null,
  ]
    .filter(Boolean)
    .join("\n");
}

function updateErrorRecoveryState(history = state.projectHistory) {
  if (!refs.errorRecoveryState || !refs.errorRecoveryMessage || !refs.historyRestoreButton) {
    return;
  }

  const safeHistory = getSafeProjectHistory(history);
  const canRestore = safeHistory.canUndo;
  const currentLabel = safeHistory.currentSnapshot?.label ?? "当前版本";
  const previousLabel = safeHistory.previousSnapshot?.label ?? "上个版本";
  refs.errorRecoveryState.classList.toggle("is-hidden", safeHistory.totalSnapshots === 0);
  refs.errorRecoveryMessage.textContent =
    safeHistory.totalSnapshots === 0
      ? "如存在可用的自动保存版本，这里会显示恢复入口。"
      : canRestore
        ? `已经找到 ${safeHistory.totalSnapshots} 份自动快照。当前停在「${currentLabel}」，可以尝试恢复到「${previousLabel}」。`
        : `已经找到 ${safeHistory.totalSnapshots} 份自动快照，但当前已经是最早版本「${currentLabel}」。`;

  if (refs.errorRecoverButton) {
    refs.errorRecoverButton.disabled = !canRestore;
  }

  if (refs.errorRecoveryTimeline) {
    refs.errorRecoveryTimeline.innerHTML =
      safeHistory.totalSnapshots > 0 ? renderHistoryTimeline(safeHistory, { compact: true, allowRelabel: false }) : "";
  }
}

function showFatalProjectLoadError(error) {
  state.loadErrorStage = "project_load";
  refs.loadingState.classList.add("is-hidden");
  refs.projectCenterState.classList.add("is-hidden");
  refs.appMain.classList.add("is-hidden");
  refs.errorState.classList.remove("is-hidden");
  refs.errorMessage.textContent = getProjectLoadErrorMessage(error);
  state.data = null;
  state.validation = null;
  state.lastExportResult = null;
  state.projectHistory = error?.recovery ?? null;
  state.projectSessionRecovery = null;
  setProjectChromeEnabled(false);
  updateErrorRecoveryState();
  updateTopbar();
  setSaveStatus("项目载入失败", true);
  focusErrorStatePrimaryAction();
}

function getProjectLoadErrorMessage(error) {
  const detail = getErrorDetailMessage(error, "项目没有载入成功，请稍后再试一次。");
  return `项目没有载入成功。\n\n${detail}\n\n如果这里显示了自动快照，可以先尝试恢复到上一个版本。`;
}

function getLoadErrorProjectTitle(options = {}) {
  const explicitTitle = String(options.projectTitle ?? "").trim();
  if (explicitTitle) {
    return explicitTitle;
  }

  const currentProjectTitle = String(state.data?.project?.title ?? "").trim();
  if (currentProjectTitle) {
    return currentProjectTitle;
  }

  const activeProjectId = state.data?.project?.projectId ?? state.projectCenter?.activeProjectId ?? null;
  const projectCenterTitle = String(
    (state.projectCenter?.projects ?? []).find((project) => project?.projectId === activeProjectId)?.title ?? ""
  ).trim();

  return projectCenterTitle || "未打开项目";
}

function getLoadErrorStageLabel(options = {}) {
  const explicitLabel = String(options.stageLabel ?? "").trim();
  if (explicitLabel) {
    return explicitLabel;
  }

  const stage = String(options.stage ?? state.loadErrorStage ?? "").trim();
  if (stage === "editor_startup") {
    return "编辑器启动";
  }
  if (stage === "project_load") {
    return "项目载入";
  }

  return "未标记";
}

function getLoadErrorRecoverySummary(options = {}) {
  const explicitSummary = String(options.recoverySummary ?? "").trim();
  if (explicitSummary) {
    return explicitSummary;
  }

  const history = getSafeProjectHistory(options.history ?? state.projectHistory);
  if (history.totalSnapshots <= 0) {
    return "";
  }

  if (!history.canUndo) {
    return `${history.totalSnapshots} 份，当前已是最早版本`;
  }

  const previousLabel = String(history.previousSnapshot?.label ?? "").trim();
  return previousLabel
    ? `${history.totalSnapshots} 份，可恢复到「${previousLabel}」`
    : `${history.totalSnapshots} 份，可恢复到上个版本`;
}

function buildLoadErrorFeedbackText(message, options = {}) {
  const cleanMessage = String(message ?? "").trim();
  if (!cleanMessage) {
    return "";
  }

  const capturedAt = options.capturedAt ?? new Date().toISOString();
  const pageUrl = options.pageUrl ?? globalThis.location?.href ?? "未知页面";
  const stageLabel = getLoadErrorStageLabel(options);
  const projectTitle = getLoadErrorProjectTitle(options);
  const releaseVersion = options.releaseVersion ?? (state.data ? getProjectReleaseVersion() : "");
  const recoverySummary = getLoadErrorRecoverySummary(options);
  const lines = [
    "# Canvasia Engine 错误反馈",
    "",
    `时间：${capturedAt}`,
    `页面：${pageUrl}`,
    `阶段：${stageLabel}`,
    `项目：${projectTitle}`,
  ];

  if (releaseVersion) {
    lines.push(`项目版本：${releaseVersion}`);
  }

  if (recoverySummary) {
    lines.push(`自动快照：${recoverySummary}`);
  }

  lines.push("", "错误信息：", cleanMessage);
  return lines.join("\n");
}

function focusErrorStatePrimaryAction() {
  const focusTarget = refs.errorState?.querySelector?.('[data-action="reload-editor-page"]');
  if (typeof focusTarget?.focus !== "function") {
    return false;
  }

  focusTarget.focus({ preventScroll: true });
  return true;
}

function isErrorStateVisible() {
  return Boolean(refs.errorState && !refs.errorState.classList.contains("is-hidden"));
}

async function copyCurrentLoadErrorMessage() {
  const message = String(refs.errorMessage?.textContent ?? "").trim();
  if (!message) {
    setSaveStatus("当前没有可复制的错误信息", true);
    showToast("当前没有可复制的错误信息", "error");
    return false;
  }

  const copied = await copyTextToClipboard(buildLoadErrorFeedbackText(message));
  if (!copied) {
    setSaveStatus("错误信息复制失败", true);
    showToast("复制失败，可以手动选中错误信息", "error");
    return false;
  }

  setSaveStatus("错误信息已复制，可直接粘贴到反馈里");
  showToast("错误信息已复制");
  return true;
}

function reloadEditorPage() {
  setSaveStatus("正在重新载入编辑器...");
  showToast("正在重新载入编辑器");

  try {
    if (typeof globalThis.location?.reload === "function") {
      globalThis.location.reload();
      return true;
    }
  } catch (error) {
    console.warn("[Canvasia Engine] Reload from error state failed", error);
  }

  setSaveStatus("浏览器没有允许自动刷新，请手动刷新页面", true);
  showToast("请手动刷新页面", "error");
  return false;
}

function handleProjectLoadFailure(error) {
  if (error?.recovery) {
    showFatalProjectLoadError(error);
    showToast("项目打开失败，但已经找到可恢复的自动快照", "error");
    return true;
  }

  return false;
}

async function showCopyableOperationFailure(error, title, detailPrefix) {
  const detailMessage = getErrorDetailMessage(error);
  setSaveStatus(getErrorSummaryLine(error, title), true);
  showToast(`${title}，已列出原因`, "error");
  await showEngineAlert({
    title,
    message: `${detailPrefix}：\n${detailMessage}`,
    tone: "warning",
    copyable: true,
    confirmLabel: "我知道了",
  });
}

async function showProjectCenterFailure(error, title, detailPrefix) {
  await showCopyableOperationFailure(error, title, detailPrefix);
}

async function showEditorOperationFailure(error, title, detailPrefix) {
  await showCopyableOperationFailure(error, title, detailPrefix);
}

async function maybePromptProjectRecovery(data = state.data) {
  if (!data?.project?.projectId) {
    return;
  }

  const recovery = getSafeProjectSessionRecovery(data.sessionRecovery ?? state.projectSessionRecovery);
  const history = getSafeProjectHistory(data.history ?? state.projectHistory);
  const previousSnapshot =
    projectHistoryTools?.getPreviousHistorySnapshot?.(history) ??
    history.previousSnapshot ??
    getHistorySnapshotByIndex(Number(history.currentIndex) - 1, history);
  const promptKey =
    projectHistoryTools?.buildProjectRecoveryPromptKey?.(data.project.projectId, recovery) ??
    `${data.project.projectId}:${recovery.lastUnexpectedExitAt || recovery.lastUnexpectedExitStartedAt || "none"}`;

  if (!recovery.noticeActive || !previousSnapshot || state.historyRecoveryPromptKey === promptKey) {
    return;
  }

  state.historyRecoveryPromptKey = promptKey;
  const shouldRestore = await confirmRestoreProjectHistorySnapshot(previousSnapshot, {
    introText: "检测到上次可能没有正常退出。是否恢复到上次安全点？",
  });

  if (shouldRestore) {
    await applyProjectHistoryAction("restore", {
      targetIndex: Number(previousSnapshot.index ?? history.currentIndex - 1),
      snapshotLabel: previousSnapshot.label ?? "上次安全点",
      acknowledgeRecoveryNotice: true,
    });
    return;
  }

  showToast("稍后仍可在首页的项目安全网中恢复到上次安全点");
}

