function renderScriptRecordingGroupSection(filteredEntries, { compact = false } = {}) {
  const groups = buildScriptRecordingGroups(filteredEntries).filter((group) => group.pendingCount > 0);

  if (groups.length === 0) {
    return compact
      ? ""
      : `
          <article class="detail-card voice-recording-panel">
            <strong>待录分组总览</strong>
            <p>当前筛选里暂时没有待录音台词，或者这些台词已经都有真实语音文件了。</p>
          </article>
        `;
  }

  const visibleGroups = compact ? groups.slice(0, 3) : groups;
  return `
    <section class="voice-recording-panel">
      <div class="panel-heading">
        <h2>待录分组总览</h2>
        <span class="badge badge-soft">按角色 / 章节排开更方便录音</span>
      </div>
      <div class="voice-recording-grid">
        ${visibleGroups.map((group) => renderScriptRecordingGroupCard(group)).join("")}
      </div>
      ${
        compact && groups.length > visibleGroups.length
          ? `<div class="helper-text">高级模式下会展开完整分组，目前先显示最值得先录的 ${visibleGroups.length} 批。</div>`
          : ""
      }
    </section>
  `;
}

