function buildScriptDirectionIdeas(entries) {
  return entries
    .map((entry) => {
      const text = String(entry.sourceText ?? "").trim();
      if (!text) {
        return null;
      }

      const suggestions = [];

      if (entry.type === "choice") {
        suggestions.push({
          effect: "黑场淡入淡出",
          reason: "分支切换点",
          helper: "适合先停一下，再用黑场或白场把路线切开。",
          score: 34,
        });
      }

      if (/(回忆|曾经|那一天|那天|想起|仿佛|梦里|记得)/.test(text)) {
        suggestions.push({
          effect: "回忆滤镜",
          reason: "回忆感",
          helper: "这句很适合加暖色回忆、黑白回忆或梦境柔光。",
          score: 32,
        });
      }

      if (entry.type === "narration" && /(雨|雪|樱|花瓣|风|夜风|微风|光尘|落叶|雾)/.test(text)) {
        suggestions.push({
          effect: "粒子特效",
          reason: "气氛词",
          helper: "可以先试雪花、雨丝、樱花或光尘，把环境感抬起来。",
          score: 30,
        });
      }

      if (/(突然|猛地|一瞬间|砰|啪|轰|刺眼|震|惊)/.test(text)) {
        suggestions.push({
          effect: "闪屏",
          reason: "瞬时冲击",
          helper: "这种词很适合用闪屏或短震动制造瞬间冲击。",
          score: 28,
        });
      }

      if (entry.type === "dialogue" && /[!！]/.test(text)) {
        suggestions.push({
          effect: "屏幕震动",
          reason: "情绪爆点",
          helper: "感叹语气很适合轻震或明显震动，把情绪往上提。",
          score: 26,
        });
      }

      if (entry.type === "dialogue" && /[?？]/.test(text)) {
        suggestions.push({
          effect: "镜头推近拉远",
          reason: "疑问悬念",
          helper: "疑问句很适合轻推近，能把注意力压到角色脸上。",
          score: 24,
        });
      }

      if (entry.type === "narration" && entry.contentLength >= 28) {
        suggestions.push({
          effect: "镜头平移",
          reason: "长句铺陈",
          helper: "长旁白适合慢慢平移或缓推，让文字和画面一起铺开。",
          score: 20,
        });
      }

      if (entry.type === "dialogue" && entry.contentLength >= 26) {
        suggestions.push({
          effect: "镜头推近拉远",
          reason: "长句独白",
          helper: "这种比较长的台词可以配轻推近，减少画面太平的问题。",
          score: 18,
        });
      }

      if (entry.type === "dialogue" && entry.expressionName && !/默认|普通|平静/.test(entry.expressionName)) {
        suggestions.push({
          effect: "角色淡入淡出",
          reason: `表情：${entry.expressionName}`,
          helper: "如果这是情绪转折点，可以让立绘或镜头有一个更明显的入场强调。",
          score: 16,
        });
      }

      if (entry.type === "dialogue" && entry.voiceStatus === "missing" && /[!！?？]/.test(text)) {
        suggestions.push({
          effect: "补语音 + 强调演出",
          reason: "值得重点补声线",
          helper: "这句情绪已经很明确，补语音以后会特别容易立住。",
          score: 14,
        });
      }

      if (suggestions.length === 0) {
        return null;
      }

      const ranked = suggestions.sort((left, right) => right.score - left.score);
      const top = ranked[0];
      return {
        entry,
        effect: top.effect,
        score: top.score,
        rankLabel: `适合加：${top.effect}`,
        reasons: ranked.slice(0, 3).map((item) => item.reason),
        helperText: top.helper,
      };
    })
    .filter(Boolean)
    .sort((left, right) => right.score - left.score)
    .slice(0, 5);
}

function buildScriptVoiceTodoQueue(entries) {
  return entries
    .filter((entry) => entry.type === "dialogue" && entry.voiceStatus === "missing")
    .map((entry) => {
      const reasons = [];
      const emotionScore = /[!！]/.test(entry.sourceText) ? 1 : 0;
      const questionScore = /[?？]/.test(entry.sourceText) ? 1 : 0;
      const longScore = entry.contentLength >= 24 ? 1 : 0;
      const issueScore = (entry.issues ?? []).length;

      if (emotionScore) {
        reasons.push("情绪台词");
      }
      if (questionScore) {
        reasons.push("疑问语气");
      }
      if (longScore) {
        reasons.push("句子偏长");
      }
      if (entry.expressionName && !/默认|普通|平静/.test(entry.expressionName)) {
        reasons.push(`表情：${entry.expressionName}`);
      }
      if (issueScore > 1) {
        reasons.push("问题较多");
      }

      const score =
        Math.min(entry.contentLength, 42) +
        emotionScore * 20 +
        questionScore * 12 +
        longScore * 10 +
        issueScore * 8 +
        (reasons.some((reason) => reason.startsWith("表情：")) ? 6 : 0);

      return {
        entry,
        score,
        rankLabel: `优先补 ${Math.max(1, Math.round(score / 12))}`,
        reasons: reasons.slice(0, 3),
        helperText: entry.expressionName || "这句还没绑语音",
      };
    })
    .sort((left, right) => right.score - left.score)
    .slice(0, 4);
}

function buildScriptVoiceBatchSuggestions(entries) {
  const groups = new Map();

  entries
    .filter((entry) => entry.type === "dialogue" && entry.voiceStatus === "missing" && entry.characterId)
    .forEach((entry) => {
      const key = `${entry.characterId}:${entry.chapterId}`;
      const group =
        groups.get(key) ??
        {
          key,
          characterId: entry.characterId,
          speakerName: entry.speakerName,
          chapterId: entry.chapterId,
          chapterName: entry.chapterName,
          lineCount: 0,
          totalChars: 0,
          sceneIds: new Set(),
          issueCount: 0,
          emotionCount: 0,
          questionCount: 0,
          longCount: 0,
          expressionCounts: new Map(),
          firstEntry: entry,
        };

      group.lineCount += 1;
      group.totalChars += entry.contentLength ?? String(entry.text ?? "").trim().length;
      group.sceneIds.add(entry.sceneId);
      group.issueCount += (entry.issues?.length ?? 0) > 0 ? 1 : 0;
      group.emotionCount += /[!！]/.test(entry.sourceText) ? 1 : 0;
      group.questionCount += /[?？]/.test(entry.sourceText) ? 1 : 0;
      group.longCount += (entry.contentLength ?? 0) >= 24 ? 1 : 0;

      if (entry.expressionName) {
        group.expressionCounts.set(entry.expressionName, (group.expressionCounts.get(entry.expressionName) ?? 0) + 1);
      }

      if ((entry.blockIndex ?? 9999) < (group.firstEntry?.blockIndex ?? 9999)) {
        group.firstEntry = entry;
      }

      groups.set(key, group);
    });

  return Array.from(groups.values())
    .map((group) => {
      const averageLength = group.lineCount > 0 ? Math.round(group.totalChars / group.lineCount) : 0;
      const estimatedMinutes = Math.max(2, Math.round(group.totalChars / 55));
      const topExpression = getTopNamedCounts(group.expressionCounts)[0]?.name ?? "情绪分布比较平均";
      const priorityScore =
        group.lineCount * 18 +
        group.sceneIds.size * 10 +
        group.totalChars / 10 +
        group.emotionCount * 12 +
        group.questionCount * 6 +
        group.longCount * 5 +
        group.issueCount * 8;
      let suggestion = "这一批可以直接筛出来导出 CSV，比较适合按角色集中录。";

      if (group.emotionCount >= 2) {
        suggestion = "这批情绪句比较集中，适合单独约一轮更进入状态的录音。";
      } else if (group.sceneIds.size >= 3) {
        suggestion = "这批分布在多个场景里，先统一录完可以明显减少后面来回返工。";
      } else if (group.longCount >= 2) {
        suggestion = "这批里长句偏多，适合先留出更完整的一段时间连续录。";
      }

      return {
        ...group,
        sceneCount: group.sceneIds.size,
        averageLength,
        estimatedMinutes,
        topExpression,
        priorityScore,
        suggestion,
      };
    })
    .sort((left, right) => {
      if (right.priorityScore !== left.priorityScore) {
        return right.priorityScore - left.priorityScore;
      }
      if (right.lineCount !== left.lineCount) {
        return right.lineCount - left.lineCount;
      }
      return left.chapterName.localeCompare(right.chapterName, "zh-CN");
    })
    .slice(0, 6);
}

