function buildScriptHighlightCandidates(entries) {
  return entries
    .map((entry) => {
      const reasons = [];
      let score = 0;

      if (entry.type === "choice") {
        score += 28;
        reasons.push("分支节点");
      }

      if (entry.type === "dialogue" && /[!！]/.test(entry.sourceText)) {
        score += 20;
        reasons.push("情绪爆点");
      }

      if (/[?？]/.test(entry.sourceText)) {
        score += 14;
        reasons.push("疑问悬念");
      }

      if (/(…|\.{3,})/.test(entry.sourceText)) {
        score += 8;
        reasons.push("停顿感");
      }

      if (entry.contentLength > getScriptLengthLimit(entry.type)) {
        score += 10;
        reasons.push("长句铺陈");
      }

      if (entry.type === "narration" && entry.contentLength >= 28) {
        score += 10;
        reasons.push("气氛描写");
      }

      if (entry.type === "dialogue" && entry.voiceStatus === "missing") {
        score += 5;
        reasons.push("待配音");
      }

      if (entry.expressionName && !/默认|普通|平静/.test(entry.expressionName)) {
        score += 4;
        reasons.push(`表情：${entry.expressionName}`);
      }

      if (score <= 0) {
        return null;
      }

      return {
        entry,
        score,
        rankLabel: `重点查看`,
        reasons: reasons.slice(0, 3),
        helperText:
          entry.type === "choice"
            ? "这类节点常适合转场、特效或节奏停顿"
            : entry.type === "narration"
              ? "这句更适合配合气氛或镜头变化"
              : "这句可能适合重点情绪演出",
      };
    })
    .filter(Boolean)
    .sort((left, right) => right.score - left.score)
    .slice(0, 4);
}

function renderScriptChapterRhythmSection(filteredEntries) {
  const chapterRhythms = buildScriptChapterRhythms(filteredEntries);

  if (chapterRhythms.length === 0) {
    return `
      <article class="detail-card rhythm-panel">
        <strong>章节节奏总览</strong>
        <p>当前筛选里还没有足够的正文内容，暂时看不出章节节奏。</p>
      </article>
    `;
  }

  const spotlightChapterId = getSafeScriptChapterFilter(state.scriptChapterFilter);
  if (spotlightChapterId !== "all") {
    const spotlight =
      chapterRhythms.find((rhythm) => rhythm.chapterId === spotlightChapterId) ?? chapterRhythms[0];
    return renderScriptChapterRhythmSpotlight(spotlight);
  }

  return `
    <section class="rhythm-panel">
      <div class="panel-heading">
        <h2>章节节奏总览</h2>
        <span class="badge badge-soft">一眼看推进感</span>
      </div>
      <div class="rhythm-stack">
        ${chapterRhythms.slice(0, 3).map((rhythm) => renderScriptChapterRhythmCard(rhythm)).join("")}
      </div>
    </section>
  `;
}

function buildScriptChapterRhythms(entries) {
  const groups = new Map();

  entries.forEach((entry) => {
    const group =
      groups.get(entry.chapterId) ??
      {
        chapterId: entry.chapterId,
        chapterName: entry.chapterName,
        totalEntries: 0,
        dialogueCount: 0,
        narrationCount: 0,
        choiceCount: 0,
        totalLength: 0,
        issueCount: 0,
        missingVoiceCount: 0,
        sceneIds: new Set(),
        speakerCounts: new Map(),
      };

    group.totalEntries += 1;
    group.totalLength += String(entry.text ?? "").trim().length;
    group.issueCount += (entry.issues?.length ?? 0) > 0 ? 1 : 0;
    group.sceneIds.add(entry.sceneId);

    if (entry.type === "dialogue") {
      group.dialogueCount += 1;
      group.missingVoiceCount += entry.voiceStatus === "missing" ? 1 : 0;
      const workflowState = getScriptVoiceWorkflowState(entry);
      group.missingBindingCount = (group.missingBindingCount ?? 0) + (workflowState === "missing_binding" ? 1 : 0);
      group.placeholderVoiceCount = (group.placeholderVoiceCount ?? 0) + (workflowState === "placeholder" ? 1 : 0);
      group.readyVoiceCount = (group.readyVoiceCount ?? 0) + (workflowState === "ready" ? 1 : 0);
      if (entry.speakerName) {
        group.speakerCounts.set(entry.speakerName, (group.speakerCounts.get(entry.speakerName) ?? 0) + 1);
      }
    } else if (entry.type === "narration") {
      group.narrationCount += 1;
    } else if (entry.type === "choice") {
      group.choiceCount += 1;
    }

    groups.set(entry.chapterId, group);
  });

  return Array.from(groups.values())
    .map((group) => {
      const totalEntries = group.totalEntries || 1;
      const averageLength = Math.round(group.totalLength / totalEntries);
      const dialogueRatio = group.dialogueCount / totalEntries;
      const narrationRatio = group.narrationCount / totalEntries;
      const choiceRatio = group.choiceCount / totalEntries;
      const voiceCoverage =
        group.dialogueCount > 0
          ? Math.round(((group.dialogueCount - group.missingVoiceCount) / group.dialogueCount) * 100)
          : 100;
      const readyVoiceCoverage =
        group.dialogueCount > 0
          ? Math.round(((group.readyVoiceCount ?? 0) / group.dialogueCount) * 100)
          : 100;
      const topSpeaker = getTopNamedCounts(group.speakerCounts)[0] ?? null;
      const recordingMinutes = Math.max(1, Math.round(group.totalLength / 55));

      return {
        chapterId: group.chapterId,
        chapterName: group.chapterName,
        totalEntries: group.totalEntries,
        dialogueCount: group.dialogueCount,
        narrationCount: group.narrationCount,
        choiceCount: group.choiceCount,
        averageLength,
        issueCount: group.issueCount,
        missingVoiceCount: group.missingVoiceCount,
        sceneCount: group.sceneIds.size,
        dialogueRatio,
        narrationRatio,
        choiceRatio,
        voiceCoverage,
        readyVoiceCoverage,
        missingBindingCount: group.missingBindingCount ?? 0,
        placeholderVoiceCount: group.placeholderVoiceCount ?? 0,
        readyVoiceCount: group.readyVoiceCount ?? 0,
        recordingMinutes,
        topSpeaker,
        summary: buildScriptChapterRhythmSummary({
          averageLength,
          dialogueRatio,
          narrationRatio,
          choiceRatio,
          choiceCount: group.choiceCount,
          issueCount: group.issueCount,
          missingVoiceCount: group.missingVoiceCount,
        }),
      };
    })
    .sort((left, right) => {
      if (right.totalEntries !== left.totalEntries) {
        return right.totalEntries - left.totalEntries;
      }
      if (right.issueCount !== left.issueCount) {
        return right.issueCount - left.issueCount;
      }
      return left.chapterName.localeCompare(right.chapterName, "zh-CN");
    });
}

