function renderVoiceprintMeter(label, ratio) {
  const safeRatio = Math.max(0, Math.min(Number(ratio) || 0, 1));
  const percentage = Math.round(safeRatio * 100);
  return `
    <div class="voiceprint-meter">
      <div class="voiceprint-meter-top">
        <span>${escapeHtml(label)}</span>
        <strong>${percentage}%</strong>
      </div>
      <div class="voiceprint-meter-track">
        <span class="voiceprint-meter-fill" style="width: ${percentage}%"></span>
      </div>
    </div>
  `;
}

function buildScriptVoiceprintSummary(voiceprint) {
  const paceLabel =
    voiceprint.averageLength >= 22
      ? "偏长句细腻"
      : voiceprint.averageLength <= 10
        ? "短句利落"
        : "节奏比较均衡";
  const dominantTone = [
    { label: "疑问感明显", ratio: voiceprint.questionRatio },
    { label: "情绪起伏大", ratio: voiceprint.exclaimRatio },
    { label: "停顿感明显", ratio: voiceprint.pauseRatio },
    { label: "爱用长句铺陈", ratio: voiceprint.longRatio },
  ].sort((left, right) => right.ratio - left.ratio)[0];
  const toneLabel = dominantTone?.ratio >= 0.22 ? dominantTone.label : "语气比较稳";
  const openingText = voiceprint.topOpenings[0]?.name
    ? `常从“${voiceprint.topOpenings[0].name}”起句`
    : "起句还比较自由";
  return `${paceLabel} / ${toneLabel} / ${openingText}`;
}

function extractScriptOpening(text) {
  const cleaned = String(text ?? "")
    .trim()
    .replace(/^[“”"'‘’「」『』【】（）()《》〈〉\[\]\s]+/, "")
    .replace(/^[，。！？!?、…~～·]+/, "")
    .replace(/\s+/g, "");

  if (cleaned.length < 2) {
    return "";
  }

  return cleaned.slice(0, cleaned.length >= 3 ? 3 : 2);
}

function getTopNamedCounts(sourceMap, options = {}) {
  const minCount = options.minCount ?? 1;
  return Array.from(sourceMap.entries())
    .filter(([, count]) => count >= minCount)
    .sort((left, right) => {
      if (right[1] !== left[1]) {
        return right[1] - left[1];
      }
      return left[0].localeCompare(right[0], "zh-CN");
    })
    .slice(0, 2)
    .map(([name, count]) => ({ name, count }));
}

function formatVoiceprintList(items, fallbackText) {
  if (!items?.length) {
    return fallbackText;
  }

  return items.map((item) => `${item.name} × ${item.count}`).join(" / ");
}

function renderScriptIssueBadges(issues) {
  return issues
    .map((issue) => {
      const toneClass =
        issue === "missing_voice" ? "warn-text" : issue === "duplicate" ? "danger-text" : "";
      return `<span class="issue-tag ${toneClass}">${escapeHtml(getScriptIssueFilterLabel(issue))}</span>`;
    })
    .join("");
}

function countScriptIssues(entries) {
  const counts = {
    any: 0,
    placeholder: 0,
    too_long: 0,
    duplicate: 0,
    missing_voice: 0,
  };

  entries.forEach((entry) => {
    const issues = entry.issues ?? [];
    if (issues.length > 0) {
      counts.any += 1;
    }
    issues.forEach((issue) => {
      if (Object.prototype.hasOwnProperty.call(counts, issue)) {
        counts[issue] += 1;
      }
    });
  });

  return counts;
}

function exportScriptData(format) {
  const allEntries = analyzeScriptEntries(buildScriptEntries());
  const filteredEntries = getFilteredScriptEntries(allEntries);

  if (filteredEntries.length === 0) {
    setSaveStatus("当前筛选下没有可导出的台本内容", true);
    showToast("当前筛选下没有可导出的台本内容", "error");
    return;
  }

  const formatType = format === "csv" ? "csv" : "txt";
  const fileName = buildScriptExportFileName(formatType);
  const content =
    formatType === "csv"
      ? buildScriptCsvContent(filteredEntries, allEntries.length)
      : buildScriptTxtContent(filteredEntries, allEntries.length);
  const mimeType =
    formatType === "csv" ? "text/csv;charset=utf-8" : "text/plain;charset=utf-8";

  downloadTextFile(fileName, content, mimeType);
  setSaveStatus(`已导出${formatType.toUpperCase()}台本：${fileName}`);
  showToast(`台本已导出：${fileName}`);
}

function exportScriptVoiceSheet(filters = {}) {
  const allEntries = analyzeScriptEntries(buildScriptEntries());
  const sourceEntries =
    filters.characterId || filters.chapterId ? allEntries : getFilteredScriptEntries(allEntries);
  const voiceSheetEntries = getVoiceSheetEntries(sourceEntries, filters);
  const totalPendingEntries = getVoiceSheetEntries(allEntries).length;

  if (voiceSheetEntries.length === 0) {
    setSaveStatus("当前范围下没有可导出的待录语音", true);
    showToast("当前范围下没有待录语音", "error");
    return;
  }

  const fileName = buildScriptVoiceSheetFileName(filters);
  const content = buildScriptVoiceSheetContent(voiceSheetEntries, totalPendingEntries, filters);
  downloadTextFile(fileName, content, "text/csv;charset=utf-8");
  setSaveStatus(`已导出配音命名清单：${fileName}`);
  showToast(`配音命名清单已导出：${fileName}`);
}

