function renderCharacterRelationshipBadges(partner) {
  const badges = [
    `<span class="issue-tag">同场 ${partner.sharedSceneCount} 场</span>`,
    `<span class="issue-tag good-text">接话 ${partner.exchangeCount} 次</span>`,
    `<span class="issue-tag">共演台词 ${partner.sharedLineCount} 句</span>`,
  ];

  if (partner.duoMissingVoiceCount > 0) {
    badges.push(`<span class="issue-tag warn-text">双人待配音 ${partner.duoMissingVoiceCount} 句</span>`);
  }

  if (partner.focusSceneCount > 0) {
    badges.push(`<span class="issue-tag ${getScenePriorityToneClass("focus")}">重点场 ${partner.focusSceneCount}</span>`);
  }

  if (partner.flatSharedSceneCount > 0) {
    badges.push(`<span class="issue-tag">演出偏素 ${partner.flatSharedSceneCount}</span>`);
  }

  return badges.join("");
}

