function buildPreviewRegressionSeeds(routeOverview) {
  return previewRegressionTools.buildPreviewRegressionSeeds(routeOverview, {
    entrySceneId: state.data?.project?.entrySceneId,
    fallbackSceneId: state.data?.scenes?.[0]?.id,
    scenesById: state.data?.scenesById,
    getSafeSceneId,
    maxCases: PREVIEW_REGRESSION_MAX_CASES,
    branchingSeedLimit: PREVIEW_REGRESSION_BRANCHING_SEED_LIMIT,
  });
}

function getPreviewRegressionTerminalMeta(snapshot, previousSnapshot, steps) {
  const message = String(snapshot?.visualState?.dialogueText ?? "").trim();

  if (message.includes("目标场景不存在")) {
    return {
      status: "fail",
      title: "跳转到了不存在的场景",
      detail: "这条路线在推进过程中撞到了一个不存在的目标场景，正式发布前必须先把跳转补对。",
      anchorSnapshot: previousSnapshot ?? snapshot,
    };
  }

  if (message.includes("这个场景还没有卡片")) {
    return {
      status: "fail",
      title: "进入了空场景",
      detail: "这条路线会把玩家带进一个没有任何卡片的场景，试玩会直接卡住。",
      anchorSnapshot: snapshot?.blockId ? snapshot : previousSnapshot ?? snapshot,
    };
  }

  if (steps <= 1) {
    return {
      status: "warn",
      title: "这条路线结束得太快",
      detail: "烟测虽然没有直接撞错，但这条路线几乎一开场就结束了，可确认是否缺少正文、跳转或分支承接。",
      anchorSnapshot: previousSnapshot ?? snapshot,
    };
  }

  return {
    status: "pass",
    title: "这条关键路线已经走通",
    detail: "本次烟测能顺利走到结尾，没有撞到坏链或死循环。",
    anchorSnapshot: previousSnapshot ?? snapshot,
  };
}

function buildPreviewRegressionCaseActions(caseResult) {
  const actions = [];

  if (caseResult.anchorBlockId) {
    actions.push({
      label: "试玩问题位置",
      action: "preview-story-location",
      sceneId: caseResult.anchorSceneId,
      blockId: caseResult.anchorBlockId,
    });
    actions.push({
      label: "打开对应卡片",
      action: "open-character-line",
      sceneId: caseResult.anchorSceneId,
      blockId: caseResult.anchorBlockId,
    });
    return actions;
  }

  if (caseResult.seedSceneId) {
    actions.push({
      label: "试玩这段",
      action: "preview-scene-from-map",
      sceneId: caseResult.seedSceneId,
    });
  }

  if (caseResult.anchorSceneId) {
    actions.push({
      label: "打开场景",
      action: "open-scene-from-map",
      sceneId: caseResult.anchorSceneId,
    });
  }

  return actions;
}

function runPreviewRegressionCase(seed) {
  const variableOverrides = getPreviewRegressionVariableOverrides(seed);
  const session = createPreviewRegressionSession(seed.sceneId, variableOverrides);
  const visitedStepCounts = new Map();
  const visitedSceneIds = new Set();
  const selectedOptionTexts = [];
  const variableOverrideSummary = formatPreviewRegressionVariableOverrides(variableOverrides);
  const expectedTargetSceneId = String(seed.targetSceneId ?? "").trim();
  let expectedTargetReached = !expectedTargetSceneId;
  let previousSnapshot = null;
  let steps = 0;
  let choiceCount = 0;

  function finalizeResult(result) {
    if (
      seed.seedKind === "route_case" &&
      expectedTargetSceneId &&
      !expectedTargetReached &&
      result.status === "pass"
    ) {
      result.status = "warn";
      result.statusLabel = "目标分支未跑到";
      result.reason = "这条分支没有按预期命中目标场景";
      result.detail = `自动试玩从分支场景开始推进，但没有进入「${seed.targetSceneName || expectedTargetSceneId}」。如果这是条件分支，需要先补变量预设或手动确认触发条件。`;
    }
    result.targetSceneId = expectedTargetSceneId;
    result.targetSceneName = seed.targetSceneName ?? "";
    result.expectedTargetReached = expectedTargetReached;
    result.variableOverrides = variableOverrides;
    result.variableOverrideSummary = variableOverrideSummary;
    result.actions = buildPreviewRegressionCaseActions(result);
    return result;
  }

  while (steps < PREVIEW_REGRESSION_MAX_STEPS) {
    const snapshot = getCurrentPreviewRegressionSnapshot(session);

    if (!snapshot) {
      break;
    }

    if (snapshot.sceneId) {
      visitedSceneIds.add(snapshot.sceneId);
      if (expectedTargetSceneId && String(snapshot.sceneId) === expectedTargetSceneId) {
        expectedTargetReached = true;
      }
    }

    const stateKey = [
      snapshot.sceneId ?? "none",
      snapshot.blockId ?? "complete",
      snapshot.blockIndex,
      snapshot.selectedOptionId ?? "",
      snapshot.resolvedBranchId ?? "",
    ].join(":");
    const nextRepeatCount = (visitedStepCounts.get(stateKey) ?? 0) + 1;
    visitedStepCounts.set(stateKey, nextRepeatCount);

    if (nextRepeatCount > PREVIEW_REGRESSION_MAX_REPEAT) {
      const anchorSnapshot = previousSnapshot ?? snapshot;
      const result = {
        id: `${seed.sceneId}:loop`,
        seedSceneId: seed.sceneId,
        sceneName: seed.sceneName,
        chapterName: seed.chapterName,
        sourceLabel: seed.sourceLabel,
        status: "fail",
        statusLabel: "疑似死循环",
        reason: "这条路线反复回到同一个步骤，已经不像正常的剧情推进了。",
        detail: `烟测在 ${steps} 步内重复命中同一位置超过 ${PREVIEW_REGRESSION_MAX_REPEAT} 次，可先检查跳转、条件判断或循环分支。`,
        steps,
        visitedSceneCount: visitedSceneIds.size,
        choiceCount,
        selectedOptionTexts,
        anchorSceneId: anchorSnapshot?.sceneId ?? seed.sceneId,
        anchorBlockId: anchorSnapshot?.blockId ?? null,
      };
      return finalizeResult(result);
    }

    if (snapshot.completed) {
      const terminalMeta = getPreviewRegressionTerminalMeta(snapshot, previousSnapshot, steps);
      const result = {
        id: `${seed.sceneId}:${terminalMeta.status}:${steps}`,
        seedSceneId: seed.sceneId,
        sceneName: seed.sceneName,
        chapterName: seed.chapterName,
        sourceLabel: seed.sourceLabel,
        status: terminalMeta.status,
        statusLabel:
          terminalMeta.status === "pass"
            ? "已走通"
            : terminalMeta.status === "warn"
              ? "需要复看"
              : "回归失败",
        reason: terminalMeta.title,
        detail: terminalMeta.detail,
        steps,
        visitedSceneCount: visitedSceneIds.size,
        choiceCount,
        selectedOptionTexts,
        anchorSceneId: terminalMeta.anchorSnapshot?.sceneId ?? seed.sceneId,
        anchorBlockId: terminalMeta.anchorSnapshot?.blockId ?? null,
      };
      return finalizeResult(result);
    }

    if (snapshot.blockType === "choice") {
      if (!snapshot.choiceOptions.length) {
        const result = {
          id: `${seed.sceneId}:choice-empty`,
          seedSceneId: seed.sceneId,
          sceneName: seed.sceneName,
          chapterName: seed.chapterName,
          sourceLabel: seed.sourceLabel,
          status: "fail",
          statusLabel: "选项卡无可用选项",
          reason: "这张选项卡没有任何可走分支",
          detail: "玩家走到这里时没有任何选项可点，试玩会直接中断，可先补齐选项去向。",
          steps,
          visitedSceneCount: visitedSceneIds.size,
          choiceCount,
          selectedOptionTexts,
          anchorSceneId: snapshot.sceneId ?? seed.sceneId,
          anchorBlockId: snapshot.blockId ?? null,
        };
        return finalizeResult(result);
      }

      const selectedOption = previewRegressionTools.chooseRegressionOption(snapshot.choiceOptions, seed, {
        sceneId: snapshot.sceneId,
        blockIndex: snapshot.blockIndex,
      });
      choiceCount += 1;
      selectedOptionTexts.push(truncateText(selectedOption.text || `选项 ${choiceCount}`, 18));
      previousSnapshot = snapshot;
      choosePreviewRegressionOption(session, selectedOption.id);
      steps += 1;
      continue;
    }

    previousSnapshot = snapshot;
    const nextSnapshot = movePreviewRegressionForward(session);

    if (!nextSnapshot || nextSnapshot === snapshot) {
      const result = {
        id: `${seed.sceneId}:stalled`,
        seedSceneId: seed.sceneId,
        sceneName: seed.sceneName,
        chapterName: seed.chapterName,
        sourceLabel: seed.sourceLabel,
        status: "fail",
        statusLabel: "推进中断",
        reason: "这条路线没有正常继续往下推进",
        detail: "烟测在这里没能继续前进，可检查这一张卡片是否缺少目标场景、选项或有效内容。",
        steps,
        visitedSceneCount: visitedSceneIds.size,
        choiceCount,
        selectedOptionTexts,
        anchorSceneId: snapshot.sceneId ?? seed.sceneId,
        anchorBlockId: snapshot.blockId ?? null,
      };
      return finalizeResult(result);
    }

    steps += 1;
  }

  const result = {
    id: `${seed.sceneId}:max-steps`,
    seedSceneId: seed.sceneId,
    sceneName: seed.sceneName,
    chapterName: seed.chapterName,
    sourceLabel: seed.sourceLabel,
    status: "fail",
    statusLabel: "超过最大步数",
    reason: "这条路线跑得太久了，像是没能正常收束",
    detail: `烟测已经推进超过 ${PREVIEW_REGRESSION_MAX_STEPS} 步，仍然没有走到结尾，可先检查是否存在循环跳转或条件阻塞。`,
    steps: PREVIEW_REGRESSION_MAX_STEPS,
    visitedSceneCount: visitedSceneIds.size,
    choiceCount,
    selectedOptionTexts,
    anchorSceneId: previousSnapshot?.sceneId ?? seed.sceneId,
    anchorBlockId: previousSnapshot?.blockId ?? null,
  };
  return finalizeResult(result);
}

function runPreviewRegressionSmokeTest(routeOverview = buildSceneRouteOverview()) {
  const seeds = buildPreviewRegressionSeeds(routeOverview);
  const cases = seeds.map((seed) => runPreviewRegressionCase(seed)).sort((left, right) => {
    const priorityMap = { fail: 0, warn: 1, pass: 2 };
    if (priorityMap[left.status] !== priorityMap[right.status]) {
      return priorityMap[left.status] - priorityMap[right.status];
    }
    return left.sceneName.localeCompare(right.sceneName, "zh-CN");
  });

  const summary = {
    total: cases.length,
    passCount: cases.filter((item) => item.status === "pass").length,
    warnCount: cases.filter((item) => item.status === "warn").length,
    failCount: cases.filter((item) => item.status === "fail").length,
  };

  return {
    ranAt: new Date().toISOString(),
    seeds,
    cases,
    summary,
  };
}

function getPreviewRegressionStatusToneClass(status) {
  if (status === "fail") {
    return "danger-text";
  }
  if (status === "warn") {
    return "warn-text";
  }
  return "good-text";
}

