function renderPlayerProfileOverviewPanel() {
  const scenes = state.data?.scenes ?? [];
  const chapters = state.data?.chapters ?? [];
  const characters = state.data?.characters ?? [];
  const cgAssets = (state.data?.assetList ?? []).filter((asset) => asset.type === "cg");
  const bgmAssets = (state.data?.assetList ?? []).filter((asset) => asset.type === "bgm");
  const endings = buildSceneRouteOverview().metrics.endingScenes;

  return `
    <article class="detail-card">
      <strong>游玩记录 / 玩家档案馆</strong>
      <p class="helper-text">导出后的标题页会根据项目里的剧情入口自动显示“玩家档案”。它会把玩家自己的游玩次数、累计时长、存档、章节、成就、图鉴、结局和 EXTRA 收藏一起记在本机里，不会写回你的项目文件。</p>
      <div class="preview-sprint-metrics">
        ${renderRouteMetricCard(
          "标题页入口",
          scenes.length > 0 ? "会显示" : "暂不显示",
          scenes.length > 0 ? "只要项目里已经有可玩的场景，标题页就会出现“玩家档案”按钮" : "完成第一章和第一场景后，标题页玩家档案入口才会出现"
        )}
        ${renderRouteMetricCard(
          "会累计什么",
          "游玩次数 + 时长 + 存档",
          "还会继续汇总章节、成就、图鉴、结局和 EXTRA 的整体进度"
        )}
        ${renderRouteMetricCard(
          "存档结构",
          "24 格正式存档 + 快速存档",
          "同时还会把自动续玩一起并进玩家档案里显示"
        )}
        ${renderRouteMetricCard(
          "进度来源",
          `${chapters.length} 章 / ${characters.length} 角色 / ${endings} 结局 / ${cgAssets.length + bgmAssets.length} EXTRA`,
          "章节、角色、结局、CG 和 BGM 越完整，玩家档案里的总进度就越像正式作品"
        )}
      </div>
      <div class="detail-actions">
        <button class="toolbar-button" data-action="switch-screen" data-screen="preview">
          去试玩收尾页确认
        </button>
        <button class="toolbar-button" data-action="switch-screen" data-screen="dashboard">
          去首页继续补骨架
        </button>
        <button class="toolbar-button" data-action="export-build" data-export-target="web">
          导一版试玩包确认
        </button>
      </div>
      <div class="detail-meta">${
        scenes.length > 0
          ? `这套玩家档案会自动汇总：${escapeHtml(
              [
                `${chapters.length} 章章节选集`,
                `${characters.length} 位角色图鉴`,
                `${endings} 个结局回收`,
                `${cgAssets.length} 张 CG`,
                `${bgmAssets.length} 首 BGM`,
              ].join(" / ")
            )}`
          : "当前还没有可玩的场景，所以标题页暂时不会出现玩家档案入口。"
      }</div>
    </article>
  `;
}

function renderVoiceReplayOverviewPanel() {
  const scenes = state.data?.scenes ?? [];
  const assetList = state.data?.assetList ?? [];
  const assetsById = state.data?.assetsById ?? new Map();
  const voiceBlocks = [];

  scenes.forEach((scene) => {
    (scene.blocks ?? []).forEach((block, blockIndex) => {
      if ((block.type !== "dialogue" && block.type !== "narration") || !block.voiceAssetId) {
        return;
      }

      const asset = assetsById.get(block.voiceAssetId);
      if (!asset || asset.type !== "voice") {
        return;
      }

      voiceBlocks.push({
        sceneName: scene.name,
        chapterName: scene.chapterName,
        text: String(block.text ?? "").trim(),
        asset,
        blockIndex,
      });
    });
  });

  const readyVoiceBlocks = voiceBlocks.filter((entry) => entry.asset.fileExists);
  const missingVoiceBlocks = voiceBlocks.filter((entry) => !entry.asset.fileExists);
  const uniqueVoiceAssets = new Set(voiceBlocks.map((entry) => entry.asset.id)).size;
  const readyVoiceAssets = new Set(readyVoiceBlocks.map((entry) => entry.asset.id)).size;

  return `
    <article class="detail-card">
      <strong>语音回听 / 名台词回放馆</strong>
      <p class="helper-text">导出后的标题页会根据“已经绑了真实语音文件的台词”自动显示“语音回听”。玩家第一次推进到那句台词后，这句就会被收录进本机回听馆，之后能直接从标题页回放。</p>
      <div class="preview-sprint-metrics">
        ${renderRouteMetricCard(
          "可参与回听的台词",
          readyVoiceBlocks.length > 0 ? `${readyVoiceBlocks.length} 句` : "暂时没有",
          readyVoiceBlocks.length > 0
            ? "这些已经有真实语音文件的台词，导出后就能自动进入回听馆"
            : "至少先让几句台词绑上真实语音文件，标题页回听入口才会出现"
        )}
        ${renderRouteMetricCard(
          "语音条目",
          uniqueVoiceAssets > 0 ? `${readyVoiceAssets}/${uniqueVoiceAssets} 已就绪` : "还没有语音条目",
          uniqueVoiceAssets > 0
            ? missingVoiceBlocks.length > 0
              ? `还有 ${missingVoiceBlocks.length} 句绑了语音条目但还没真实文件`
              : "这批语音素材已经能支持标题页回听"
            : "去配音工作流里生成或上传语音"
        )}
        ${renderRouteMetricCard(
          "标题页入口",
          readyVoiceBlocks.length > 0 ? "会显示" : "暂不显示",
          readyVoiceBlocks.length > 0
            ? "只要项目里已经有至少一句“带真实语音文件”的台词，标题页就会出现“语音回听”按钮"
            : "当前没有可播放的语音台词，所以标题页不会显示回听入口"
        )}
        ${renderRouteMetricCard(
          "自动收录规则",
          "第一次推进到这句后收录",
          "玩家真的走到这句带语音的台词后，这句就会在自己的本机自动亮起"
        )}
      </div>
      <div class="detail-actions">
        <button class="toolbar-button" data-action="switch-screen" data-screen="script">
          去台词台本看语音
        </button>
        <button
          class="toolbar-button"
          data-action="focus-asset-gap"
          data-asset-filter-mode="missing_file"
          data-asset-type="voice"
        >
          去补待导入语音
        </button>
        <button class="toolbar-button" data-action="export-build" data-export-target="web">
          导一版试玩包确认
        </button>
      </div>
      <div class="detail-meta">${
        readyVoiceBlocks.length > 0
          ? `当前最适合先确认的回听台词：${escapeHtml(
              readyVoiceBlocks
                .slice(0, 3)
                .map((entry) => `${entry.chapterName} · ${entry.sceneName} · ${truncateText(entry.text || "这句台词没有正文。", 20)}`)
                .join(" / ")
            )}${readyVoiceBlocks.length > 3 ? ` 等 ${readyVoiceBlocks.length} 句` : ""}`
          : "现在还没有满足条件的语音台词，所以标题页不会出现语音回听入口。"
      }</div>
    </article>
  `;
}

function buildExtraModeOverview() {
  const assetList = state.data?.assetList ?? [];
  const cgAssets = assetList.filter((asset) => asset.type === "cg");
  const bgmAssets = assetList.filter((asset) => asset.type === "bgm");
  const readyCgCount = cgAssets.filter((asset) => asset.fileExists).length;
  const readyBgmCount = bgmAssets.filter((asset) => asset.fileExists).length;

  return {
    cg: {
      total: cgAssets.length,
      ready: readyCgCount,
      missing: Math.max(cgAssets.length - readyCgCount, 0),
    },
    bgm: {
      total: bgmAssets.length,
      ready: readyBgmCount,
      missing: Math.max(bgmAssets.length - readyBgmCount, 0),
    },
    hasAnyEntry: cgAssets.length > 0 || bgmAssets.length > 0,
  };
}

function renderExtraModeOverviewPanel() {
  const overview = buildExtraModeOverview();
  const exportResult = state.lastExportResult;
  const latestExportNote = exportResult
    ? `最近一次导出：${exportResult.targetLabel ?? exportResult.target ?? "试玩包"} · 发布版本 ${
        exportResult.releaseVersion ?? getProjectReleaseVersion()
      }`
    : "等你导一版试玩包后，这里会继续沿用同一套 EXTRA 解锁规则。";

  return `
    <article class="detail-card">
      <strong>EXTRA 回想馆 / 音乐鉴赏</strong>
      <p class="helper-text">导出后的标题页会根据项目里的 CG 和 BGM 条目自动显示入口。玩家第一次在剧情里看到某张 CG、听到某首 BGM 后，就会在自己的本机自动解锁到 EXTRA 里。</p>
      <div class="preview-sprint-metrics">
        ${renderRouteMetricCard(
          "CG 条目",
          overview.cg.total > 0 ? `${overview.cg.ready}/${overview.cg.total} 已就绪` : "还没有 CG",
          overview.cg.total > 0
            ? overview.cg.missing > 0
              ? `还有 ${overview.cg.missing} 张缺真实文件`
              : "这些 CG 导出后就能参与回想解锁"
            : "去素材页补第一张 CG"
        )}
        ${renderRouteMetricCard(
          "音乐条目",
          overview.bgm.total > 0 ? `${overview.bgm.ready}/${overview.bgm.total} 已就绪` : "还没有 BGM",
          overview.bgm.total > 0
            ? overview.bgm.missing > 0
              ? `还有 ${overview.bgm.missing} 首缺真实文件`
              : "这些 BGM 导出后就能参与音乐鉴赏解锁"
            : "去素材页补第一首 BGM"
        )}
        ${renderRouteMetricCard(
          "标题页入口",
          overview.hasAnyEntry ? "会显示" : "暂不显示",
          overview.hasAnyEntry
            ? "只要项目里有 CG 或 BGM 条目，标题页就会显示对应 EXTRA 入口"
            : "当前还没有 CG/BGM 条目，所以标题页不会显示 EXTRA 入口"
        )}
        ${renderRouteMetricCard(
          "自动解锁规则",
          "剧情首次遇见后收录",
          "玩家本机的解锁进度会单独保存，不会写回你的项目文件"
        )}
      </div>
      <div class="detail-actions">
        <button
          class="toolbar-button"
          data-action="focus-asset-gap"
          data-asset-filter-mode="all"
          data-asset-type="cg"
        >
          去看 CG 条目
        </button>
        <button
          class="toolbar-button"
          data-action="focus-asset-gap"
          data-asset-filter-mode="all"
          data-asset-type="bgm"
        >
          去看 BGM 条目
        </button>
        <button class="toolbar-button" data-action="export-build" data-export-target="web">
          导一版试玩包确认
        </button>
      </div>
      <div class="detail-meta">${escapeHtml(latestExportNote)}</div>
    </article>
  `;
}

function renderAchievementOverviewPanel() {
  const scenes = state.data?.scenes ?? [];
  const characters = state.data?.characters ?? [];
  const assetList = state.data?.assetList ?? [];
  const endingCount = buildSceneRouteOverview().metrics.endingScenes;
  const choiceBlockCount = scenes.reduce(
    (count, scene) => count + ((scene.blocks ?? []).filter((block) => block.type === "choice").length || 0),
    0
  );
  const cgCount = assetList.filter((asset) => asset.type === "cg").length;
  const bgmCount = assetList.filter((asset) => asset.type === "bgm").length;
  const achievementTotal =
    (scenes.length > 0 ? 1 : 0) +
    (choiceBlockCount > 0 ? 1 : 0) +
    (characters.length > 0 ? 2 : 0) +
    (cgCount > 0 ? 2 : 0) +
    (bgmCount > 0 ? 2 : 0) +
    (endingCount > 0 ? 2 : 0);

  return `
    <article class="detail-card">
      <strong>成就系统 / 收集成就馆</strong>
      <p class="helper-text">导出后的标题页会根据项目内容自动出现“成就馆”。这一版不需要你手配规则，系统会按开始试玩、第一次做选项、角色图鉴收录、CG/BGM 解锁、结局回收和全收集这些里程碑自动点亮成就。</p>
      <div class="preview-sprint-metrics">
        ${renderRouteMetricCard(
          "自动成就总数",
          achievementTotal > 0 ? `${achievementTotal} 个` : "暂时没有",
          achievementTotal > 0
            ? "会按剧情、图鉴、EXTRA 和结局进度自动生成"
            : "至少先有场景、角色、CG、BGM 或结局，标题页才会出现成就馆"
        )}
        ${renderRouteMetricCard(
          "标题页入口",
          achievementTotal > 0 ? "会显示" : "暂不显示",
          achievementTotal > 0
            ? "只要项目里存在可自动生成的里程碑，标题页就会出现“成就馆”按钮"
            : "当前项目内容还不足以生成自动成就，所以标题页不会显示入口"
        )}
        ${renderRouteMetricCard(
          "剧情里程碑",
          scenes.length > 0 ? `${choiceBlockCount > 0 ? 2 : 1} 个` : "0 个",
          scenes.length > 0
            ? choiceBlockCount > 0
              ? "会自动记录开始试玩和首次做出选项"
              : "会自动记录第一次开始试玩"
            : "完成第一章剧情后，这类成就才会出现"
        )}
        ${renderRouteMetricCard(
          "收集里程碑",
          `${characters.length > 0 ? 2 : 0} 角色 / ${cgCount > 0 ? 2 : 0} CG / ${bgmCount > 0 ? 2 : 0} BGM / ${endingCount > 0 ? 2 : 0} 结局`,
          "包含首次收录和全收集两层自动成就"
        )}
      </div>
      <div class="detail-actions">
        <button class="toolbar-button" data-action="switch-screen" data-screen="dashboard">
          去首页继续补剧情
        </button>
        <button class="toolbar-button" data-action="switch-screen" data-screen="characters">
          去角色页补图鉴来源
        </button>
        <button class="toolbar-button" data-action="export-build" data-export-target="web">
          导一版试玩包确认
        </button>
      </div>
      <div class="detail-meta">${
        achievementTotal > 0
          ? `当前来源：${escapeHtml(
              [
                scenes.length > 0 ? "开始试玩" : "",
                choiceBlockCount > 0 ? "首次选项" : "",
                characters.length > 0 ? `角色图鉴 ${characters.length} 位` : "",
                cgCount > 0 ? `CG ${cgCount} 张` : "",
                bgmCount > 0 ? `BGM ${bgmCount} 首` : "",
                endingCount > 0 ? `结局 ${endingCount} 个` : "",
              ]
                .filter(Boolean)
                .join(" / ")
            )}`
          : "现在还没有足够的剧情和收集内容，所以标题页暂时不会出现成就馆入口。"
      }</div>
    </article>
  `;
}

