function escapeMarkdownTableCell(value) {
  return String(value ?? "")
    .replace(/\|/g, "\\|")
    .replace(/\r?\n/g, "<br />")
    .trim();
}

function buildMarkdownTable(headers, rows) {
  if (!rows.length) {
    return "";
  }
  return [
    `| ${headers.map(escapeMarkdownTableCell).join(" | ")} |`,
    `| ${headers.map(() => "---").join(" | ")} |`,
    ...rows.map((row) => `| ${row.map(escapeMarkdownTableCell).join(" | ")} |`),
  ].join("\n");
}

function getReleaseSeverityLabel(severity) {
  if (releaseControlTools?.getReleaseSeverityLabel) {
    return releaseControlTools.getReleaseSeverityLabel(severity);
  }

  switch (severity) {
    case "blocker":
      return "阻塞";
    case "warn":
      return "提醒";
    case "good":
      return "通过";
    default:
      return severity ? String(severity) : "未分级";
  }
}

function getReleaseStepToneLabel(tone) {
  if (releaseControlTools?.getReleaseStepToneLabel) {
    return releaseControlTools.getReleaseStepToneLabel(tone);
  }

  switch (tone) {
    case "danger":
      return "先修";
    case "warn":
      return "优先";
    case "good":
      return "确认";
    default:
      return "收尾";
  }
}

function serializeReleaseReportAction(action) {
  if (releaseControlTools?.serializeReleaseReportAction) {
    return releaseControlTools.serializeReleaseReportAction(action);
  }

  if (!action) {
    return null;
  }
  return {
    label: action.label ?? "",
    action: action.action ?? "",
    href: action.href ?? "",
    screen: action.screen ?? "",
    sceneId: action.sceneId ?? "",
    blockId: action.blockId ?? "",
    characterId: action.characterId ?? "",
    chapterId: action.chapterId ?? "",
    assetId: action.assetId ?? "",
    dataset: action.dataset ?? {},
  };
}

function serializeProjectMilestoneCheck(check) {
  return {
    id: check?.id ?? "",
    label: check?.label ?? "",
    done: Boolean(check?.done),
    detail: check?.detail ?? "",
    missing: check?.missing ?? "",
    weight: check?.weight ?? 1,
    action: serializeReleaseReportAction(check?.action),
  };
}

function serializeOptionalProjectMilestoneCheck(check) {
  return check ? serializeProjectMilestoneCheck(check) : null;
}

function serializeProjectMilestone(milestone) {
  if (!milestone) {
    return null;
  }

  return {
    id: milestone.id ?? "",
    title: milestone.title ?? "",
    label: milestone.label ?? "",
    percent: milestone.percent ?? 0,
    done: Boolean(milestone.done),
    tone: milestone.tone ?? "",
    summary: milestone.summary ?? "",
    blockers: (milestone.blockers ?? []).map(serializeProjectMilestoneCheck),
    wins: (milestone.wins ?? []).map(serializeProjectMilestoneCheck),
    checks: (milestone.checks ?? []).map(serializeProjectMilestoneCheck),
    actions: (milestone.actions ?? []).map(serializeReleaseReportAction).filter(Boolean),
  };
}

function serializeProjectMilestonePlan(plan) {
  return {
    overallScore: plan?.overallScore ?? 0,
    completedCount: plan?.completedCount ?? 0,
    totalCount: plan?.totalCount ?? 0,
    headline: plan?.headline ?? "",
    nextMilestone: serializeProjectMilestone(plan?.nextMilestone),
    milestones: (plan?.milestones ?? []).map(serializeProjectMilestone).filter(Boolean),
  };
}

function serializeProjectMilestoneGapDigest(digest) {
  return {
    status: digest?.status ?? "",
    eyebrow: digest?.eyebrow ?? "",
    title: digest?.title ?? "",
    description: digest?.description ?? "",
    overallScore: digest?.overallScore ?? 0,
    completedCount: digest?.completedCount ?? 0,
    totalCount: digest?.totalCount ?? 0,
    activePercent: digest?.activePercent ?? 0,
    releasePercent: digest?.releasePercent ?? 0,
    activeBlockerCount: digest?.activeBlockerCount ?? 0,
    releaseBlockerCount: digest?.releaseBlockerCount ?? 0,
    gapMetricLabel: digest?.gapMetricLabel ?? "",
    gapMetricHint: digest?.gapMetricHint ?? "",
    nextMilestoneTitle: digest?.nextMilestoneTitle ?? "",
    primaryGap: serializeOptionalProjectMilestoneCheck(digest?.primaryGap),
    topGaps: (digest?.topGaps ?? []).map(serializeProjectMilestoneCheck),
    nextAction: serializeReleaseReportAction(digest?.nextAction),
  };
}

function serializeFinalPublishGate(gate) {
  return {
    status: gate?.status ?? "",
    tone: gate?.tone ?? "",
    badge: gate?.badge ?? "",
    title: gate?.title ?? "",
    description: gate?.description ?? "",
    metrics: (gate?.metrics ?? []).map((metric) => ({
      label: metric?.label ?? "",
      value: metric?.value ?? "",
      hint: metric?.hint ?? "",
    })),
    primaryAction: serializeReleaseReportAction(gate?.primaryAction),
    secondaryActions: (gate?.secondaryActions ?? []).map(serializeReleaseReportAction).filter(Boolean),
    checklist: (gate?.checklist ?? []).map((item) => ({
      label: item?.label ?? "",
      detail: item?.detail ?? "",
      done: Boolean(item?.done),
      action: serializeReleaseReportAction(item?.action),
    })),
  };
}

function serializeRouteTestingPlan(plan = {}) {
  return routeTestingReportTools.serializeRouteTestingPlan(plan);
}

function formatProjectMilestonePrimaryBlocker(milestone) {
  const blocker = milestone?.blockers?.[0];
  if (!blocker) {
    return milestone?.done ? "已达标" : "进入试玩确认手感";
  }
  return blocker.missing || blocker.label || "继续补齐当前阶段";
}

function formatProjectMilestoneActions(actions = []) {
  const labels = (actions ?? []).map((action) => action?.label).filter(Boolean);
  return labels.length > 0 ? labels.join(" / ") : "试玩确认";
}

function buildReleaseReportNextStep(releaseFixOrder, projectMilestoneGapDigest) {
  const firstReleaseStep = releaseFixOrder?.steps?.[0];
  if (firstReleaseStep) {
    const action = firstReleaseStep.actions?.[0] ?? null;
    return {
      title: firstReleaseStep.title,
      description: firstReleaseStep.description,
      statusLabel: firstReleaseStep.statusLabel,
      action: serializeReleaseReportAction(action),
      source: "release_fix_order",
    };
  }

  if (projectMilestoneGapDigest && projectMilestoneGapDigest.status !== "ready") {
    const primaryGap = projectMilestoneGapDigest?.primaryGap;
    const action = primaryGap?.action ?? projectMilestoneGapDigest?.nextAction ?? null;
    return {
      title: primaryGap?.label ?? projectMilestoneGapDigest?.title ?? "继续推进成品目标路线",
      description:
        primaryGap?.missing ??
        projectMilestoneGapDigest?.description ??
        "先按成品目标路线补齐当前阶段，再重新巡检和试玩。",
      statusLabel: projectMilestoneGapDigest?.eyebrow ?? "当前阶段缺口",
      action: serializeReleaseReportAction(action),
      source: "project_milestone_gap",
    };
  }

  return {
    title: "最终试玩和正式导出",
    description: "当前没有明显阻塞，可以直接做最终试玩和正式导出。",
    statusLabel: "可以继续",
    action: null,
    source: "release_ready",
  };
}

function formatReleaseReportNextStepActionHint(nextStep) {
  const actionLabel = nextStep?.action?.label;
  return actionLabel ? `建议按钮：${actionLabel}。` : "";
}

function formatReleaseReportNextStepAdvice(nextStep) {
  const actionHint = formatReleaseReportNextStepActionHint(nextStep);
  if (nextStep?.source === "release_fix_order") {
    return `先处理「${nextStep.title}」，再重新导出一版原生 Runtime / 桌面包确认。${actionHint}`;
  }
  if (nextStep?.source === "project_milestone_gap") {
    return `发布修复队列暂时没有硬阻塞；先补「${nextStep.title}」，再重新巡检和试玩。${actionHint}`;
  }
  return "当前没有明显阻塞，可以直接做最终试玩和正式导出。";
}

function buildReleaseControlReportPayload() {
  const generatedAt = new Date().toISOString();
  const routeOverview = buildSceneRouteOverview();
  const issueItems = buildPreviewIssueItems();
  const releaseItems = buildReleaseChecklistItems();
  const releaseSummary = buildReleaseChecklistSummary(releaseItems);
  const releaseFixOrder = buildReleaseFixOrder(routeOverview);
  const finalPublishGate = buildFinalPublishGate(releaseItems, releaseFixOrder);
  const projectDoctorQueue = buildProjectDoctorQueue(routeOverview, issueItems);
  const projectDoctorSummary = buildProjectDoctorSummary(projectDoctorQueue);
  const projectMilestonePlan = buildProjectMilestonePlan(routeOverview);
  const projectMilestoneGapDigest = buildProjectMilestoneGapDigest(projectMilestonePlan);
  const mediaBudgetReport = buildAssetMediaBudgetReport();
  const native3dDigest = getLatestNativeRuntime3dDigest();
  const regressionResult = state.inspectionRegressionResult;
  const regressionFixQueue = buildPreviewRegressionFixQueue();
  const exportResult = state.lastExportResult;
  const routeTestingPlan = routeOverview.routeTestingPlan ?? {};
  const routeTestingSummary = routeTestingPlan.summary ?? {};
  const resolution = getProjectResolution();
  const urgentMissingAssets = state.data.assetList.filter((asset) => isAssetUrgentMissing(asset));
  const unusedAssets = getUnusedAssets();
  const nextStep = buildReleaseReportNextStep(releaseFixOrder, projectMilestoneGapDigest);
  const projectDoctorRepairReceiptReport = buildProjectDoctorRepairReceiptReportSummary(state.projectDoctorRepairReceipt);

  return {
    formatVersion: 1,
    generatedAt,
    generatedAtLabel: formatDate(generatedAt),
    project: {
      title: state.data.project.title,
      editorMode: getProjectEditorMode(),
      editorModeLabel: getEditorModeLabel(getProjectEditorMode()),
      releaseVersion: getProjectReleaseVersion(),
      resolution,
    },
    summary: {
      badge: releaseSummary.badge,
      title: releaseSummary.title,
      description: releaseSummary.description,
      blockerCount: releaseItems.filter((item) => item.severity === "blocker").length,
      warnCount: releaseItems.filter((item) => item.severity === "warn").length,
      readyCount: releaseItems.filter((item) => item.severity === "good").length,
      metrics: releaseSummary.metrics.map(([label, value]) => ({ label, value })),
    },
    finalPublishGate: serializeFinalPublishGate(finalPublishGate),
    validation: {
      errorCount: state.validation.errors.length,
      warningCount: state.validation.warnings.length,
      errors: state.validation.errors.map((issue) => ({
        message: issue.message,
        location: issue.location,
        context: issue.context ?? null,
        action: serializeReleaseReportAction(getValidationIssueAction(issue)),
      })),
      warnings: state.validation.warnings.map((issue) => ({
        message: issue.message,
        location: issue.location,
        context: issue.context ?? null,
        action: serializeReleaseReportAction(getValidationIssueAction(issue)),
      })),
    },
    route: {
      entrySceneName: routeOverview.metrics.entrySceneName,
      branchingScenes: routeOverview.metrics.branchingScenes,
      endingScenes: routeOverview.metrics.endingScenes,
      reachableEndingScenes: routeOverview.metrics.reachableEndingScenes,
      unreachableEndingScenes: routeOverview.metrics.unreachableEndingScenes,
      orphanScenes: routeOverview.metrics.orphanScenes,
      reachableScenes: routeOverview.metrics.reachableScenes,
      unreachableScenes: routeOverview.metrics.unreachableScenes,
      maxRouteDepth: routeOverview.metrics.maxRouteDepth,
      brokenRoutes: routeOverview.metrics.brokenRoutes,
      decisionPointScenes: routeOverview.metrics.decisionPointScenes,
      routeTestCases: routeOverview.metrics.routeTestCases,
      blockedRouteTestCases: routeOverview.metrics.blockedRouteTestCases,
      totalScenes: routeOverview.nodes.length,
      endingPaths: (routeOverview.endingPaths ?? []).map((path) => ({
        sceneName: path.sceneName,
        chapterName: path.chapterName,
        isReachable: path.isReachable,
        routeDepth: path.routeDepth,
        pathLabel: path.pathLabel,
      })),
      testingPlan: serializeRouteTestingPlan(routeOverview.routeTestingPlan),
    },
    projectMilestones: {
      ...serializeProjectMilestonePlan(projectMilestonePlan),
      gapDigest: serializeProjectMilestoneGapDigest(projectMilestoneGapDigest),
    },
    releaseChecklist: releaseItems.map((item) => ({
      title: item.title,
      status: item.status,
      severity: item.severity,
      severityLabel: getReleaseSeverityLabel(item.severity),
      description: item.description,
      action: serializeReleaseReportAction(item.action),
    })),
    fixOrder: {
      blockerCount: releaseFixOrder.blockerCount,
      urgentCount: releaseFixOrder.urgentCount,
      steps: releaseFixOrder.steps.map((step, index) => ({
        order: index + 1,
        tone: step.tone,
        toneLabel: getReleaseStepToneLabel(step.tone),
        title: step.title,
        statusLabel: step.statusLabel,
        description: step.description,
        actions: (step.actions ?? []).map(serializeReleaseReportAction).filter(Boolean),
      })),
    },
    projectDoctor: {
      badge: projectDoctorSummary.badge,
      title: projectDoctorSummary.title,
      description: projectDoctorSummary.description,
      lastRepairReceipt: state.projectDoctorRepairReceipt,
      lastRepairReceiptReport: projectDoctorRepairReceiptReport,
      dangerCount: projectDoctorSummary.dangerCount ?? 0,
      warnCount: projectDoctorSummary.warnCount ?? 0,
      softCount: projectDoctorSummary.softCount ?? 0,
      autoRepairableCount: projectDoctorSummary.autoRepairableCount ?? 0,
      autoRepairLabel: projectDoctorSummary.autoRepairLabel ?? "",
      nextStepTitle: projectDoctorSummary.nextStepTitle ?? "",
      steps: projectDoctorQueue.map((step) => ({
        order: step.order,
        kind: step.kind,
        label: step.label,
        badge: step.badge,
        tone: step.tone,
        title: step.title,
        meta: step.meta,
        why: step.why,
        recovery: step.recovery,
        doneWhen: step.doneWhen ?? "",
        repairCodes: getProjectDoctorAutoRepairCodes(step),
        repairLabel: formatProjectDoctorRepairCodes(getProjectDoctorAutoRepairCodes(step)),
        actions: (step.actions ?? []).map(serializeReleaseReportAction).filter(Boolean),
      })),
    },
    issues: issueItems.map((item) => ({
      kind: item.kind,
      label: item.label,
      title: item.title,
      meta: item.meta,
      action: serializeReleaseReportAction(item.action),
    })),
    assets: {
      urgentMissingCount: urgentMissingAssets.length,
      urgentMissingAssets: urgentMissingAssets.slice(0, 50).map((asset) => ({
        assetId: asset.id,
        name: asset.name,
        type: asset.type,
        typeLabel: getAssetTypeLabel(asset.type),
        path: asset.path,
      })),
      unusedCount: unusedAssets.length,
      unusedAssets: unusedAssets.slice(0, 50).map((asset) => ({
        assetId: asset.id,
        name: asset.name,
        type: asset.type,
        typeLabel: getAssetTypeLabel(asset.type),
        path: asset.path,
      })),
      mediaBudget: {
        count: mediaBudgetReport.count,
        blockerCount: mediaBudgetReport.blockerCount,
        warnCount: mediaBudgetReport.warnCount,
        totalBytes: mediaBudgetReport.totalBytes,
        totalLabel: mediaBudgetReport.totalLabel,
        items: mediaBudgetReport.items.slice(0, 50).map((item) => ({
          assetId: item.assetId,
          name: item.name,
          type: item.type,
          typeLabel: item.typeLabel,
          fileSizeBytes: item.fileSizeBytes,
          fileSizeLabel: item.fileSizeLabel,
          warnBytes: item.warnBytes,
          warnLabel: item.warnLabel,
          blockerBytes: item.blockerBytes,
          blockerLabel: item.blockerLabel,
          severity: item.severity,
          severityLabel: item.severityLabel,
          summary: item.summary,
          suggestion: item.suggestion,
        })),
      },
      native3dRisk: native3dDigest
        ? {
            status: native3dDigest.status ?? "",
            headline: native3dDigest.headline ?? "",
            summaryLine: native3dDigest.summaryLine ?? "",
            riskLine: formatNativeRuntime3dRiskLine(native3dDigest),
            riskCounts: native3dDigest.riskCounts ?? {},
            issueAssetIds: native3dDigest.issueAssetIds ?? [],
            topIssues: getNativeRuntime3dIssueAssets(native3dDigest).slice(0, 50),
            recommendations: native3dDigest.recommendations ?? [],
          }
        : null,
    },
    export: exportResult
      ? {
          target: exportResult.target ?? "",
          targetLabel: exportResult.targetLabel ?? "",
          buildPath: exportResult.buildPath ?? "",
          archiveSha256: exportResult.archiveSha256 ?? "",
          archiveSizeLabel: exportResult.archiveSizeLabel ?? "",
          releaseArtifactUploadCount: exportResult.releaseArtifactUploadCount ?? 0,
          missingAssets: exportResult.missingAssets ?? 0,
          missingAssetNames: exportResult.missingAssetNames ?? [],
          runtimeMode: exportResult.runtimeMode ?? "",
          runtimeModeLabel: exportResult.runtimeModeLabel ?? "",
          runtimeWarning: exportResult.runtimeWarning ?? "",
          releaseCandidateReportStatus: exportResult.releaseCandidateReportStatus ?? "",
          releaseCandidateReportSummary: exportResult.releaseCandidateReportSummary ?? {},
          releaseCandidateReadinessEstimate: exportResult.releaseCandidateReadinessEstimate ?? {},
          releaseControlStatus: exportResult.releaseControlStatus ?? "",
          releaseControlSummary: exportResult.releaseControlSummary ?? "",
          fileIntegrityStatus: exportResult.fileIntegrityStatus ?? "",
          fileIntegritySummary: exportResult.fileIntegritySummary ?? {},
          asset3dReportStatus: exportResult.asset3dReportStatus ?? "",
          asset3dReportSummary: exportResult.asset3dReportSummary ?? {},
          publicUrls: {
            manifest: exportResult.manifestPublicUrl ?? "",
            archive: exportResult.archivePublicUrl ?? "",
            archiveChecksum: exportResult.archiveChecksumPublicUrl ?? "",
            archiveChecksumJson: exportResult.archiveChecksumJsonPublicUrl ?? "",
            archiveVerifierMac: exportResult.archiveVerifierMacPublicUrl ?? "",
            archiveVerifierLinux: exportResult.archiveVerifierLinuxPublicUrl ?? "",
            archiveVerifierWindows: exportResult.archiveVerifierWindowsPublicUrl ?? "",
            releaseArtifactIndex: exportResult.releaseArtifactIndexPublicUrl ?? "",
            releaseArtifactIndexJson: exportResult.releaseArtifactIndexJsonPublicUrl ?? "",
            releaseNotes: exportResult.releaseNotesPublicUrl ?? "",
            releaseCandidateReport: exportResult.releaseCandidateReportPublicUrl ?? "",
            releaseControlReport: exportResult.releaseControlReportPublicUrl ?? "",
            releaseControlJson: exportResult.releaseControlJsonPublicUrl ?? "",
            macReleaseControlReporter: exportResult.macReleaseControlReporterPublicUrl ?? "",
            linuxReleaseControlReporter: exportResult.linuxReleaseControlReporterPublicUrl ?? "",
            windowsReleaseControlReporter: exportResult.windowsReleaseControlReporterPublicUrl ?? "",
            fileIntegrityReport: exportResult.fileIntegrityReportPublicUrl ?? "",
            fileIntegrityMarkdown: exportResult.fileIntegrityMarkdownPublicUrl ?? "",
            macFileIntegrityChecker: exportResult.macFileIntegrityCheckerPublicUrl ?? "",
            linuxFileIntegrityChecker: exportResult.linuxFileIntegrityCheckerPublicUrl ?? "",
            windowsFileIntegrityChecker: exportResult.windowsFileIntegrityCheckerPublicUrl ?? "",
            asset3dDigest: exportResult.asset3dDigestPublicUrl ?? "",
            asset3dReport: exportResult.asset3dReportPublicUrl ?? "",
            asset3dSummary: exportResult.asset3dSummaryPublicUrl ?? "",
          },
        }
      : null,
    regression: regressionResult
      ? {
          ranAt: regressionResult.ranAt,
          ranAtLabel: formatDate(regressionResult.ranAt),
          summary: regressionResult.summary,
          cases: regressionResult.cases.map((caseResult) => ({
            sceneId: caseResult.sceneId,
            sceneName: caseResult.sceneName,
            chapterName: caseResult.chapterName,
            sourceLabel: caseResult.sourceLabel,
            status: caseResult.status,
            statusLabel: caseResult.statusLabel,
            reason: caseResult.reason,
            detail: caseResult.detail,
            steps: caseResult.steps,
            visitedSceneCount: caseResult.visitedSceneCount,
            choiceCount: caseResult.choiceCount,
            variableOverrideSummary: caseResult.variableOverrideSummary ?? "",
            expectedTargetReached: Boolean(caseResult.expectedTargetReached),
            selectedOptionTexts: caseResult.selectedOptionTexts ?? [],
          })),
          fixQueue: regressionFixQueue.map((caseResult, index) => ({
            order: index + 1,
            sceneId: caseResult.sceneId,
            sceneName: caseResult.sceneName,
            chapterName: caseResult.chapterName,
            sourceLabel: caseResult.sourceLabel,
            status: caseResult.status,
            statusLabel: caseResult.statusLabel,
            priorityScore: caseResult.priorityScore,
            reason: caseResult.reason,
            recommendation: caseResult.recommendation,
          })),
        }
      : null,
    nextStep,
  };
}

function buildInspectionReportContent() {
  const routeOverview = buildSceneRouteOverview();
  const issueItems = buildPreviewIssueItems();
  const releaseItems = buildReleaseChecklistItems();
  const releaseSummary = buildReleaseChecklistSummary(releaseItems);
  const releaseFixOrder = buildReleaseFixOrder(routeOverview);
  const finalPublishGate = buildFinalPublishGate(releaseItems, releaseFixOrder);
  const projectDoctorQueue = buildProjectDoctorQueue(routeOverview, issueItems);
  const projectDoctorSummary = buildProjectDoctorSummary(projectDoctorQueue);
  const projectMilestonePlan = buildProjectMilestonePlan(routeOverview);
  const projectMilestoneGapDigest = buildProjectMilestoneGapDigest(projectMilestonePlan);
  const nextStep = buildReleaseReportNextStep(releaseFixOrder, projectMilestoneGapDigest);
  const regressionResult = state.inspectionRegressionResult;
  const regressionFixQueue = buildPreviewRegressionFixQueue();
  const exportResult = state.lastExportResult;
  const routeTestingPlan = routeOverview.routeTestingPlan ?? {};
  const routeTestingSummary = routeTestingPlan.summary ?? {};
  const lines = [
    `${state.data.project.title} · 项目巡检报告`,
    `导出时间：${formatDate(new Date().toISOString())}`,
    `项目模式：${getEditorModeLabel(getProjectEditorMode())}`,
    `发布版本：${getProjectReleaseVersion()}`,
    `分辨率：${getProjectResolution().width} × ${getProjectResolution().height}`,
    "",
    "总体结果：",
    `- 结构错误：${state.validation.errors.length} 项`,
    `- 补充提醒：${state.validation.warnings.length} 项`,
    `- 已引用缺口素材：${state.data.assetList.filter((asset) => isAssetUrgentMissing(asset)).length} 个`,
    `- 闲置素材：${getUnusedAssets().length} 个`,
    `- 入口场景：${routeOverview.metrics.entrySceneName}`,
    `- 分支场景：${routeOverview.metrics.branchingScenes} 个`,
    `- 收束场景：${routeOverview.metrics.endingScenes} 个`,
    `- 可打到结局：${routeOverview.metrics.reachableEndingScenes}/${routeOverview.metrics.endingScenes} 个`,
    `- 孤立场景：${routeOverview.metrics.orphanScenes} 个`,
    `- 可达场景：${routeOverview.metrics.reachableScenes}/${routeOverview.nodes.length} 个`,
    `- 不可达场景：${routeOverview.metrics.unreachableScenes} 个`,
    `- 最长路线深度：${routeOverview.metrics.maxRouteDepth} 步`,
    `- 坏链数量：${routeOverview.metrics.brokenRoutes} 条`,
    `- 路线试玩手册：${routeTestingSummary.decisionPointCount ?? 0} 个分支检查点 / ${routeTestingSummary.routeCaseCount ?? 0} 条路线用例 / ${routeTestingSummary.endingTestCaseCount ?? 0} 个结局用例`,
    `- 成品目标路线：${projectMilestonePlan.nextMilestone?.title ?? "继续推进当前项目"}（总进度 ${projectMilestonePlan.overallScore ?? 0}%）`,
    "",
    "发布检查判断：",
    `- ${releaseSummary.title}`,
    `- ${releaseSummary.description}`,
    "",
    "最终发表门禁：",
    `- ${finalPublishGate.badge}：${finalPublishGate.title}`,
    `- ${finalPublishGate.description}`,
    "",
  ];

  if (exportResult) {
    lines.push(
      "最近一次导出：",
      `- 目标：${exportResult.targetLabel ?? exportResult.target ?? "未记录"}`,
      `- 路径：${exportResult.buildPath ?? "未记录"}`,
      `- 缺失素材：${exportResult.missingAssets ?? 0} 个`,
      exportResult.runtimeModeLabel ? `- 桌面模式：${exportResult.runtimeModeLabel}` : "",
      exportResult.runtimeWarning ? `- 桌面壳提示：${exportResult.runtimeWarning}` : "",
      ""
    );
  }

  lines.push("路线试玩手册：");
  (routeTestingPlan.decisionPoints ?? []).slice(0, 6).forEach((point, index) => {
    const routeCaseSummary = (point.routeCases ?? [])
      .slice(0, 4)
      .map((routeCase) => `${routeCase.label} -> ${routeCase.targetSceneName}（${routeCase.statusLabel}）`)
      .join(" / ");
    lines.push(
      `${index + 1}. ${point.sceneName}`,
      `   路径：${point.entryPathLabel || "入口未接通"}`,
      `   分支：${routeCaseSummary || "暂无可列出的分支用例"}`
    );
  });
  if ((routeTestingPlan.decisionPoints ?? []).length === 0) {
    lines.push("1. 当前还没有需要单独覆盖的分支点。");
  }
  (routeTestingPlan.endingTestCases ?? []).slice(0, 4).forEach((testCase, index) => {
    lines.push(
      `结局 ${index + 1}. ${testCase.sceneName} / ${testCase.statusLabel}`,
      `   路径：${testCase.pathLabel || "暂未接通"}`,
      `   提示：${testCase.testingHint}`
    );
  });
  lines.push("");

  if (state.validation.errors.length > 0) {
    lines.push("结构错误：");
    state.validation.errors.forEach((issue) => {
      lines.push(`- ${issue.message} / ${issue.location}`);
    });
    lines.push("");
  }

  if (state.validation.warnings.length > 0) {
    lines.push("补充提醒：");
    state.validation.warnings.forEach((issue) => {
      lines.push(`- ${issue.message} / ${issue.location}`);
    });
    lines.push("");
  }

  const exportMissingItem = issueItems.find((item) => item.kind === "export_missing");
  if (exportMissingItem) {
    lines.push("导出缺失素材：", `- ${exportMissingItem.title}`, `- ${exportMissingItem.meta}`, "");
  }

  const unusedAssetItem = issueItems.find((item) => item.kind === "unused_assets");
  if (unusedAssetItem) {
    lines.push("闲置素材：", `- ${unusedAssetItem.title}`, `- ${unusedAssetItem.meta}`, "");
  }

  lines.push("处理动作：");
  if (state.validation.errors.length > 0) {
    lines.push("- 先清结构错误，再继续试玩和正式导出。");
  } else if ((exportResult?.missingAssets ?? 0) > 0) {
    lines.push("- 先补导出缺失素材，再重新导一版包确认。");
  } else if (state.validation.warnings.length > 0) {
    lines.push("- 现在没有硬阻塞，可以边试玩边压提醒项。");
  } else {
    lines.push("- 当前巡检结果比较干净，可以继续做正式导出和最终试玩。");
  }

  lines.push("", "项目医生修复队列：");
  lines.push(`- ${projectDoctorSummary.badge}：${projectDoctorSummary.title}`);
  lines.push(`- ${projectDoctorSummary.description}`);
  lines.push(`- ${projectDoctorSummary.autoRepairLabel ?? "暂无可预览修复项"}`);
  if (state.projectDoctorRepairReceipt) {
    const receiptLabels = getProjectDoctorRepairReceiptReportLabels(state.projectDoctorRepairReceipt);
    const receiptItems = buildProjectDoctorRepairReceiptReportItems(state.projectDoctorRepairReceipt, receiptLabels);
    const receiptWriteStatus = getProjectDoctorRepairReceiptWriteStatus(state.projectDoctorRepairReceipt);
    lines.push(
      `- ${receiptLabels.heading}：${state.projectDoctorRepairReceipt.title}`,
      `- 回执编号：${getProjectDoctorRepairReceiptDisplayId(state.projectDoctorRepairReceipt)}`,
      `- ${receiptLabels.timeLabel}：${formatDate(state.projectDoctorRepairReceipt.generatedAt)}`,
      `- ${receiptLabels.countLabel}：${state.projectDoctorRepairReceipt.repairCount ?? 0} / ${state.projectDoctorRepairReceipt.skippedCount ?? 0}`,
      `- 写入状态：${receiptWriteStatus.label}（${receiptWriteStatus.detail}）`,
      `- 修复范围：${formatProjectDoctorRepairReceiptScope(state.projectDoctorRepairReceipt)}`,
      ...receiptItems.map((item) => `- ${item}`),
      ""
    );
  }
  if (projectDoctorQueue.length > 0) {
    projectDoctorQueue.forEach((step) => {
      lines.push(
        `${step.order}. ${step.title}`,
        `   类型：${step.label} / ${step.badge}`,
        `   位置：${step.meta}`,
        `   原因：${step.why}`,
        `   建议：${step.recovery}`,
        `   修完应该看到：${step.doneWhen ?? "重新巡检后，这条问题会消失或变成可确认的提醒。"}`,
        `   安全修复：${formatProjectDoctorRepairCodes(getProjectDoctorAutoRepairCodes(step))}`,
        ""
      );
    });
  } else {
    lines.push("1. 当前没有项目医生需要优先处理的事项。");
  }

  lines.push("", "成品目标路线：");
  lines.push(
    `- ${projectMilestonePlan.headline ?? "继续推进当前项目。"}`,
    `- ${projectMilestoneGapDigest.eyebrow ?? "当前阶段缺口"}：${projectMilestoneGapDigest.title}`,
    `- 建议：${projectMilestoneGapDigest.description}`,
    `- 总进度：${projectMilestonePlan.overallScore ?? 0}%`,
    `- 已完成阶段：${projectMilestonePlan.completedCount ?? 0}/${projectMilestonePlan.totalCount ?? 0}`,
    `- 当前阶段：${projectMilestonePlan.nextMilestone?.title ?? "继续推进当前项目"}`,
    `- 下一步缺口：${formatProjectMilestonePrimaryBlocker(projectMilestonePlan.nextMilestone)}`,
    ""
  );
  if ((projectMilestoneGapDigest.topGaps ?? []).length > 0) {
    lines.push("优先缺口：");
    projectMilestoneGapDigest.topGaps.forEach((gap, index) => {
      lines.push(`${index + 1}. ${gap.label ?? "待处理项"}：${gap.missing || gap.detail || "继续补齐这个条件。"}`);
    });
    lines.push("");
  }
  (projectMilestonePlan.milestones ?? []).forEach((milestone, index) => {
    lines.push(
      `${index + 1}. ${milestone.title}`,
      `   状态：${milestone.done ? "已达标" : `${milestone.percent}%`}`,
      `   说明：${milestone.summary}`,
      `   下一步：${formatProjectMilestonePrimaryBlocker(milestone)}`,
      `   按钮：${formatProjectMilestoneActions(milestone.actions)}`,
      ""
    );
  });

  lines.push("", "发布前修复顺序：");
  if (releaseFixOrder.steps.length > 0) {
    releaseFixOrder.steps.forEach((step, index) => {
      lines.push(
        `${index + 1}. ${step.title}`,
        `   说明：${step.description}`,
        `   当前状态：${step.statusLabel}`,
        ""
      );
    });
  } else {
    lines.push(`1. ${formatReleaseReportNextStepAdvice(nextStep)}`);
  }

  lines.push("", "自动回归试玩路线测试：");
  if (regressionResult) {
    lines.push(
      `- 回归时间：${formatDate(regressionResult.ranAt)}`,
      `- 已测试路线：${regressionResult.summary.total} 条`,
      `- 通过：${regressionResult.summary.passCount} 条`,
      `- 需要复看：${regressionResult.summary.warnCount} 条`,
      `- 失败：${regressionResult.summary.failCount} 条`,
      ""
    );
    regressionResult.cases.forEach((caseResult, index) => {
      lines.push(
        `${index + 1}. ${caseResult.sceneName} / ${caseResult.statusLabel}`,
        `   来源：${caseResult.chapterName} · ${caseResult.sourceLabel}`,
        `   说明：${caseResult.reason}`,
        `   细节：${caseResult.detail}`,
        `   步数：${caseResult.steps} / 访问场景：${caseResult.visitedSceneCount} / 选择次数：${caseResult.choiceCount}`,
        caseResult.variableOverrideSummary ? `   测试预设：${caseResult.variableOverrideSummary}` : "",
        caseResult.selectedOptionTexts.length > 0
          ? `   选择路线：${caseResult.selectedOptionTexts.join(" / ")}`
          : "",
        ""
      );
    });
  } else {
    lines.push("1. 还没有执行自动回归试玩路线测试。");
  }

  lines.push("", "发布前回归修复优先队列：");
  if (regressionFixQueue.length > 0) {
    regressionFixQueue.forEach((caseResult, index) => {
      lines.push(
        `${index + 1}. ${caseResult.sceneName} / ${caseResult.statusLabel}`,
        `   来源：${caseResult.chapterName} · ${caseResult.sourceLabel}`,
        `   优先分：${caseResult.priorityScore}`,
        `   先修原因：${caseResult.reason}`,
        `   处理动作：${caseResult.recommendation}`,
        ""
      );
    });
  } else {
    lines.push(
      regressionResult
        ? "1. 这轮自动回归里暂时没有需要优先修的失败或提醒路线。"
        : "1. 先执行自动回归试玩路线测试，这里才会生成优先修复顺序。"
    );
  }

  return `\uFEFF${lines.filter(Boolean).join("\n")}`;
}

function buildReleaseControlReportContent() {
  const routeOverview = buildSceneRouteOverview();
  const issueItems = buildPreviewIssueItems();
  const releaseItems = buildReleaseChecklistItems();
  const releaseSummary = buildReleaseChecklistSummary(releaseItems);
  const releaseFixOrder = buildReleaseFixOrder(routeOverview);
  const finalPublishGate = buildFinalPublishGate(releaseItems, releaseFixOrder);
  const projectDoctorQueue = buildProjectDoctorQueue(routeOverview, issueItems);
  const projectDoctorSummary = buildProjectDoctorSummary(projectDoctorQueue);
  const projectMilestonePlan = buildProjectMilestonePlan(routeOverview);
  const projectMilestoneGapDigest = buildProjectMilestoneGapDigest(projectMilestonePlan);
  const nextStep = buildReleaseReportNextStep(releaseFixOrder, projectMilestoneGapDigest);
  const mediaBudgetReport = buildAssetMediaBudgetReport();
  const native3dDigest = getLatestNativeRuntime3dDigest();
  const regressionResult = state.inspectionRegressionResult;
  const regressionFixQueue = buildPreviewRegressionFixQueue();
  const exportResult = state.lastExportResult;
  const routeTestingPlan = routeOverview.routeTestingPlan ?? {};
  const routeTestingSummary = routeTestingPlan.summary ?? {};
  const resolution = getProjectResolution();
  const generatedAt = new Date().toISOString();
  const projectDoctorReceiptLabels = state.projectDoctorRepairReceipt
    ? getProjectDoctorRepairReceiptReportLabels(state.projectDoctorRepairReceipt)
    : null;
  const projectDoctorReceiptReportItems = state.projectDoctorRepairReceipt && projectDoctorReceiptLabels
    ? buildProjectDoctorRepairReceiptReportItems(state.projectDoctorRepairReceipt, projectDoctorReceiptLabels)
    : [];
  const projectDoctorReceiptWriteStatus = state.projectDoctorRepairReceipt
    ? getProjectDoctorRepairReceiptWriteStatus(state.projectDoctorRepairReceipt)
    : null;
  const releaseChecklistTable = buildMarkdownTable(
    ["检查项", "状态", "级别", "说明"],
    releaseItems.map((item) => [
      item.title,
      item.status,
      getReleaseSeverityLabel(item.severity),
      item.description,
    ])
  );
  const finalPublishGateTable = buildMarkdownTable(
    ["项目", "结果", "说明"],
    [
      ["门禁状态", finalPublishGate.badge, finalPublishGate.title],
      ["门禁结论", finalPublishGate.status, finalPublishGate.description],
      ...(finalPublishGate.metrics ?? []).map((metric) => [
        metric.label ?? "",
        metric.value ?? "",
        metric.hint ?? "",
      ]),
    ]
  );
  const finalPublishGateChecklistTable = buildMarkdownTable(
    ["事项", "说明", "完成"],
    (finalPublishGate.checklist ?? []).map((item) => [
      item.label ?? "",
      item.detail ?? "",
      item.done ? "是" : "否",
    ])
  );
  const mediaBudgetTable = buildMarkdownTable(
    ["素材", "类型", "当前体积", "建议预算", "级别", "建议"],
    mediaBudgetReport.items.slice(0, 20).map((item) => [
      item.name,
      item.typeLabel,
      item.fileSizeLabel,
      item.warnLabel,
      item.severityLabel,
      item.suggestion,
    ])
  );
  const native3dIssueTable = buildMarkdownTable(
    ["素材", "类型", "状态", "风险", "引用", "建议"],
    getNativeRuntime3dIssueAssets(native3dDigest)
      .slice(0, 20)
      .map((issue) => [
        issue.name,
        issue.typeLabel,
        issue.statusLabel,
        issue.summary,
        Array.isArray(issue.usagePreview) && issue.usagePreview.length ? issue.usagePreview.join(" / ") : `${issue.usageCount ?? 0} 处`,
        issue.recommendedAction,
      ])
  );
  const fixOrderTable = buildMarkdownTable(
    ["顺序", "优先级", "事项", "当前状态", "说明"],
    releaseFixOrder.steps.map((step, index) => [
      `${index + 1}`,
      getReleaseStepToneLabel(step.tone),
      step.title,
      step.statusLabel,
      step.description,
    ])
  );
  const issueTable = buildMarkdownTable(
    ["类型", "标题", "位置 / 摘要"],
    issueItems.slice(0, 30).map((item) => [item.label, item.title, item.meta])
  );
  const projectDoctorTable = buildMarkdownTable(
    ["顺序", "类型", "事项", "为什么", "建议怎么修", "修完应该看到", "安全修复"],
    projectDoctorQueue.map((step) => [
      `${step.order}`,
      `${step.label} / ${step.badge}`,
      `${step.title} / ${step.meta}`,
      step.why,
      step.recovery,
      step.doneWhen ?? "重新巡检后，这条问题会消失或变成可确认的提醒。",
      formatProjectDoctorRepairCodes(getProjectDoctorAutoRepairCodes(step)),
    ])
  );
  const projectMilestoneTable = buildMarkdownTable(
    ["阶段", "状态", "完成度", "当前缺口", "下一步按钮"],
    (projectMilestonePlan.milestones ?? []).map((milestone) => [
      milestone.title,
      milestone.done ? "已达标" : "继续推进",
      `${milestone.percent ?? 0}%`,
      formatProjectMilestonePrimaryBlocker(milestone),
      formatProjectMilestoneActions(milestone.actions),
    ])
  );
  const projectMilestoneGapTable = buildMarkdownTable(
    ["顺序", "缺口", "处理提示"],
    (projectMilestoneGapDigest.topGaps ?? []).map((gap, index) => [
      `${index + 1}`,
      gap.label ?? "待处理项",
      gap.missing || gap.detail || "继续补齐这个条件。",
    ])
  );
  const regressionTable = regressionResult
    ? buildMarkdownTable(
        ["路线", "状态", "来源", "细节", "步数"],
        regressionResult.cases.map((caseResult) => [
          caseResult.sceneName,
          caseResult.statusLabel,
          `${caseResult.chapterName} · ${caseResult.sourceLabel}`,
          caseResult.detail,
          `${caseResult.steps}`,
        ])
      )
    : "";
  const regressionFixTable = buildMarkdownTable(
    ["顺序", "路线", "状态", "优先分", "处理建议"],
    regressionFixQueue.map((caseResult, index) => [
      `${index + 1}`,
      caseResult.sceneName,
      caseResult.statusLabel,
      `${caseResult.priorityScore}`,
      caseResult.recommendation,
    ])
  );
  const routeTestingTables = routeTestingReportTools.buildRouteTestingReportTables(routeTestingPlan);

  const lines = [
    `# ${state.data.project.title} 发布前总控报告`,
    "",
    `- 生成时间：${formatDate(generatedAt)}`,
    `- 项目模式：${getEditorModeLabel(getProjectEditorMode())}`,
    `- 发布版本：${getProjectReleaseVersion()}`,
    `- 分辨率：${resolution.width} × ${resolution.height}`,
    `- 发布判断：${releaseSummary.badge} · ${releaseSummary.title}`,
    "",
    "## 总览",
    "",
    releaseSummary.description,
    "",
    buildMarkdownTable(
      ["指标", "结果"],
      [
        ["结构错误", `${state.validation.errors.length} 项`],
        ["补充提醒", `${state.validation.warnings.length} 项`],
        ["已引用缺口素材", `${state.data.assetList.filter((asset) => isAssetUrgentMissing(asset)).length} 个`],
        ["素材预算风险", `${mediaBudgetReport.count} 个，合计 ${mediaBudgetReport.totalLabel}`],
        ["闲置素材", `${getUnusedAssets().length} 个`],
        ["入口场景", routeOverview.metrics.entrySceneName],
        ["分支 / 收束 / 孤立场景", `${routeOverview.metrics.branchingScenes} / ${routeOverview.metrics.endingScenes} / ${routeOverview.metrics.orphanScenes}`],
        ["可打到结局", `${routeOverview.metrics.reachableEndingScenes} / ${routeOverview.metrics.endingScenes}`],
        ["第一条结局路径", routeOverview.endingPaths?.find((path) => path.isReachable)?.pathLabel ?? "暂未接通"],
        ["可达 / 不可达 / 最长深度", `${routeOverview.metrics.reachableScenes} / ${routeOverview.metrics.unreachableScenes} / ${routeOverview.metrics.maxRouteDepth} 步`],
        ["路线试玩手册", `${routeTestingSummary.decisionPointCount ?? 0} 个分支点 / ${routeTestingSummary.routeCaseCount ?? 0} 条路线用例 / ${routeTestingSummary.endingTestCaseCount ?? 0} 个结局用例`],
        ["坏链数量", `${routeOverview.metrics.brokenRoutes} 条`],
        ["成品目标路线", `${projectMilestonePlan.nextMilestone?.title ?? "继续推进当前项目"}（${projectMilestonePlan.overallScore ?? 0}%）`],
        [projectMilestoneGapDigest.eyebrow ?? "当前阶段缺口", projectMilestoneGapDigest.title],
      ]
    ),
    "",
    "## 路线试玩手册",
    "",
    routeTestingTables.summaryTable || "当前没有可列出的路线试玩手册摘要。",
    "",
    routeTestingTables.decisionTable || "当前没有需要单独覆盖的分支点。",
    "",
    routeTestingTables.endingTable || "当前没有可列出的结局试玩路径。",
    "",
    "## 最终发表门禁",
    "",
    finalPublishGateTable || "当前没有可列出的最终发表门禁。",
    "",
    finalPublishGateChecklistTable || "当前关键发布门槛已达标，可以进入附件整理、发布说明和最后人工验收。",
    "",
    "## 发布检查清单",
    "",
    releaseChecklistTable || "当前没有可列出的发布检查项。",
    "",
  ];

  if (exportResult) {
    lines.push(
      "## 最近一次导出",
      "",
      buildMarkdownTable(
        ["项目", "内容"],
        [
          ["目标", exportResult.targetLabel ?? exportResult.target ?? "未记录"],
          ["路径", exportResult.buildPath ?? "未记录"],
          ["缺失素材", `${exportResult.missingAssets ?? 0} 个`],
          ["桌面模式", exportResult.runtimeModeLabel ?? "未记录"],
          ["桌面壳提示", exportResult.runtimeWarning ?? "无"],
          ["原生 RC", exportResult.releaseCandidateReportStatus ?? "未生成"],
          ["3D 清单", exportResult.asset3dReportStatus ?? "未生成"],
        ]
      ),
      ""
    );
  }

  lines.push(
    "## 项目医生修复队列",
    "",
    `- ${projectDoctorSummary.badge}：${projectDoctorSummary.title}`,
    `- ${projectDoctorSummary.description}`,
    `- ${projectDoctorSummary.autoRepairLabel ?? "暂无可预览修复项"}`,
    ...(state.projectDoctorRepairReceipt && projectDoctorReceiptLabels
      ? [
          `- ${projectDoctorReceiptLabels.compactPrefix}：${state.projectDoctorRepairReceipt.title}（${projectDoctorReceiptLabels.repairVerb} ${state.projectDoctorRepairReceipt.repairCount ?? 0} 项，${projectDoctorReceiptLabels.skipVerb} ${state.projectDoctorRepairReceipt.skippedCount ?? 0} 项）`,
          `- 回执编号：${getProjectDoctorRepairReceiptDisplayId(state.projectDoctorRepairReceipt)}`,
          `- 写入状态：${projectDoctorReceiptWriteStatus.label}（${projectDoctorReceiptWriteStatus.detail}）`,
          `- 修复范围：${formatProjectDoctorRepairReceiptScope(state.projectDoctorRepairReceipt)}`,
          ...projectDoctorReceiptReportItems.map((item) => `- ${item}`),
        ]
      : []),
    "",
    projectDoctorTable || "当前没有项目医生需要优先处理的事项。",
    ""
  );

  lines.push(
    "## 成品目标路线",
    "",
    `- ${projectMilestonePlan.headline ?? "继续推进当前项目。"}`,
    `- ${projectMilestoneGapDigest.eyebrow ?? "当前阶段缺口"}：${projectMilestoneGapDigest.title}`,
    `- 建议：${projectMilestoneGapDigest.description}`,
    `- 总进度：${projectMilestonePlan.overallScore ?? 0}%`,
    `- 已完成阶段：${projectMilestonePlan.completedCount ?? 0}/${projectMilestonePlan.totalCount ?? 0}`,
    `- 当前阶段：${projectMilestonePlan.nextMilestone?.title ?? "继续推进当前项目"}`,
    `- 下一步缺口：${formatProjectMilestonePrimaryBlocker(projectMilestonePlan.nextMilestone)}`,
    "",
    projectMilestoneGapTable || "当前没有需要优先列出的阶段缺口。",
    "",
    projectMilestoneTable || "当前没有可列出的成品目标路线。",
    ""
  );

  lines.push("## 发布前修复顺序", "", fixOrderTable || formatReleaseReportNextStepAdvice(nextStep), "");

  lines.push("## 素材性能预算", "");
  if (mediaBudgetReport.count > 0) {
    lines.push(
      `当前有 ${mediaBudgetReport.count} 个素材建议发布前压缩，其中明显超预算 ${mediaBudgetReport.blockerCount} 个，合计 ${mediaBudgetReport.totalLabel}。`,
      "",
      mediaBudgetTable,
      ""
    );
  } else {
    lines.push("当前没有明显超出建议预算的大图、大音频、大视频、Live2D 或 3D 资产。", "");
  }

  lines.push("## 3D 发布风险", "");
  if (native3dDigest) {
    lines.push(
      `- 状态：${native3dDigest.headline ?? native3dDigest.status ?? "未记录"}`,
      `- 摘要：${native3dDigest.summaryLine ?? "未记录"}`,
      `- 风险拆分：${formatNativeRuntime3dRiskLine(native3dDigest)}`,
      ""
    );
    if (native3dIssueTable) {
      lines.push(native3dIssueTable, "");
    } else {
      lines.push("当前没有需要定位的 3D 风险素材。", "");
    }
  } else {
    lines.push("还没有最近一次原生 Runtime 3D 风险摘要。导出原生 Runtime 包后会自动生成。", "");
  }

  lines.push("## 巡检问题 Top 列表", "", issueTable || "当前没有巡检问题。", "");

  lines.push("## 自动回归试玩路线", "");
  if (regressionResult) {
    lines.push(
      `- 已测试：${regressionResult.summary.total} 条`,
      `- 通过：${regressionResult.summary.passCount} 条`,
      `- 需要复看：${regressionResult.summary.warnCount} 条`,
      `- 失败：${regressionResult.summary.failCount} 条`,
      "",
      regressionTable || "没有可列出的回归路线。",
      ""
    );
  } else {
    lines.push("还没有执行自动回归试玩路线测试。", "");
  }

  lines.push("## 回归修复优先队列", "", regressionFixTable || "当前没有回归修复队列。", "");

  lines.push(
    "## 下一步建议",
    "",
    formatReleaseReportNextStepAdvice(nextStep),
    ""
  );

  return `\uFEFF${lines.join("\n")}`;
}

