function getCharacterPrimarySpriteAssetId(character) {
  const presentation = character?.presentation ?? {};
  const expressionSpriteId = (character?.expressions ?? []).find((expression) => expression?.spriteAssetId)?.spriteAssetId ?? "";
  return presentation.fallbackSpriteAssetId || character?.defaultSpriteId || expressionSpriteId || "";
}

function buildReleaseCreativeQualityContext() {
  const data = state.data ?? {};
  const chapters = data.chapters ?? [];
  const scenes = chapters.flatMap((chapter) => chapter.scenes ?? []);
  const characters = data.characters ?? [];
  const assetsById = data.assetsById ?? new Map();
  const assetList = data.assetList ?? [];
  const scriptEntries = analyzeScriptEntries(buildScriptEntries());
  const effectBlockTypes = new Set([
    "particle_effect",
    "screen_shake",
    "screen_flash",
    "screen_fade",
    "camera_zoom",
    "camera_pan",
    "screen_filter",
    "depth_blur",
  ]);
  const storyScenes = scenes.filter((scene) =>
    (scene.blocks ?? []).some((block) => ["dialogue", "narration", "choice"].includes(block.type))
  );
  const storySceneBlocks = storyScenes.flatMap((scene) => scene.blocks ?? []);

  return {
    storySceneCount: storyScenes.length,
    dialogueCount: scriptEntries.filter((entry) => entry.type === "dialogue").length,
    narrationCount: scriptEntries.filter((entry) => entry.type === "narration").length,
    choiceCount: scriptEntries.filter((entry) => entry.type === "choice").length,
    characterCount: characters.length,
    charactersWithSpriteCount: characters.filter((character) => {
      const assetId = getCharacterPrimarySpriteAssetId(character);
      const asset = assetId ? assetsById.get(assetId) : null;
      return Boolean(assetId && (!asset || asset.fileExists));
    }).length,
    characterShowCount: storySceneBlocks.filter((block) => block.type === "character_show" && block.characterId).length,
    characterHideCount: storySceneBlocks.filter((block) => block.type === "character_hide" && block.characterId).length,
    scenesWithBackground: storyScenes.filter((scene) =>
      (scene.blocks ?? []).some((block) => block.type === "background" && block.assetId)
    ).length,
    scenesWithMusic: storyScenes.filter((scene) =>
      (scene.blocks ?? []).some((block) => block.type === "music_play" && block.assetId)
    ).length,
    scenesWithEffects: storyScenes.filter((scene) =>
      (scene.blocks ?? []).some((block) => effectBlockTypes.has(block.type))
    ).length,
    placeholderAssetCount: assetList.filter(
      (asset) => Array.isArray(asset.tags) && asset.tags.includes("占位素材")
    ).length,
    placeholderScriptCount: scriptEntries.filter((entry) => (entry.issues ?? []).includes("placeholder")).length,
  };
}

function buildReleaseFixOrder(routeOverview) {
  if (releaseControlTools?.buildReleaseFixOrder) {
    const project = state.data?.project ?? {};
    const validationErrors = state.validation?.errors ?? [];
    const validationWarnings = state.validation?.warnings ?? [];
    const missingVoiceWarnings = validationWarnings.filter(
      (issue) => issue.message === "这句台词还没有绑定语音。"
    );
    const nonVoiceWarnings = validationWarnings.filter(
      (issue) => issue.message !== "这句台词还没有绑定语音。"
    );

    return releaseControlTools.buildReleaseFixOrder({
      project,
      resolution: getProjectResolution(project),
      releaseVersion: getProjectReleaseVersion(project),
      hasStoredReleaseVersion: Boolean(String(project.releaseVersion ?? "").trim()),
      errorCount: validationErrors.length,
      warningIssues: validationWarnings,
      firstErrorAction: validationErrors[0] ? getValidationIssueAction(validationErrors[0]) : null,
      firstVoiceAction: missingVoiceWarnings[0] ? getValidationIssueAction(missingVoiceWarnings[0]) : null,
      firstWarningAction: nonVoiceWarnings[0] ? getValidationIssueAction(nonVoiceWarnings[0]) : null,
      routeMetrics: routeOverview?.metrics ?? {},
      urgentMissingAssetsCount: state.data.assetList.filter((asset) => isAssetUrgentMissing(asset)).length,
      mediaBudgetReport: buildAssetMediaBudgetReport(),
      unusedAssetCount: getUnusedAssets().length,
      exportResult: state.lastExportResult,
      creativeQuality: buildReleaseCreativeQualityContext(),
    });
  }

  const project = state.data?.project ?? {};
  const resolution = getProjectResolution(project);
  const releaseVersion = getProjectReleaseVersion(project);
  const hasStoredReleaseVersion = Boolean(String(project.releaseVersion ?? "").trim());
  const urgentMissingAssets = state.data.assetList.filter((asset) => isAssetUrgentMissing(asset)).length;
  const mediaBudgetReport = buildAssetMediaBudgetReport();
  const unusedAssets = getUnusedAssets();
  const missingVoiceWarnings = state.validation.warnings.filter(
    (issue) => issue.message === "这句台词还没有绑定语音。"
  );
  const nonVoiceWarnings = state.validation.warnings.filter(
    (issue) => issue.message !== "这句台词还没有绑定语音。"
  );
  const exportResult = state.lastExportResult;
  const steps = [];

  if (state.validation.errors.length > 0) {
    const firstErrorAction = getValidationIssueAction(state.validation.errors[0]);
    steps.push({
      tone: "danger",
      title: "先清结构错误",
      statusLabel: `还有 ${state.validation.errors.length} 项结构错误`,
      description: "这些问题最容易直接打断剧情推进、跳错场景，或者让正式导出后的流程不完整。",
      actions: [
        {
          label: "只看结构错误",
          action: "set-preview-issue-filter",
          dataset: { "preview-issue-filter": "errors" },
        },
        firstErrorAction
          ? { ...firstErrorAction, label: "打开第一条错误" }
          : { label: "去剧情页修", action: "switch-screen", screen: "story" },
      ],
    });
  }

  const orphanSceneCount = routeOverview.metrics.orphanScenes ?? 0;
  const unreachableSceneCount = routeOverview.metrics.unreachableScenes ?? 0;
  if (orphanSceneCount > 0 || unreachableSceneCount > 0) {
    steps.push({
      tone: "warn",
      title: "检查孤立场景和路线入口",
      statusLabel:
        orphanSceneCount > 0 && unreachableSceneCount > 0
          ? `还有 ${orphanSceneCount} 个孤立场景 / ${unreachableSceneCount} 个不可达场景`
          : orphanSceneCount > 0
            ? `还有 ${orphanSceneCount} 个孤立场景`
            : `还有 ${unreachableSceneCount} 个入口不可达场景`,
      description: "这些场景可能没有入口，或者虽然有入口线、但从项目入口试玩时仍然走不到。",
      actions: [
        { label: "回首页看路线图", action: "switch-screen", screen: "dashboard" },
        { label: "去剧情页补跳转", action: "switch-screen", screen: "story" },
      ],
    });
  }

  if (urgentMissingAssets > 0) {
    steps.push({
      tone: "warn",
      title: "补齐已引用缺口素材",
      statusLabel: `还有 ${urgentMissingAssets} 个引用缺口`,
      description: "这些素材已经被剧情使用，但真实文件还没准备好，正式导出后会直接缺图、缺音或缺视频。",
      actions: [
        {
          label: "去补缺口素材",
          action: "focus-asset-gap",
          dataset: { "asset-filter-mode": "urgent_missing" },
        },
        {
          label: "只看导出缺失",
          action: "set-preview-issue-filter",
          dataset: { "preview-issue-filter": "export_missing" },
        },
      ],
    });
  }

  if (mediaBudgetReport.count > 0) {
    const largest = mediaBudgetReport.largest;
    steps.push({
      tone: mediaBudgetReport.blockerCount > 0 ? "warn" : "soft",
      title: "压缩超预算素材",
      statusLabel:
        mediaBudgetReport.blockerCount > 0
          ? `明显超预算 ${mediaBudgetReport.blockerCount} 个`
          : `建议压缩 ${mediaBudgetReport.count} 个素材`,
      description: largest
        ? `先从最大素材「${largest.name}」开始处理。当前风险素材合计 ${mediaBudgetReport.totalLabel}，压一轮会直接改善包体和加载体验。`
        : "发布前建议压缩体积偏大的素材，降低包体和加载风险。",
      actions: [
        {
          label: "只看体积风险素材",
          action: "focus-asset-gap",
          dataset: { "asset-filter-mode": "media_budget" },
        },
        largest
          ? {
              label: "打开最大素材",
              action: "open-asset-from-issue",
              assetId: largest.assetId,
            }
          : { label: "去素材页", action: "switch-screen", screen: "assets" },
      ],
    });
  }

  if (missingVoiceWarnings.length > 0) {
    const firstVoiceAction = getValidationIssueAction(missingVoiceWarnings[0]);
    steps.push({
      tone: "warn",
      title: "集中补待绑语音",
      statusLabel: `还有 ${missingVoiceWarnings.length} 句待绑语音`,
      description: "如需准备正式版本，这一批最好先集中清掉，后面的配音整理和最终试玩都会轻很多。",
      actions: [
        { label: "只看待绑语音", action: "focus-script-missing-voice" },
        firstVoiceAction
          ? { ...firstVoiceAction, label: "打开第一句" }
          : { label: "去台本页处理", action: "switch-screen", screen: "script" },
      ],
    });
  }

  if (!hasStoredReleaseVersion || resolution.width !== 1920 || resolution.height !== 1080) {
    steps.push({
      tone: "soft",
      title: "确认发布版本和分辨率",
      statusLabel:
        !hasStoredReleaseVersion
          ? `当前版本 ${releaseVersion} 还没正式写入`
          : `${resolution.width} × ${resolution.height}`,
      description: "在正式导出前，先把版本号和桌面分辨率定下来，后面的发布清单、桌面包和交付说明会更一致。",
      actions: [
        !hasStoredReleaseVersion
          ? { label: "保存发布版本", action: "save-release-version" }
          : { label: "去预览导出页", action: "switch-screen", screen: "preview" },
        resolution.width === 1920 && resolution.height === 1080
          ? { label: "查看导出设置", action: "switch-screen", screen: "preview" }
          : {
              label: "切到 1920×1080",
              action: "set-resolution",
              dataset: { width: "1920", height: "1080" },
            },
      ],
    });
  }

  if (nonVoiceWarnings.length > 0) {
    const firstWarningAction = getValidationIssueAction(nonVoiceWarnings[0]);
    steps.push({
      tone: "soft",
      title: "顺手处理补充提醒",
      statusLabel: `还有 ${nonVoiceWarnings.length} 项补充提醒`,
      description: "这些不一定会卡死项目，但修完以后最终试玩手感和导出稳定度通常会更好。",
      actions: [
        {
          label: "只看补充提醒",
          action: "set-preview-issue-filter",
          dataset: { "preview-issue-filter": "warnings" },
        },
        firstWarningAction
          ? { ...firstWarningAction, label: "打开第一条提醒" }
          : { label: "去巡检结果里看", action: "switch-screen", screen: "inspection" },
      ],
    });
  }

  if (unusedAssets.length > 0) {
    steps.push({
      tone: "soft",
      title: "清一轮闲置素材",
      statusLabel: `当前有 ${unusedAssets.length} 个闲置素材`,
      description: "这一步不会阻塞发布，但清掉无用条目后，工程会更干净，后面找素材也轻很多。",
      actions: [
        { label: "去素材页定位", action: "focus-unused-assets" },
        {
          label: "只看闲置素材",
          action: "set-preview-issue-filter",
          dataset: { "preview-issue-filter": "unused_assets" },
        },
      ],
    });
  }

  const desktopReady =
    ["windows_nwjs", "macos_nwjs", "linux_nwjs"].includes(exportResult?.target) &&
    exportResult.runtimeMode === "nwjs" &&
    (exportResult.missingAssets ?? 0) === 0;

  steps.push({
    tone: desktopReady ? "good" : "warn",
    title: desktopReady ? "最后导出正式桌面包确认" : "再导一版正式桌面包",
    statusLabel: desktopReady ? "最近一版已经接近正式交付" : "用最新内容再验证一次桌面包",
    description: desktopReady
      ? "最后再导一次桌面包，确认发布版本、启动画面、图标和素材缺口都没有回退。"
      : "前面的修复做完后，最后一定要重新导一版原生桌面包，确认真壳、图标和素材都跟上了。",
    actions: [
      {
        label: "导出 Windows 桌面包",
        action: "export-build",
        dataset: { "export-target": "windows_nwjs" },
      },
      {
        label: "导出 macOS 桌面包",
        action: "export-build",
        dataset: { "export-target": "macos_nwjs" },
      },
      {
        label: "导出 Linux 桌面包",
        action: "export-build",
        dataset: { "export-target": "linux_nwjs" },
      },
      { label: "去预览导出页", action: "switch-screen", screen: "preview" },
    ],
  });

  return {
    steps,
    blockerCount: steps.filter((step) => step.tone === "danger").length,
    urgentCount: steps.filter((step) => step.tone === "warn").length,
  };
}

function renderReleaseFixOrderStep(step, index) {
  return `
    <article class="preview-sprint-card is-${step.tone}">
      <div class="preview-sprint-head">
        <strong>第 ${index + 1} 步 · ${escapeHtml(step.title)}</strong>
        <span class="issue-tag ${getDashboardTaskToneClass(step.tone)}">${escapeHtml(step.statusLabel)}</span>
      </div>
      <p>${escapeHtml(step.description)}</p>
      <div class="preview-sprint-actions">
        ${(step.actions ?? []).map((action, actionIndex) => renderQuickActionButton(action, actionIndex === 0)).join("")}
      </div>
    </article>
  `;
}

function renderReleaseFixOrderPanel(routeOverview) {
  const plan = buildReleaseFixOrder(routeOverview);

  return `
    <article class="detail-card preview-sprint-panel">
      <div class="panel-heading">
        <h2>发布前修复顺序</h2>
        <span class="badge badge-soft">按这个顺序做最省力</span>
      </div>
      <p class="helper-text">这里会把现在最值得先做的修复动作排成一条顺序，尽量避免你东补一点、西补一点，结果最后还得返工。</p>
      <div class="detail-actions">
        <button class="toolbar-button toolbar-button-primary" data-action="generate-release-fix-order">
          一键生成修复顺序
        </button>
        <button class="toolbar-button" data-action="export-release-control-report">
          导出发布总控报告
        </button>
        <button class="toolbar-button" data-action="export-release-control-json">
          导出 JSON 数据
        </button>
        <button class="toolbar-button" data-action="export-inspection-report">
          导出带修复顺序的巡检报告
        </button>
      </div>
      ${
        plan.steps.length > 0
          ? `<div class="preview-sprint-grid">${plan.steps.map((step, index) => renderReleaseFixOrderStep(step, index)).join("")}</div>`
          : renderEmpty("当前没有明显阻塞，已经接近可以直接做最终试玩和正式导出。")
      }
    </article>
  `;
}

function getProjectDoctorAutoRepairCodes(step) {
  if (Array.isArray(step?.repairCodes)) {
    return step.repairCodes
      .map((code) => String(code ?? "").trim())
      .filter(Boolean);
  }

  const primaryText = `${step?.title ?? ""} ${step?.meta ?? ""}`;
  const primaryCodes = inferProjectDoctorAutoRepairCodesFromText(primaryText);
  if (primaryCodes.length) {
    return primaryCodes;
  }
  return inferProjectDoctorAutoRepairCodesFromText(step?.recovery ?? "");
}

function inferProjectDoctorAutoRepairCodesFromText(value) {
  const text = String(value ?? "");
  const codes = [];

  if (text.includes("入口场景")) {
    codes.push("entry_scene");
  }
  if (text.includes("场景顺序") || text.includes("场景排序") || text.includes("sceneOrder")) {
    codes.push("scene_order");
  }
  if (text.includes("章节排序") || text.includes("chapterOrder")) {
    codes.push("chapter_order");
  }

  return [...new Set(codes)];
}

function getProjectDoctorRepairCodeLabel(code) {
  const labels = {
    entry_scene: "入口场景",
    scene_order: "场景排序",
    chapter_order: "章节排序",
  };
  return labels[code] ?? code;
}

function getProjectDoctorRepairReceiptRequestedCodes(receipt = {}) {
  return Array.isArray(receipt?.requestedCodes)
    ? receipt.requestedCodes.map((code) => String(code ?? "").trim()).filter(Boolean)
    : [];
}

function formatProjectDoctorRepairReceiptScope(receipt = {}) {
  const requestedCodes = getProjectDoctorRepairReceiptRequestedCodes(receipt);
  if (!requestedCodes.length) {
    return receipt?.status === "unknown" ? "无可执行范围" : "全部安全项";
  }
  return requestedCodes.map(getProjectDoctorRepairCodeLabel).join(" / ");
}

function formatProjectDoctorRepairCodes(codes = []) {
  const safeCodes = (codes ?? [])
    .map((code) => String(code ?? "").trim())
    .filter(Boolean);
  if (!safeCodes.length) {
    return "需手动处理";
  }
  return `可先预览安全修复：${safeCodes.map(getProjectDoctorRepairCodeLabel).join(" / ")}`;
}

function getProjectDoctorRepairReceiptReportLabels(receipt = {}) {
  const isPreview = receipt?.status === "preview" || Boolean(receipt?.dryRun);
  const isUnknown = receipt?.status === "unknown";
  if (isPreview) {
    return {
      heading: "最近一次安全修复预览",
      timeLabel: "预览时间",
      countLabel: "将修复 / 将跳过",
      compactPrefix: "最近一次安全修复预览",
      repairVerb: "将修复",
      skipVerb: "将跳过",
    };
  }
  if (isUnknown) {
    return {
      heading: "最近一次未识别修复请求",
      timeLabel: "请求时间",
      countLabel: "可修复 / 已跳过",
      compactPrefix: "最近一次未识别修复请求",
      repairVerb: "可修复",
      skipVerb: "已跳过",
    };
  }
  return {
    heading: "最近一次安全修复",
    timeLabel: "修复时间",
    countLabel: "已修复 / 已跳过",
    compactPrefix: "最近一次安全修复",
    repairVerb: "已修复",
    skipVerb: "已跳过",
  };
}

function getProjectDoctorRepairReceiptWriteStatus(receipt = {}) {
  const status = String(receipt?.status ?? "");
  if (status === "preview" || receipt?.dryRun) {
    return {
      status: "preview",
      label: "未写入项目文件",
      detail: "这只是安全修复预览，确认执行前不会改动项目。",
    };
  }
  if (status === "unknown") {
    return {
      status: "unknown",
      label: "未执行",
      detail: "修复码未识别，请重新巡检刷新后再预览。",
    };
  }
  if (status === "repaired") {
    return {
      status: "written",
      label: "已写入项目文件",
      detail: "安全修复已执行，建议重新巡检确认结果。",
    };
  }
  return {
    status: "clean",
    label: "无需写入",
    detail: "项目医生没有发现需要自动写入的低风险结构问题。",
  };
}

function formatProjectDoctorRepairReceiptIdStamp(value) {
  const date = value ? new Date(value) : null;
  if (!date || Number.isNaN(date.getTime())) {
    return "undated";
  }
  return [
    date.getUTCFullYear(),
    String(date.getUTCMonth() + 1).padStart(2, "0"),
    String(date.getUTCDate()).padStart(2, "0"),
    String(date.getUTCHours()).padStart(2, "0"),
    String(date.getUTCMinutes()).padStart(2, "0"),
  ].join("");
}

function getProjectDoctorRepairReceiptId(receipt = {}) {
  const status = sanitizeFileName(receipt?.status || "receipt").toLowerCase() || "receipt";
  const stamp = formatProjectDoctorRepairReceiptIdStamp(receipt?.generatedAt);
  const itemDigest = (items = []) => (Array.isArray(items) ? items : [])
    .map((item) => [
      item?.code,
      item?.title,
      item?.detail,
    ].map((value) => String(value ?? "").trim()).join("~"))
    .join("||");
  const source = [
    status,
    receipt?.dryRun ? "dry-run" : "write",
    receipt?.generatedAt ?? "",
    receipt?.title ?? "",
    getProjectDoctorRepairReceiptRequestedCodes(receipt).join(","),
    receipt?.repairCount ?? 0,
    receipt?.skippedCount ?? 0,
    itemDigest(receipt?.repairs),
    itemDigest(receipt?.skipped),
  ].join("|");
  let hash = 0;
  for (let index = 0; index < source.length; index += 1) {
    hash = (hash * 31 + source.charCodeAt(index)) >>> 0;
  }
  return `doctor-${status}-${stamp}-${hash.toString(36).padStart(6, "0").slice(-6)}`;
}

function normalizeProjectDoctorRepairReceiptId(value) {
  const text = String(value ?? "")
    .replace(/\s+/g, "-")
    .trim();
  if (!text) {
    return "";
  }
  return text
    .replace(/[\\/:*?"<>|]/g, "-")
    .replace(/-+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 96);
}

function getProjectDoctorRepairReceiptDisplayId(receipt = {}) {
  const explicitId = normalizeProjectDoctorRepairReceiptId(receipt?.receiptId);
  return explicitId || getProjectDoctorRepairReceiptId(receipt);
}

function withProjectDoctorRepairReceiptId(receipt = null) {
  if (!receipt) {
    return receipt;
  }
  return {
    ...receipt,
    receiptId: getProjectDoctorRepairReceiptDisplayId(receipt),
  };
}

function compactProjectDoctorRepairReceiptReportText(value, fallback = "", maxLength = 140) {
  const text = String(value ?? "")
    .replace(/\s+/g, " ")
    .trim();
  const safeText = text || fallback;
  if (!safeText || safeText.length <= maxLength) {
    return safeText;
  }
  return `${safeText.slice(0, Math.max(0, maxLength - 1)).trim()}…`;
}

function formatProjectDoctorRepairReceiptReportItem(item = {}, verb = "已处理") {
  const title = compactProjectDoctorRepairReceiptReportText(item?.title, "项目医生记录", 72);
  const detail = compactProjectDoctorRepairReceiptReportText(item?.detail, "", 120);
  return detail ? `${verb}：${title}；${detail}` : `${verb}：${title}`;
}

function buildProjectDoctorRepairReceiptReportItems(receipt = {}, labels = getProjectDoctorRepairReceiptReportLabels(receipt)) {
  const repairs = Array.isArray(receipt?.repairs) ? receipt.repairs : [];
  const skipped = Array.isArray(receipt?.skipped) ? receipt.skipped : [];
  const items = [
    ...repairs.slice(0, 5).map((item) => formatProjectDoctorRepairReceiptReportItem(item, labels.repairVerb)),
    ...skipped.slice(0, 5).map((item) => formatProjectDoctorRepairReceiptReportItem(item, labels.skipVerb)),
  ];

  if (repairs.length > 5) {
    items.push(`${labels.repairVerb}：另有 ${repairs.length - 5} 项没有展开，完整记录在本次项目医生回执里。`);
  }
  if (skipped.length > 5) {
    items.push(`${labels.skipVerb}：另有 ${skipped.length - 5} 项没有展开，完整记录在本次项目医生回执里。`);
  }
  return items;
}

function buildProjectDoctorRepairReceiptReportSummary(receipt = null) {
  if (!receipt) {
    return null;
  }

  const labels = getProjectDoctorRepairReceiptReportLabels(receipt);
  const requestedRepairCodes = getProjectDoctorRepairReceiptRequestedCodes(receipt);
  const writeStatus = getProjectDoctorRepairReceiptWriteStatus(receipt);
  return {
    receiptId: getProjectDoctorRepairReceiptDisplayId(receipt),
    status: String(receipt.status ?? ""),
    dryRun: Boolean(receipt.dryRun),
    generatedAt: String(receipt.generatedAt ?? ""),
    heading: labels.heading,
    timeLabel: labels.timeLabel,
    countLabel: labels.countLabel,
    repairVerb: labels.repairVerb,
    skipVerb: labels.skipVerb,
    title: compactProjectDoctorRepairReceiptReportText(receipt.title, labels.heading, 120),
    repairCount: Number(receipt.repairCount ?? 0) || 0,
    skippedCount: Number(receipt.skippedCount ?? 0) || 0,
    requestedRepairCodes,
    requestedRepairLabels: requestedRepairCodes.map(getProjectDoctorRepairCodeLabel),
    scopeLabel: formatProjectDoctorRepairReceiptScope(receipt),
    writeStatus,
    items: buildProjectDoctorRepairReceiptReportItems(receipt, labels),
  };
}

function buildProjectDoctorRepairReceiptMarkdownContent(receipt = state.projectDoctorRepairReceipt) {
  if (!receipt) {
    return "";
  }

  const labels = getProjectDoctorRepairReceiptReportLabels(receipt);
  const reportSummary = buildProjectDoctorRepairReceiptReportSummary(receipt);
  const repairs = Array.isArray(receipt.repairs) ? receipt.repairs : [];
  const skipped = Array.isArray(receipt.skipped) ? receipt.skipped : [];
  const nextActions = (Array.isArray(receipt.nextActions)
    ? receipt.nextActions
    : buildProjectDoctorRepairNextActions(receipt.status, reportSummary?.requestedRepairCodes ?? [])
  ).filter(Boolean);
  const detailRows = [
    ...repairs.map((item) => [
      labels.repairVerb,
      compactProjectDoctorRepairReceiptReportText(item?.title, "项目医生记录", 96),
      compactProjectDoctorRepairReceiptReportText(item?.detail, "没有更多细节。", 180),
    ]),
    ...skipped.map((item) => [
      labels.skipVerb,
      compactProjectDoctorRepairReceiptReportText(item?.title, "项目医生记录", 96),
      compactProjectDoctorRepairReceiptReportText(item?.detail, "没有更多细节。", 180),
    ]),
  ];
  const summaryTable = buildMarkdownTable(
    ["项目", "内容"],
    [
      ["回执编号", reportSummary?.receiptId ?? getProjectDoctorRepairReceiptDisplayId(receipt)],
      ["回执类型", labels.heading],
      ["标题", reportSummary?.title ?? labels.heading],
      [labels.timeLabel, formatDate(receipt.generatedAt)],
      ["写入状态", `${reportSummary?.writeStatus?.label ?? "未记录"}：${reportSummary?.writeStatus?.detail ?? "没有记录写入状态。"}`],
      ["修复范围", reportSummary?.scopeLabel ?? formatProjectDoctorRepairReceiptScope(receipt)],
      [labels.countLabel, `${reportSummary?.repairCount ?? 0} / ${reportSummary?.skippedCount ?? 0}`],
    ]
  );
  const detailTable = buildMarkdownTable(["类型", "事项", "细节"], detailRows);
  const nextActionLines = nextActions.length
    ? nextActions.map((action, index) => `${index + 1}. ${action.label ?? "继续处理"}`)
    : ["1. 重新巡检并导出发布总控报告。"];

  return [
    `# ${labels.heading}`,
    "",
    `- 回执编号：${reportSummary?.receiptId ?? getProjectDoctorRepairReceiptDisplayId(receipt)}`,
    `- 项目：${state.data?.project?.title ?? "Canvasia Engine Project"}`,
    `- 导出时间：${formatDate(new Date().toISOString())}`,
    "",
    "## 回执摘要",
    "",
    summaryTable,
    "",
    "## 明细",
    "",
    detailTable || "当前没有可展开的处理明细。",
    "",
    "## 后续建议",
    "",
    ...nextActionLines,
    "",
  ].join("\n");
}

function buildProjectDoctorRepairReceiptClipboardSummary(receipt = state.projectDoctorRepairReceipt) {
  if (!receipt) {
    return "";
  }

  const reportSummary = buildProjectDoctorRepairReceiptReportSummary(receipt);
  const nextActions = (Array.isArray(receipt.nextActions)
    ? receipt.nextActions
    : buildProjectDoctorRepairNextActions(receipt.status, reportSummary?.requestedRepairCodes ?? [])
  ).filter(Boolean);
  const itemLines = (reportSummary?.items ?? []).slice(0, 3).map((item) => `- ${item}`);
  const overflowCount = Math.max(0, (reportSummary?.items?.length ?? 0) - itemLines.length);
  if (overflowCount > 0) {
    itemLines.push(`- 另有 ${overflowCount} 条明细，请导出完整回执查看。`);
  }
  const generatedAtText = receipt.generatedAt ? formatDate(receipt.generatedAt) : "未记录";
  const writeStatusLabel = reportSummary?.writeStatus?.label ?? "未记录";
  const writeStatusDetail = reportSummary?.writeStatus?.detail;
  const writeStatusText = writeStatusDetail
    ? `${writeStatusLabel}（${writeStatusDetail}）`
    : writeStatusLabel;

  return [
    `${reportSummary?.heading ?? "项目医生回执"}：${reportSummary?.title ?? "项目医生回执"}`,
    `回执编号：${reportSummary?.receiptId ?? getProjectDoctorRepairReceiptDisplayId(receipt)}`,
    `项目：${state.data?.project?.title ?? "Canvasia Engine Project"}`,
    `${reportSummary?.timeLabel ?? "回执时间"}：${generatedAtText}`,
    `写入状态：${writeStatusText}`,
    `修复范围：${reportSummary?.scopeLabel ?? formatProjectDoctorRepairReceiptScope(receipt)}`,
    `${reportSummary?.countLabel ?? "处理数量"}：${reportSummary?.repairCount ?? 0} / ${reportSummary?.skippedCount ?? 0}`,
    ...itemLines,
    nextActions[0]?.label ? `下一步：${nextActions[0].label}` : "",
  ]
    .filter(Boolean)
    .join("\n");
}

function exportProjectDoctorRepairReceipt() {
  if (!state.projectDoctorRepairReceipt) {
    showToast("还没有项目医生回执可导出，请先预览或执行安全修复。", "error");
    setSaveStatus("暂无项目医生回执可导出", true);
    return false;
  }

  const fileName = buildProjectDoctorRepairReceiptFileName(state.projectDoctorRepairReceipt);
  downloadTextFile(
    fileName,
    buildProjectDoctorRepairReceiptMarkdownContent(state.projectDoctorRepairReceipt),
    "text/markdown;charset=utf-8"
  );
  setSaveStatus(`已导出项目医生回执：${fileName}`);
  showToast("项目医生回执已导出");
  return true;
}

async function copyProjectDoctorRepairReceiptSummary() {
  if (!state.projectDoctorRepairReceipt) {
    showToast("还没有项目医生回执可复制，请先预览或执行安全修复。", "error");
    setSaveStatus("暂无项目医生回执可复制", true);
    return false;
  }

  const receiptId = getProjectDoctorRepairReceiptDisplayId(state.projectDoctorRepairReceipt);
  const copied = await copyTextToClipboard(
    buildProjectDoctorRepairReceiptClipboardSummary(state.projectDoctorRepairReceipt)
  );
  if (!copied) {
    showToast("复制失败，可以改用“导出这次回执”保存文件。", "error");
    setSaveStatus("项目医生回执复制失败", true);
    return false;
  }

  setSaveStatus(`已复制项目医生回执摘要：${receiptId}`);
  showToast("项目医生回执摘要已复制");
  return true;
}

function buildProjectDoctorRepairNextActions(status = "clean", repairCodes = []) {
  if (projectDoctorTools?.buildProjectDoctorRepairNextActions) {
    return projectDoctorTools.buildProjectDoctorRepairNextActions(status, repairCodes);
  }

  const repaired = status === "repaired";
  const preview = status === "preview";
  const unknown = status === "unknown";
  const repairCodeText = Array.isArray(repairCodes) ? repairCodes.filter(Boolean).join(",") : "";
  if (preview) {
    return [
      {
        label: "确认执行安全修复",
        action: "repair-project-doctor",
        dataset: repairCodeText ? { "repair-codes": repairCodeText } : {},
      },
      { label: "重新巡检确认", action: "run-project-inspection" },
      { label: "导出巡检报告", action: "export-inspection-report" },
    ];
  }
  if (unknown) {
    return [
      { label: "重新巡检刷新修复码", action: "run-project-inspection" },
      { label: "重新预览安全修复", action: "preview-project-doctor-repair" },
      { label: "导出巡检报告", action: "export-inspection-report" },
    ];
  }
  return [
    { label: "重新巡检确认", action: "run-project-inspection" },
    repaired
      ? { label: "跑自动回归确认", action: "run-preview-regression" }
      : { label: "去预览导出", action: "switch-screen", screen: "preview" },
    { label: "导出巡检报告", action: "export-inspection-report" },
  ];
}

function buildProjectDoctorRepairReceipt(result) {
  if (projectDoctorTools?.buildProjectDoctorRepairReceipt) {
    return withProjectDoctorRepairReceiptId(projectDoctorTools.buildProjectDoctorRepairReceipt(result));
  }

  const repairs = Array.isArray(result?.repairs) ? result.repairs : [];
  const dryRun = Boolean(result?.dryRun);
  const changed = Boolean(result?.changed);
  const wouldChange = Boolean(result?.wouldChange) || repairs.length > 0;
  const requestedCodes = Array.isArray(result?.requestedCodes) ? result.requestedCodes.filter(Boolean) : [];
  const ignoredCodes = Array.isArray(result?.ignoredCodes) ? result.ignoredCodes.filter(Boolean) : [];
  const skipped = [
    ...(Array.isArray(result?.skipped) ? result.skipped : []),
    ...ignoredCodes.map((code) => ({
      code: `ignored_${code}`,
      title: `未识别修复码：${code}`,
      detail: "这个修复码不属于当前安全修复范围，可能来自过期按钮或手动输入；请重新巡检后再点项目医生按钮。",
    })),
  ];
  const status = ignoredCodes.length && !wouldChange && !changed
    ? "unknown"
    : dryRun && wouldChange ? "preview" : changed ? "repaired" : "clean";
  const ignoredNote = ignoredCodes.length ? `；另有 ${ignoredCodes.length} 个未识别修复码已列在跳过区` : "";
  return withProjectDoctorRepairReceiptId({
    generatedAt: result?.savedAt ?? new Date().toISOString(),
    status,
    badge: status === "unknown" ? "未识别" : status === "preview" ? "预览未写入" : changed ? "已自动修复" : "无需自动修复",
    title:
      status === "preview"
        ? `项目医生预览到 ${repairs.length} 项可安全修复`
        : status === "unknown"
        ? `项目医生未识别 ${ignoredCodes.length} 个修复码`
        : changed
        ? `项目医生完成 ${repairs.length} 项安全修复`
        : "项目医生没有发现可自动修复的低风险结构问题",
    description:
      status === "preview"
        ? `这只是预览，不会写入项目文件；确认列表无误后再执行安全修复${ignoredNote}。`
        : status === "unknown"
        ? `这些修复码不属于当前安全修复范围：${ignoredCodes.join(" / ")}。请重新巡检后再点项目医生按钮。`
        : changed
        ? `修复已写入项目并进入自动快照链${ignoredNote}。`
        : `入口、章节顺序和场景顺序当前无需自动处理${ignoredNote}。`,
    repairCount: repairs.length,
    skippedCount: skipped.length,
    dryRun,
    wouldChange,
    requestedCodes,
    ignoredCodes,
    repairs,
    skipped,
    nextActions: buildProjectDoctorRepairNextActions(status, requestedCodes),
  });
}

function withProjectDoctorRepairActions(queue) {
  const previewedRepairCodes = new Set(getCurrentProjectDoctorPreviewRepairCodes());

  return queue.map((step) => {
    const repairCodes = getProjectDoctorAutoRepairCodes(step);
    if (!repairCodes.length) {
      return step;
    }
    const canConfirmStepRepair = repairCodes.every((code) => previewedRepairCodes.has(code));

    return {
      ...step,
      actions: [
        {
          label: "先预览这项修复",
          action: "preview-project-doctor-repair",
          dataset: { "repair-codes": repairCodes.join(",") },
        },
        {
          label: canConfirmStepRepair ? "确认执行这项修复" : "预览后可执行这项",
          action: "repair-project-doctor",
          disabled: !canConfirmStepRepair,
          title: canConfirmStepRepair ? "" : "先点“先预览这项修复”，确认预览结果后再执行",
          dataset: { "repair-codes": repairCodes.join(",") },
        },
        ...(step.actions ?? []),
      ],
    };
  });
}

function buildProjectDoctorQueue(routeOverview, issueItems) {
  if (projectDoctorTools?.buildProjectDoctorQueue) {
    return withProjectDoctorRepairActions(
      projectDoctorTools.buildProjectDoctorQueue({
        issueItems,
        routeOverview,
        regressionResult: state.inspectionRegressionResult,
        limit: isAdvancedEditorMode() ? 10 : 6,
      })
    );
  }

  return withProjectDoctorRepairActions(
    issueItems.slice(0, 6).map((item, index) => ({
      id: `${item.kind}-${index}`,
      order: index + 1,
      kind: item.kind,
      label: item.label,
      badge: index === 0 ? "先处理" : "排队",
      tone: item.kind === "errors" ? "danger" : item.kind === "unused_assets" ? "soft" : "warn",
      title: item.title,
      meta: item.meta,
      why: "它会影响试玩、导出或后续排查效率。",
      recovery: item.recovery ?? "点开对应位置，按提示补内容、补引用或调整设置。",
      actions: [item.action].filter(Boolean),
    }))
  );
}

function buildProjectDoctorSummary(queue) {
  if (projectDoctorTools?.buildProjectDoctorSummary) {
    return projectDoctorTools.buildProjectDoctorSummary(queue);
  }

  const dangerCount = queue.filter((step) => step.tone === "danger").length;
  const warnCount = queue.filter((step) => step.tone === "warn").length;
  return {
    status: dangerCount > 0 ? "danger" : warnCount > 0 ? "warn" : queue.length ? "soft" : "clean",
    badge: dangerCount > 0 ? "先修硬阻塞" : warnCount > 0 ? "可边做边修" : queue.length ? "整理收尾" : "很干净",
    title: queue.length ? `项目医生排出了 ${queue.length} 个优先步骤` : "项目医生没有发现需要优先处理的事项",
    description: queue.length
      ? "按这个顺序处理，通常比从长长的问题列表里随机点更省时间。"
      : "当前可以继续试玩、补内容或导出一版做最终确认。",
    dangerCount,
    warnCount,
    softCount: queue.filter((step) => step.tone === "soft").length,
    autoRepairableCount: queue.filter((step) => getProjectDoctorAutoRepairCodes(step).length > 0).length,
    autoRepairLabel: queue.some((step) => getProjectDoctorAutoRepairCodes(step).length > 0)
      ? `可先预览安全修复 ${queue.filter((step) => getProjectDoctorAutoRepairCodes(step).length > 0).length} 项`
      : "暂无可预览修复项",
    nextStepTitle: queue[0]?.title ?? "",
  };
}

function renderProjectDoctorStepCard(step) {
  const toneClass = getDashboardTaskToneClass(step.tone);
  const actions = (step.actions ?? []).filter(Boolean).slice(0, 3);

  return `
    <article class="preview-sprint-card project-doctor-step is-${escapeHtml(step.tone ?? "soft")}">
      <div class="preview-sprint-head">
        <strong>第 ${Number(step.order ?? 0)} 步 · ${escapeHtml(step.title)}</strong>
        <span class="issue-tag ${toneClass}">${escapeHtml(step.badge ?? step.label ?? "处理")}</span>
      </div>
      <div class="detail-meta">${escapeHtml(`${step.label ?? "待处理"} · ${step.meta ?? "未标注位置"}`)}</div>
      <p>${escapeHtml(step.why ?? "这一步会影响试玩、导出或后续排查效率。")}</p>
      <div class="project-doctor-recovery">
        <strong>建议怎么修</strong>
        <span>${escapeHtml(step.recovery ?? "点开对应位置，按提示补内容、补引用或调整设置。")}</span>
      </div>
      <div class="project-doctor-done">
        <strong>修完应该看到</strong>
        <span>${escapeHtml(step.doneWhen ?? "重新巡检后，这条问题会消失或变成可确认的提醒。")}</span>
      </div>
      <div class="preview-sprint-actions">
        ${actions.map((action, index) => renderQuickActionButton(action, index === 0)).join("")}
      </div>
    </article>
  `;
}

function renderProjectDoctorReceiptList(items = [], emptyText = "没有记录") {
  if (!items.length) {
    return `<div class="empty-note">${escapeHtml(emptyText)}</div>`;
  }

  return `
    <div class="project-doctor-receipt-list">
      ${items
        .map(
          (item) => `
            <article class="project-doctor-receipt-item">
              <strong>${escapeHtml(item.title ?? "项目医生记录")}</strong>
              <span>${escapeHtml(item.detail ?? "没有更多细节。")}</span>
            </article>
          `
        )
        .join("")}
    </div>
  `;
}

function renderProjectDoctorRepairReceiptPanel(receipt = state.projectDoctorRepairReceipt) {
  if (!receipt) {
    return "";
  }

  const isPreview = receipt.status === "preview";
  const isUnknown = receipt.status === "unknown";
  const receiptLabels = getProjectDoctorRepairReceiptReportLabels(receipt);
  const writeStatus = getProjectDoctorRepairReceiptWriteStatus(receipt);
  const tone = receipt.status === "repaired" ? "good" : isPreview || isUnknown ? "warn" : "soft";
  const scopeLabel = formatProjectDoctorRepairReceiptScope(receipt);
  const scopeHint = isUnknown
    ? "请重新巡检刷新修复码"
    : isPreview
    ? "确认按钮只执行这个范围"
    : "本次自动修复范围";
  const nextActions = (Array.isArray(receipt.nextActions)
    ? receipt.nextActions
    : buildProjectDoctorRepairNextActions(receipt.status, getProjectDoctorRepairReceiptRequestedCodes(receipt))
  )
    .filter(Boolean)
    .slice(0, 3);
  return `
    <article class="preview-sprint-card project-doctor-receipt is-${tone}">
      <div class="preview-sprint-head">
        <strong>${escapeHtml(receipt.title)}</strong>
        <span class="issue-tag ${receipt.status === "repaired" ? "good-text" : ""}">${escapeHtml(receipt.badge)}</span>
      </div>
      <p>${escapeHtml(receipt.description)}</p>
      <div class="preview-sprint-metrics">
        ${renderRouteMetricCard(receiptLabels.repairVerb, `${receipt.repairCount ?? 0} 项`, "低风险结构项")}
        ${renderRouteMetricCard(receiptLabels.skipVerb, `${receipt.skippedCount ?? 0} 项`, isUnknown ? "未执行的请求" : "当前无需处理")}
        ${renderRouteMetricCard(receiptLabels.timeLabel, formatDate(receipt.generatedAt), "本次会话记录")}
        ${renderRouteMetricCard("写入状态", writeStatus.label, writeStatus.detail)}
        ${renderRouteMetricCard("修复范围", scopeLabel, scopeHint)}
        ${renderRouteMetricCard("回执编号", getProjectDoctorRepairReceiptDisplayId(receipt), "发给测试人员时可用来对齐记录")}
      </div>
      <div class="preview-sprint-actions project-doctor-receipt-actions">
        ${nextActions.map((action, index) => renderQuickActionButton(action, index === 0)).join("")}
        <button class="toolbar-button" data-action="copy-project-doctor-receipt-summary">
          复制回执摘要
        </button>
        <button class="toolbar-button" data-action="export-project-doctor-receipt">
          导出这次回执
        </button>
      </div>
      <div class="project-doctor-receipt-columns">
        <div>
          <strong class="project-doctor-receipt-heading">${isPreview ? "预览会处理" : isUnknown ? "可自动处理" : "已自动处理"}</strong>
          ${renderProjectDoctorReceiptList(receipt.repairs ?? [], isPreview ? "预览里没有发现可自动修复项。" : isUnknown ? "这次请求里没有可执行的安全修复项。" : "这次没有写入新的自动修复。")}
        </div>
        <div>
          <strong class="project-doctor-receipt-heading">${isPreview ? "预览会跳过" : isUnknown ? "未识别 / 已跳过" : "无需处理 / 已跳过"}</strong>
          ${renderProjectDoctorReceiptList(receipt.skipped ?? [], isPreview ? "预览里没有需要跳过的项目。" : isUnknown ? "这次没有可列出的未识别修复码。" : "这次没有跳过项。")}
        </div>
      </div>
    </article>
  `;
}

function parseProjectDoctorRepairCodes(value) {
  return String(value ?? "")
    .split(",")
    .map((item) => item.trim())
    .filter(Boolean);
}

function getCurrentProjectDoctorPreviewRepairCodes() {
  const receipt = state.projectDoctorRepairReceipt;
  if (receipt?.status !== "preview" || !receipt?.wouldChange || !Array.isArray(receipt.requestedCodes)) {
    return [];
  }
  return receipt.requestedCodes.map((code) => String(code ?? "").trim()).filter(Boolean);
}

async function repairProjectDoctor(repairCodesValue = "", options = {}) {
  if (!state.data) {
    showToast("先打开一个项目，再使用项目医生修复");
    return;
  }

  const repairCodes = parseProjectDoctorRepairCodes(repairCodesValue);
  const dryRun = Boolean(options.dryRun);
  let confirmedRepairCodes = repairCodes;
  if (!dryRun) {
    const previewRepairCodes = getCurrentProjectDoctorPreviewRepairCodes();
    const previewRepairCodeSet = new Set(previewRepairCodes);
    confirmedRepairCodes = repairCodes.length ? repairCodes : previewRepairCodes;
    const matchesPreview = confirmedRepairCodes.length > 0
      && confirmedRepairCodes.every((code) => previewRepairCodeSet.has(code));
    if (!matchesPreview) {
      const message = previewRepairCodes.length
        ? "项目医生预览已变化，请先重新预览安全修复"
        : "请先点“先预览安全修复”，确认后再执行";
      setSaveStatus(message, true);
      showToast(message, "error");
      return;
    }
  }
  const payload = {
    ...(confirmedRepairCodes.length > 0 ? { repairCodes: confirmedRepairCodes } : {}),
    ...(dryRun ? { dryRun: true } : {}),
  };

  try {
    setSaveStatus(dryRun ? "项目医生正在预览安全修复..." : "项目医生正在安全修复...");
    const result = await postJson(API_REPAIR_PROJECT_DOCTOR, payload);
    if (!dryRun) {
      state.lastExportResult = null;
    }
    state.projectDoctorRepairReceipt = buildProjectDoctorRepairReceipt(result);
    if (!dryRun) {
      await reloadProjectData({ ...getCurrentUiState(), preserveProjectDoctorRepairReceipt: true });
    }

    if (state.currentScreen === "inspection") {
      renderInspectionScreen();
    }
    if (state.currentScreen === "preview") {
      renderPreviewScreen();
    }
    if (state.currentScreen === "dashboard") {
      renderDashboard();
    }

    const repairCount = Array.isArray(result.repairs) ? result.repairs.length : 0;
    const ignoredCount = Array.isArray(result.ignoredCodes) ? result.ignoredCodes.length : 0;
    const ignoredSuffix = ignoredCount > 0 ? `，另有 ${ignoredCount} 个未识别修复码` : "";
    const message = dryRun
      ? repairCount > 0
        ? `项目医生预览到 ${repairCount} 项可安全修复，尚未写入${ignoredSuffix}`
        : ignoredCount > 0
        ? `项目医生发现 ${ignoredCount} 个未识别修复码，请重新巡检`
        : "项目医生预览过了，暂无可自动修复的低风险结构问题"
      : repairCount > 0
        ? `项目医生已完成 ${repairCount} 项安全修复${ignoredSuffix}`
        : ignoredCount > 0
        ? `项目医生发现 ${ignoredCount} 个未识别修复码，请重新巡检`
        : "项目医生检查过了，暂无可自动修复的低风险结构问题";
    setSaveStatus(message);
    showToast(message, "soft");
  } catch (error) {
    const actionLabel = dryRun ? "项目医生预览" : "项目医生安全修复";
    await showEditorOperationFailure(error, `${actionLabel}失败`, `${actionLabel}没有执行成功`);
  }
}

function renderProjectDoctorPanel(routeOverview, issueItems) {
  const queue = buildProjectDoctorQueue(routeOverview, issueItems);
  const summary = buildProjectDoctorSummary(queue);
  const summaryTone = summary.status === "danger" ? "danger" : summary.status === "warn" ? "warn" : "soft";
  const previewRepairCodes = getCurrentProjectDoctorPreviewRepairCodes();
  const previewRepairDataset = previewRepairCodes.length
    ? ` data-repair-codes="${escapeHtml(previewRepairCodes.join(","))}"`
    : "";
  const confirmRepairDisabled = previewRepairCodes.length
    ? ""
    : ` disabled aria-disabled="true" title="${escapeHtml("先点“先预览安全修复”，确认预览结果后再执行")}"`;
  const confirmRepairLabel = previewRepairCodes.length ? "确认并执行预览的修复" : "预览后可执行修复";

  return `
    <article class="detail-card preview-sprint-panel project-doctor-panel">
      <div class="panel-heading">
        <h2>项目医生 / 小白修复向导</h2>
        <span class="badge badge-soft">把巡检结果变成可执行步骤</span>
      </div>
      <article class="preview-sprint-card is-${summaryTone}">
        <div class="preview-sprint-head">
          <strong>${escapeHtml(summary.title)}</strong>
          <span class="issue-tag ${getDashboardTaskToneClass(summaryTone)}">${escapeHtml(summary.badge)}</span>
        </div>
        <p>${escapeHtml(summary.description)}</p>
        <div class="preview-sprint-metrics">
          ${renderRouteMetricCard("硬阻塞", `${summary.dangerCount ?? 0} 个`, "优先清掉")}
          ${renderRouteMetricCard("建议复看", `${summary.warnCount ?? 0} 个`, "发布前处理")}
          ${renderRouteMetricCard("整理项", `${summary.softCount ?? 0} 个`, "收尾时清理")}
          ${renderRouteMetricCard("可安全修复", `${summary.autoRepairableCount ?? 0} 项`, "先预览再确认")}
        </div>
      </article>
      <div class="detail-actions">
        <button class="toolbar-button toolbar-button-primary" data-action="preview-project-doctor-repair">
          先预览安全修复
        </button>
        <button class="toolbar-button" data-action="repair-project-doctor"${previewRepairDataset}${confirmRepairDisabled}>
          ${escapeHtml(confirmRepairLabel)}
        </button>
        <button class="toolbar-button toolbar-button-primary" data-action="run-project-inspection">
          重新巡检并刷新队列
        </button>
        <button class="toolbar-button" data-action="run-preview-regression">
          跑自动回归后再排序
        </button>
        <button class="toolbar-button" data-action="export-inspection-report">
          导出给测试人员
        </button>
      </div>
      ${renderProjectDoctorRepairReceiptPanel()}
      ${
        queue.length > 0
          ? `<div class="preview-sprint-grid">${queue.map((step) => renderProjectDoctorStepCard(step)).join("")}</div>`
          : renderEmpty("项目医生暂时没有排出修复队列。可以继续写剧情、试玩，或导出一版做最终确认。")
      }
    </article>
  `;
}

