function normalizeAssistantDraftBlockForScene(sceneDraft, draftBlock) {
  if (!draftBlock || typeof draftBlock !== "object") {
    return null;
  }

  const blockType = ["dialogue", "narration", "choice"].includes(draftBlock.type) ? draftBlock.type : "narration";
  const blockId = createBlockId(sceneDraft);
  const block = { ...draftBlock, id: blockId, type: blockType };

  if (blockType === "dialogue") {
    block.speakerId = getSafeCharacterId(block.speakerId ?? state.selectedCharacterId ?? state.data.characters[0]?.id);
    block.expressionId = getSafeExpressionId(block.speakerId, block.expressionId);
    block.text = String(block.text ?? "新台词").trim() || "新台词";
    delete block.speakerName;
    delete block.options;
  } else if (blockType === "choice") {
    const rawOptions = Array.isArray(block.options) ? block.options : [];
    block.options = rawOptions.slice(0, 4).map((option, index) => ({
      id: createChoiceOptionId(blockId, index),
      text: String(option?.text ?? `选项 ${index + 1}`).trim() || `选项 ${index + 1}`,
      gotoSceneId: getSafeSceneId(option?.gotoSceneId ?? sceneDraft.id, sceneDraft.id),
      effects: Array.isArray(option?.effects) ? option.effects : [],
    }));
    if (block.options.length === 0) {
      block.options = createDefaultChoiceOptions(blockId, sceneDraft.id);
    }
  } else {
    block.text = String(block.text ?? "新旁白").trim() || "新旁白";
    delete block.speakerName;
    delete block.speakerId;
    delete block.expressionId;
    delete block.options;
  }

  sceneDraft.blocks.push(block);
  return block;
}

function buildAssistantBlocksForInsertion(scene, draftBlocks) {
  const sceneDraft = cloneScene(scene);
  sceneDraft.blocks = [...(scene.blocks ?? [])];
  return (Array.isArray(draftBlocks) ? draftBlocks : [])
    .map((block) => normalizeAssistantDraftBlockForScene(sceneDraft, block))
    .filter(Boolean);
}

async function generateCreativeAssistant() {
  const scene = getSelectedScene();

  if (!scene) {
    showToast("先选中一个场景", "error");
    return;
  }

  state.creativeAssistantPrompt =
    document.getElementById("creativeAssistantPrompt")?.value?.trim() || state.creativeAssistantPrompt;
  state.creativeAssistantOpenAiKey =
    document.getElementById("creativeAssistantOpenAiKey")?.value?.trim() ?? state.creativeAssistantOpenAiKey;
  state.creativeAssistantModel =
    document.getElementById("creativeAssistantModel")?.value?.trim() || state.creativeAssistantModel;
  state.creativeAssistantBaseUrl =
    document.getElementById("creativeAssistantBaseUrl")?.value?.trim() ?? state.creativeAssistantBaseUrl;
  persistCreativeAssistantSettings();
  state.creativeAssistantLoading = true;
  state.creativeAssistantError = "";
  renderStoryScreen();

  try {
    const selectedBlock = getSelectedBlock();
    const result = await postJson(API_CREATIVE_ASSISTANT, {
      provider: getSafeCreativeAssistantProvider(state.creativeAssistantProvider),
      apiKey: state.creativeAssistantOpenAiKey,
      model: getSafeCreativeAssistantModel(state.creativeAssistantModel, state.creativeAssistantProvider),
      baseUrl: getSafeCreativeAssistantBaseUrl(state.creativeAssistantBaseUrl),
      mode: getSafeCreativeAssistantMode(state.creativeAssistantMode),
      prompt: state.creativeAssistantPrompt,
      sceneId: scene.id,
      selectedBlockId: selectedBlock?.id ?? null,
      selectedBlockSummary: selectedBlock ? getBlockSummary(selectedBlock, scene).title : "",
    });
    state.creativeAssistantResult = sanitizeCreativeAssistantGenerationResponse(result);
    if (state.creativeAssistantResult) {
      state.creativeAssistantSelectedBlockIndexes = getDefaultCreativeAssistantBlockSelection(state.creativeAssistantResult);
      rememberCreativeAssistantResult(state.creativeAssistantResult);
    }
    setSaveStatus(state.creativeAssistantResult?.title ?? "智能助手已生成建议");
    showToast(
      state.creativeAssistantResult?.provider?.fallback
        ? "真模型不可用，已回落本地模板"
        : state.creativeAssistantResult?.title ?? "智能助手已生成建议"
    );
  } catch (error) {
    state.creativeAssistantError = getErrorDetailMessage(
      error,
      "智能助手没有生成成功，请检查 API Key、模型、服务地址或网络连接。"
    );
    await showEditorOperationFailure(error, "智能助手生成失败", "智能助手没有生成成功");
  } finally {
    state.creativeAssistantLoading = false;
    renderStoryScreen();
  }
}

async function insertCreativeAssistantBlocks() {
  const scene = getSelectedScene();
  const draftBlocks = getSelectedCreativeAssistantBlocks();

  if (!scene || !draftBlocks.length) {
    showToast("先勾选至少一张助手剧情卡片", "error");
    return;
  }

  const updatedScene = cloneScene(scene);
  const selectedIndex = updatedScene.blocks.findIndex((block) => block.id === state.selectedBlockId);
  const insertIndex = selectedIndex >= 0 ? selectedIndex + 1 : updatedScene.blocks.length;
  const newBlocks = buildAssistantBlocksForInsertion(scene, draftBlocks);

  if (!newBlocks.length) {
    showToast("助手结果里没有可识别的剧情卡片", "error");
    return;
  }

  updatedScene.blocks.splice(insertIndex, 0, ...newBlocks);

  const success = await persistScene(updatedScene, {
    selectedSceneId: updatedScene.id,
    selectedBlockId: newBlocks[0]?.id ?? null,
    previewSceneId: updatedScene.id,
    previewBlockIndex: insertIndex,
    successMessage: `已插入智能助手生成的 ${newBlocks.length} 张卡片`,
  });

  if (success) {
    state.creativeAssistantResult = null;
    state.creativeAssistantSelectedBlockIndexes = null;
    renderStoryScreen();
    showToast(`已插入 ${newBlocks.length} 张助手卡片`);
  }
}

async function copyCreativeAssistantSummary() {
  const result = state.creativeAssistantResult;
  if (!result) {
    return;
  }
  const lines = [
    result.title,
    result.summary,
    ...(result.guidance ?? []).map((item) => `- ${item}`),
    ...(result.assetPrompts ?? []).map((item) => `素材提示：${item}`),
  ].filter(Boolean);
  const copied = await copyTextToClipboard(lines.join("\n"));
  if (copied) {
    showToast("助手建议已复制");
  } else {
    showEngineAlert(lines.join("\n"));
  }
}

async function copyCreativeAssistantBlocks() {
  const result = state.creativeAssistantResult;
  const content = buildCreativeAssistantBlocksText(result);
  if (!content) {
    showToast("当前没有可复制的剧情卡片", "error");
    return;
  }
  const copied = await copyTextToClipboard(content);
  if (copied) {
    showToast("剧情卡片已复制");
  } else {
    showEngineAlert(content);
  }
}

async function addBlock(blockType) {
  const scene = getSelectedScene();
  if (!scene) {
    return;
  }

  const updatedScene = cloneScene(scene);
  const newBlock = createDefaultBlock(updatedScene, blockType);
  const selectedIndex = updatedScene.blocks.findIndex((block) => block.id === state.selectedBlockId);
  const insertIndex = selectedIndex >= 0 ? selectedIndex + 1 : updatedScene.blocks.length;

  updatedScene.blocks.splice(insertIndex, 0, newBlock);

  const success = await persistScene(updatedScene, {
    selectedSceneId: updatedScene.id,
    selectedBlockId: newBlock.id,
    previewSceneId: updatedScene.id,
    previewBlockIndex: insertIndex,
    successMessage: `已新增${BLOCK_LABELS[blockType] ?? blockType}`,
  });

  if (success && state.currentScreen !== "story") {
    switchScreen("story");
  }
}

function getStoryTemplatePreset(templateId) {
  return storyTemplateTools.getStoryTemplatePreset(templateId);
}

function getStoryTemplateBlockRecipes(templateId) {
  return storyTemplateTools.getStoryTemplateBlockRecipes(templateId);
}

function cloneStoryTemplateFields(fields) {
  if (!fields || typeof fields !== "object") {
    return {};
  }

  return JSON.parse(JSON.stringify(fields));
}

function applyStoryTemplateSpeaker(block, speakerId) {
  if (!block || !speakerId) {
    return;
  }

  if (block.type === "dialogue") {
    block.speakerId = speakerId;
    block.expressionId = getSafeExpressionId(speakerId, null);
  }

  if (block.type === "character_show") {
    block.characterId = speakerId;
    block.expressionId = getSafeExpressionId(speakerId, null);
    block.position = getDefaultCharacterPosition(speakerId);
  }

  if (block.type === "character_hide") {
    block.characterId = speakerId;
  }
}

function applyStoryTemplateChoiceTexts(block, choiceTexts) {
  if (!Array.isArray(choiceTexts) || !Array.isArray(block?.options)) {
    return;
  }

  block.options = block.options.map((option, index) => ({
    ...option,
    text: choiceTexts[index] ?? option.text,
  }));
}

function applyStoryTemplateRecipe(block, recipe, context) {
  Object.assign(block, cloneStoryTemplateFields(recipe.fields));

  if (recipe.speaker) {
    applyStoryTemplateSpeaker(block, context.speakerId);
  }

  applyStoryTemplateChoiceTexts(block, recipe.choiceTexts);

  if (recipe.defaultJumpTarget && block.type === "jump") {
    block.targetSceneId = getDefaultJumpTargetSceneId(context.scene?.id);
  }
}

function createTemplateBlock(sceneDraft, recipe, context) {
  if (!recipe?.type) {
    return null;
  }

  const block = createDefaultBlock(sceneDraft, recipe.type);
  applyStoryTemplateRecipe(block, recipe, context);
  sceneDraft.blocks.push(block);
  return block;
}

function buildStoryTemplateBlocks(scene, templateId) {
  const preset = getStoryTemplatePreset(templateId);

  if (!scene || !preset) {
    return [];
  }

  const recipes = getStoryTemplateBlockRecipes(templateId);
  if (!recipes.length) {
    return [];
  }

  const sceneDraft = cloneScene(scene);
  sceneDraft.blocks = [...(scene.blocks ?? [])];
  const blocks = [];
  const speakerId = getSafeCharacterId(state.selectedCharacterId ?? state.data.characters[0]?.id);
  const context = {
    scene,
    speakerId,
  };

  recipes.forEach((recipe) => {
    const block = createTemplateBlock(sceneDraft, recipe, context);
    if (block) {
      blocks.push(block);
    }
  });

  return blocks;
}

async function applyStoryTemplate(templateId) {
  const scene = getSelectedScene();
  const preset = getStoryTemplatePreset(templateId);

  if (!scene || !preset) {
    showEngineAlert("先选中一个场景，再插入剧情模板。");
    return;
  }

  const updatedScene = cloneScene(scene);
  const selectedIndex = updatedScene.blocks.findIndex((block) => block.id === state.selectedBlockId);
  const insertIndex = selectedIndex >= 0 ? selectedIndex + 1 : updatedScene.blocks.length;
  const newBlocks = buildStoryTemplateBlocks(scene, templateId);

  if (newBlocks.length === 0) {
    setSaveStatus("这个模板暂时没有可插入的内容", true);
    return;
  }

  updatedScene.blocks.splice(insertIndex, 0, ...newBlocks);

  const success = await persistScene(updatedScene, {
    selectedSceneId: updatedScene.id,
    selectedBlockId: newBlocks[0]?.id ?? null,
    previewSceneId: updatedScene.id,
    previewBlockIndex: insertIndex,
    successMessage: `已插入模板：${preset.title}`,
  });

  if (success) {
    if (state.currentScreen !== "story") {
      switchScreen("story");
    }
    showToast(`已插入模板：${preset.title}`);
  }
}

async function duplicateSelectedBlock() {
  const scene = getSelectedScene();
  const block = getSelectedBlock();

  if (!scene || !block) {
    return;
  }

  const updatedScene = cloneScene(scene);
  const currentIndex = updatedScene.blocks.findIndex((item) => item.id === block.id);

  if (currentIndex < 0) {
    return;
  }

  const duplicatedBlock = duplicateBlockForScene(updatedScene, updatedScene.blocks[currentIndex]);
  const insertIndex = currentIndex + 1;
  updatedScene.blocks.splice(insertIndex, 0, duplicatedBlock);

  await persistScene(updatedScene, {
    selectedSceneId: updatedScene.id,
    selectedBlockId: duplicatedBlock.id,
    previewSceneId: updatedScene.id,
    previewBlockIndex: insertIndex,
    successMessage: "这张卡片已经复制",
  });
}

async function reorderStoryBlock(scene, blockId, targetBlockId, position = "before") {
  if (!scene) {
    return;
  }

  const updatedScene = cloneScene(scene);
  const originalOrder = updatedScene.blocks.map((block) => block.id).join("|");
  const currentIndex = updatedScene.blocks.findIndex((block) => block.id === blockId);

  if (currentIndex < 0) {
    return;
  }

  const [movedBlock] = updatedScene.blocks.splice(currentIndex, 1);
  const targetIndex = updatedScene.blocks.findIndex((block) => block.id === targetBlockId);

  if (targetIndex < 0) {
    updatedScene.blocks.splice(currentIndex, 0, movedBlock);
    return;
  }

  const insertIndex = position === "after" ? targetIndex + 1 : targetIndex;
  const safeInsertIndex = clamp(insertIndex, 0, updatedScene.blocks.length);
  updatedScene.blocks.splice(safeInsertIndex, 0, movedBlock);

  if (updatedScene.blocks.map((block) => block.id).join("|") === originalOrder) {
    setSaveStatus("卡片顺序没有变化");
    return;
  }

  const success = await persistScene(updatedScene, {
    selectedSceneId: updatedScene.id,
    selectedBlockId: movedBlock.id,
    previewSceneId: updatedScene.id,
    previewBlockIndex: safeInsertIndex,
    successMessage: "卡片顺序已更新",
  });

  if (success) {
    showToast("卡片顺序已更新");
  }
}

async function moveSelectedBlock(direction) {
  const scene = getSelectedScene();
  const block = getSelectedBlock();

  if (!scene || !block) {
    return;
  }

  const updatedScene = cloneScene(scene);
  const currentIndex = updatedScene.blocks.findIndex((item) => item.id === block.id);
  const targetIndex = currentIndex + direction;

  if (currentIndex < 0) {
    return;
  }

  if (targetIndex < 0 || targetIndex >= updatedScene.blocks.length) {
    setSaveStatus(direction < 0 ? "这张卡片已经在最上面了" : "这张卡片已经在最下面了");
    return;
  }

  const [movedBlock] = updatedScene.blocks.splice(currentIndex, 1);
  updatedScene.blocks.splice(targetIndex, 0, movedBlock);

  await persistScene(updatedScene, {
    selectedSceneId: updatedScene.id,
    selectedBlockId: block.id,
    previewSceneId: updatedScene.id,
    previewBlockIndex: targetIndex,
    successMessage: direction < 0 ? "卡片已上移一格" : "卡片已下移一格",
  });
}

async function deleteSelectedBlock() {
  const scene = getSelectedScene();
  const block = getSelectedBlock();

  if (!scene || !block) {
    return;
  }

  const summary = getBlockSummary(block, scene);
  const shouldDelete = await showEngineConfirm({
    title: "删除这张剧情卡片？",
    message: `要删除这张“${summary.title}”卡片吗？删除后会立刻写回项目文件。`,
    tone: "danger",
    confirmLabel: "删除卡片",
    cancelLabel: "保留卡片",
  });

  if (!shouldDelete) {
    return;
  }

  const updatedScene = cloneScene(scene);
  const blockIndex = updatedScene.blocks.findIndex((item) => item.id === block.id);

  if (blockIndex < 0) {
    return;
  }

  updatedScene.blocks.splice(blockIndex, 1);
  const nextSelectedBlock = updatedScene.blocks[Math.min(blockIndex, updatedScene.blocks.length - 1)] ?? null;

  await persistScene(updatedScene, {
    selectedSceneId: updatedScene.id,
    selectedBlockId: nextSelectedBlock?.id ?? null,
    previewSceneId: updatedScene.id,
    previewBlockIndex: Math.max(Math.min(blockIndex, updatedScene.blocks.length - 1), 0),
    successMessage: "这张卡片已经删除",
  });
}

async function createScene() {
  const chapter = getSelectedChapter();

  if (!chapter) {
    showEngineAlert("现在还没有可用章节。先点“新建章节”，再继续建场景。");
    return;
  }

  const defaultName = `新场景 ${Math.max((chapter.sceneOrder?.length ?? 0) + 1, 1)}`;
  const sceneName = await promptForText("请输入新场景的名字。", defaultName);

  if (sceneName === null) {
    return;
  }

  try {
    setSaveStatus("正在新建场景...");
    const selectedScene = getSelectedScene();
    const result = await postJson(API_CREATE_SCENE, {
      chapterId: chapter.chapterId,
      name: sceneName,
      afterSceneId: selectedScene?.chapterId === chapter.chapterId ? selectedScene.id : null,
    });

    await reloadProjectData({
      ...getCurrentUiState(),
      selectedSceneId: result.sceneId,
      selectedBlockId: result.scene?.blocks?.[0]?.id ?? null,
      previewSceneId: result.sceneId,
      previewStartSceneId: result.sceneId,
      previewBlockIndex: 0,
    });

    setSaveStatus(`已新建场景：${sceneName}`);
  } catch (error) {
    await showEditorOperationFailure(error, "新建场景失败", "场景没有创建成功");
  }
}

