async function createChapter(options = {}) {
  if (!state.data) {
    setSaveStatus("先新建或打开一个项目", true);
    return;
  }

  if (state.chapterCreateInFlight) {
    setSaveStatus("正在创建章节，请稍等...");
    showToast("正在创建章节，请稍等...");
    return;
  }

  setChapterCreateInFlight(true);
  const defaultChapterName = options.defaultChapterName ?? `新章节 ${state.data.chapters.length + 1}`;
  const suggestedSceneName = options.defaultSceneName ?? `${defaultChapterName} 开场`;

  try {
    const chapterName = options.skipPrompts
      ? defaultChapterName
      : await promptForText("请输入新章节的名字。", defaultChapterName);

    if (chapterName === null) {
      return;
    }

    const firstSceneName = options.skipPrompts
      ? suggestedSceneName
      : await promptForText("再给这个章节的第一个场景起个名字。", suggestedSceneName);

    if (firstSceneName === null) {
      return;
    }

    setSaveStatus("正在新建章节...");
    const result = await postJson(API_CREATE_CHAPTER, {
      chapterName,
      firstSceneName,
    });

    await reloadProjectData({
      ...getCurrentUiState(),
      selectedSceneId: result.sceneId,
      selectedBlockId: result.scene?.blocks?.[0]?.id ?? null,
      previewSceneId: result.sceneId,
      previewStartSceneId: result.sceneId,
      previewBlockIndex: 0,
    });

    if (options.afterCreateScreen) {
      switchScreen(options.afterCreateScreen);
    }

    setSaveStatus(options.successMessage ?? `已新建章节：${chapterName}`);
    showToast(options.successMessage ?? `已新建章节：${chapterName}`);
  } catch (error) {
    await showEditorOperationFailure(error, "新建章节失败", "章节没有创建成功");
  } finally {
    setChapterCreateInFlight(false);
  }
}

async function createPlayableDemoProject() {
  if (blockProjectCenterOperationIfInFlight()) {
    return;
  }

  const projectMode = getSafeEditorMode(state.projectCenterEditorMode);
  const projectModeLabel = getEditorModeLabel(projectMode);
  const defaults = getBlankProjectStarterDefaults();
  setProjectCreateInFlight(true);
  try {
    const name = await promptForText(
      [
        "给这个可试玩 Demo 起个名字：",
        `系统会以${projectModeLabel}创建项目、补第一章和占位素材，并直接切到试玩页。`,
      ],
      "我的第一个 Demo",
      {
        title: "新建可试玩 Demo",
        confirmLabel: "生成 Demo 项目",
        placeholder: "例如：雨夜校园试玩版",
      }
    );
    if (!name) {
      return;
    }

    setSaveStatus(`正在创建${projectModeLabel}可试玩 Demo...`);
    const projectResult = await postJson(API_CREATE_PROJECT, {
      name,
      editorMode: projectMode,
    });
    state.projectCenter = projectResult.projectCenter ?? (await loadProjectCenter());
    await enterActiveProjectEditor(`已打开${projectModeLabel}Demo 项目：${name}`);

    setSaveStatus("正在创建第一章和第一场景...");
    const chapterResult = await postJson(API_CREATE_CHAPTER, {
      chapterName: defaults.chapterName,
      firstSceneName: defaults.firstSceneName,
    });
    await reloadProjectData({
      ...getCurrentUiState(),
      selectedSceneId: chapterResult.sceneId,
      selectedBlockId: chapterResult.scene?.blocks?.[0]?.id ?? null,
      previewSceneId: chapterResult.sceneId,
      previewStartSceneId: chapterResult.sceneId,
      previewBlockIndex: 0,
    });

    await createStarterKit({
      skipPrompts: true,
      rethrowErrors: true,
    });
    switchScreen("preview");
    const successMessage = `可试玩 Demo 已生成：${name}`;
    setSaveStatus(successMessage);
    showToast(successMessage);
  } catch (error) {
    if (!handleProjectLoadFailure(error)) {
      await showProjectCenterFailure(error, "新建可试玩 Demo 失败", "可试玩 Demo 没有创建成功");
    }
  } finally {
    setProjectCreateInFlight(false);
  }
}

async function createStarterKit(options = {}) {
  const overview = getStarterKitOverview();
  if (!overview.needsStarterKit) {
    showToast("这套起步骨架已经齐了，可以直接继续写。");
    setSaveStatus("起步骨架已经齐了");
    return;
  }

  const defaults = getStarterKitDefaults();
  const payload = {
    characterName: defaults.characterName,
    backgroundName: defaults.backgroundName,
    bgmName: defaults.bgmName,
  };

  if (!options.skipPrompts) {
    if (overview.missingCharacter) {
      payload.characterName = await promptForText("给第一个角色起个名字。", defaults.characterName);
      if (payload.characterName === null) {
        return;
      }
    }

    if (overview.missingBackground) {
      payload.backgroundName = await promptForText("给第一张背景起个名字。", defaults.backgroundName);
      if (payload.backgroundName === null) {
        return;
      }
    }

    if (overview.missingBgm) {
      payload.bgmName = await promptForText("给第一首 BGM 起个名字。", defaults.bgmName);
      if (payload.bgmName === null) {
        return;
      }
    }
  }

  try {
    setSaveStatus("正在生成起步骨架...");
    const result = await postJson(API_CREATE_STARTER_KIT, payload);
    const bootstrap = result.sceneBootstrap ?? {};
    const insertedBlockIds = Array.isArray(bootstrap.insertedBlockIds) ? bootstrap.insertedBlockIds : [];
    await reloadProjectData({
      ...getCurrentUiState(),
      selectedSceneId: bootstrap.sceneId ?? state.selectedSceneId,
      selectedBlockId: insertedBlockIds[0] ?? state.selectedBlockId,
      previewSceneId: bootstrap.sceneId ?? state.previewSceneId,
      previewStartSceneId: bootstrap.sceneId ?? state.previewStartSceneId,
      previewBlockIndex: 0,
      selectedCharacterId: result.createdCharacter?.id ?? state.selectedCharacterId,
    });
    const createdLabels = Array.isArray(result.createdLabels) ? result.createdLabels : [];
    const insertedLabels = Array.isArray(bootstrap.insertedLabels) ? bootstrap.insertedLabels : [];
    const createdAssets = Array.isArray(result.createdAssets) ? result.createdAssets : [];
    const readyPlaceholderAssets = createdAssets.filter(
      (asset) =>
        asset?.fileExists &&
        Array.isArray(asset.tags) &&
        asset.tags.includes("占位素材")
    );
    const sceneLabel = bootstrap.sceneName || bootstrap.sceneId || "首场景";
    const message =
      createdLabels.length > 0 ? `已补好：${createdLabels.join("、")}` : "起步骨架已经补好了";
    const assetMessage =
      readyPlaceholderAssets.length > 0
        ? `，${readyPlaceholderAssets.length} 个可替换占位素材已生成，可直接试玩和导出`
        : "";
    const bootstrapMessage =
      bootstrap.applied && insertedLabels.length > 0
        ? `${message}${assetMessage}，并已接入${sceneLabel}：${insertedLabels.join("、")}`
        : `${message}${assetMessage}`;
    setSaveStatus(bootstrapMessage);
    showToast(bootstrapMessage);
  } catch (error) {
    if (options.rethrowErrors) {
      throw error;
    }
    await showEditorOperationFailure(error, "生成起步骨架失败", "起步骨架没有生成成功");
  }
}

async function createHistoryCheckpoint() {
  if (!state.data) {
    return;
  }

  if (state.currentScreen === "story") {
    const flushed = await flushPendingStoryChanges();
    if (!flushed) {
      return;
    }
  }

  const label = await promptForText("给这份检查点写一句备注：", "手动检查点");
  if (label === null) {
    return;
  }

  try {
    setSaveStatus("正在保存检查点...");
    const result = await postJson(API_CREATE_PROJECT_HISTORY_SNAPSHOT, { label });
    state.projectHistory = result.history ?? state.projectHistory;
    updateTopbar();
    updateErrorRecoveryState();
    if (state.currentScreen === "dashboard") {
      rerenderProjectHistoryPanel();
    }
    const currentLabel = getSafeProjectHistory(result.history).currentSnapshot?.label ?? label;
    setSaveStatus(`已存检查点：${currentLabel}`);
    showToast(`已存检查点：${currentLabel}`);
  } catch (error) {
    if (error?.recovery) {
      showFatalProjectLoadError(error);
      showToast("保存检查点时项目读取失败，但恢复入口还在", "error");
      return;
    }

    await showEditorOperationFailure(error, "保存检查点失败", "检查点没有保存成功");
  }
}

