async function acknowledgeProjectRecoveryNotice() {
  if (!state.data) {
    return;
  }

  try {
    setSaveStatus("正在记录这个提醒...");
    const result = await postJson(API_ACKNOWLEDGE_PROJECT_RECOVERY_NOTICE, {});
    state.projectSessionRecovery = result.sessionRecovery ?? state.projectSessionRecovery;
    if (state.currentScreen === "dashboard") {
      rerenderProjectHistoryPanel();
    }
    setSaveStatus("已记录当前操作");
    showToast("已收起异常退出提醒");
  } catch (error) {
    await showEditorOperationFailure(error, "收起异常提醒失败", "异常退出提醒没有收起成功");
  }
}

async function applyProjectHistoryAction(mode = "undo", options = {}) {
  const isRedo = mode === "redo";
  const isRestoreTarget = mode === "restore-target";
  const isRestoreWithIndex = mode === "restore" && Number.isFinite(Number(options.targetIndex));
  const actionLabel = isRedo
    ? "重做"
    : mode === "restore"
      ? "恢复上个版本"
      : isRestoreTarget
        ? "恢复指定版本"
        : "撤销";
  const apiUrl = isRedo
    ? API_REDO_PROJECT_HISTORY
    : isRestoreTarget || isRestoreWithIndex
      ? API_RESTORE_PROJECT_HISTORY
      : API_UNDO_PROJECT_HISTORY;
  const payload = isRestoreTarget
    ? {
        targetIndex: Number(options.targetIndex),
      }
    : mode === "restore"
      ? {
          targetIndex: Number(options.targetIndex),
        }
    : {};

  try {
    if (state.data && state.currentScreen === "story") {
      const flushed = await flushPendingStoryChanges();
      if (!flushed) {
        return;
      }
    }

    setSaveStatus(`正在${actionLabel}...`);
    const result = await postJson(apiUrl, payload);

    if (state.data) {
      await reloadProjectData({
        ...getCurrentUiState(),
      });
      showEditorShell();
    } else {
      await enterActiveProjectEditor(`${actionLabel}完成`);
    }

    const history = getSafeProjectHistory(result.history ?? state.projectHistory);
    const currentLabel = history.currentSnapshot?.label ?? "当前版本";
    const message =
      mode === "restore" || isRestoreTarget ? `已恢复到：${currentLabel}` : `${actionLabel}完成：${currentLabel}`;
    if (options.acknowledgeRecoveryNotice) {
      try {
        const acknowledgeResult = await postJson(API_ACKNOWLEDGE_PROJECT_RECOVERY_NOTICE, {});
        state.projectSessionRecovery = acknowledgeResult.sessionRecovery ?? state.projectSessionRecovery;
        if (state.currentScreen === "dashboard") {
          rerenderProjectHistoryPanel();
        }
      } catch (error) {
        // keep the main history action successful even if reminder ack fails
      }
    }
    setSaveStatus(message);
    showToast(message);
  } catch (error) {
    if (error?.recovery) {
      showFatalProjectLoadError(error);
      showToast(`${actionLabel}后项目仍然载入失败，但还保留了恢复入口`, "error");
      return;
    }

    await showEditorOperationFailure(error, `${actionLabel}失败`, `${actionLabel}没有成功`);
  }
}

