async function generateOpenAiAsset() {
  if (state.openAiAssetLoading) {
    setSaveStatus("AI 素材正在生成，请稍等...");
    showToast("AI 素材正在生成，请稍等...");
    return;
  }

  state.openAiAssetType = getSafeOpenAiAssetGenerationType(
    document.getElementById("openAiAssetType")?.value ?? state.openAiAssetType
  );
  state.openAiAssetPrompt = document.getElementById("openAiAssetPrompt")?.value?.trim() ?? state.openAiAssetPrompt;
  state.openAiAssetName = document.getElementById("openAiAssetName")?.value?.trim() ?? state.openAiAssetName;
  state.openAiAssetApiKey = document.getElementById("openAiAssetApiKey")?.value?.trim() ?? state.openAiAssetApiKey;
  state.openAiAssetModel = document.getElementById("openAiAssetModel")?.value?.trim() || state.openAiAssetModel;
  state.openAiAssetStyleHint =
    document.getElementById("openAiAssetStyleHint")?.value?.trim() ?? state.openAiAssetStyleHint;
  const bindCharacterField = document.getElementById("openAiAssetBindCharacterId");
  state.openAiAssetBindCharacterId =
    state.openAiAssetType === "sprite" && bindCharacterField ? bindCharacterField.value.trim() : "";
  const bindExpressionIdField = document.getElementById("openAiAssetBindExpressionId");
  if (bindExpressionIdField) {
    state.openAiAssetBindExpressionId = bindExpressionIdField.value.trim();
  }
  const bindExpressionNameField = document.getElementById("openAiAssetBindExpressionName");
  if (bindExpressionNameField) {
    state.openAiAssetBindExpressionName = bindExpressionNameField.value.trim();
  }
  const bindDefaultField = document.getElementById("openAiAssetBindAsDefaultSprite");
  if (bindDefaultField) {
    state.openAiAssetBindAsDefaultSprite = Boolean(bindDefaultField.checked);
  }
  state.openAiAssetSize = getSafeOpenAiAssetGenerationOption(
    document.getElementById("openAiAssetSize")?.value ?? state.openAiAssetSize,
    openAiAssetTools?.OPENAI_ASSET_GENERATION_SIZES ?? [],
    "1536x1024"
  );
  state.openAiAssetQuality = getSafeOpenAiAssetGenerationOption(
    document.getElementById("openAiAssetQuality")?.value ?? state.openAiAssetQuality,
    openAiAssetTools?.OPENAI_ASSET_GENERATION_QUALITIES ?? [],
    "medium"
  );
  state.openAiAssetBackground = getSafeOpenAiAssetGenerationOption(
    document.getElementById("openAiAssetBackground")?.value ?? state.openAiAssetBackground,
    openAiAssetTools?.OPENAI_ASSET_GENERATION_BACKGROUNDS ?? [],
    "auto"
  );
  state.openAiAssetOutputFormat = getSafeOpenAiAssetGenerationOption(
    document.getElementById("openAiAssetOutputFormat")?.value ?? state.openAiAssetOutputFormat,
    openAiAssetTools?.OPENAI_ASSET_GENERATION_FORMATS ?? [],
    "png"
  );

  const compatibilityWarning = getOpenAiAssetGenerationCompatibilityWarning();
  if (compatibilityWarning) {
    state.openAiAssetError = "";
    renderAssetsScreen();
    showToast("生图格式和背景不兼容", "error");
    return;
  }

  if (!state.openAiAssetPrompt.trim()) {
    state.openAiAssetError = "请先写一句要生成什么素材。";
    renderAssetsScreen();
    showToast("先写生图提示词", "error");
    return;
  }

  const modelWarning = getOpenAiAssetModelWarning(state.openAiAssetModel);
  if (modelWarning) {
    state.openAiAssetError = modelWarning;
    renderAssetsScreen();
    showToast("生图模型名不合法", "error");
    return;
  }

  const promptLengthWarning = getOpenAiAssetPromptLengthWarning(state.openAiAssetPrompt);
  if (promptLengthWarning) {
    state.openAiAssetError = promptLengthWarning;
    renderAssetsScreen();
    showToast("生图提示词太长", "error");
    return;
  }

  const styleHintLengthWarning = getOpenAiAssetStyleHintLengthWarning(state.openAiAssetStyleHint);
  if (styleHintLengthWarning) {
    state.openAiAssetError = styleHintLengthWarning;
    renderAssetsScreen();
    showToast("生图画风补充太长", "error");
    return;
  }

  if (!state.openAiAssetApiKey.trim()) {
    state.openAiAssetError = "请先填写 OpenAI API Key。Key 不会写入项目文件。";
    renderAssetsScreen();
    showToast("先填写 OpenAI API Key", "error");
    return;
  }

  try {
    state.openAiAssetLoading = true;
    state.openAiAssetError = "";
    state.openAiAssetLastResult = null;
    renderAssetsScreen();
    setSaveStatus(`正在生成${getAssetTypeLabel(state.openAiAssetType)}素材...`);

    const result = await postJson(
      API_GENERATE_OPENAI_ASSET,
      openAiAssetTools?.buildOpenAiAssetGenerationPayload?.(state) ?? {
        assetType: state.openAiAssetType,
        prompt: state.openAiAssetPrompt,
        assetName: state.openAiAssetName,
        apiKey: state.openAiAssetApiKey,
        model: state.openAiAssetModel,
        styleHint: state.openAiAssetStyleHint,
        characterBinding:
          state.openAiAssetType === "sprite" && state.openAiAssetBindCharacterId
            ? {
                characterId: state.openAiAssetBindCharacterId,
                expressionId: state.openAiAssetBindExpressionId,
                expressionName: state.openAiAssetBindExpressionName,
                setAsDefaultSprite: state.openAiAssetBindAsDefaultSprite,
              }
            : null,
        size: state.openAiAssetSize,
        quality: state.openAiAssetQuality,
        background: state.openAiAssetBackground,
        outputFormat: state.openAiAssetOutputFormat,
      }
    );

    state.lastExportResult = null;
    state.openAiAssetLastResult = result;
    state.openAiAssetName = "";
    await reloadProjectData({
      ...getCurrentUiState(),
      selectedAssetType: result.assetType ?? state.openAiAssetType,
      selectedAssetId: result.asset?.id ?? state.selectedAssetId,
      selectedCharacterId: result.characterBinding?.characterId ?? state.selectedCharacterId,
      assetFilterMode: "all",
    });
    state.openAiAssetLastResult = result;
    const binding = result.characterBinding;
    const bindingText = binding
      ? `，并绑定到 ${binding.characterName ?? binding.characterId} / ${binding.expressionName ?? binding.expressionId}`
      : "";
    setSaveStatus(`已生成并导入素材：${result.asset?.name ?? "新素材"}${bindingText}`);
    showToast(binding ? `已生成并绑定角色：${binding.characterName ?? "角色"}` : `已生成：${result.asset?.name ?? "新素材"}`);
  } catch (error) {
    state.openAiAssetError = getErrorDetailMessage(
      error,
      "AI 素材没有生成成功，请检查 API Key、模型、额度、服务地址或网络连接。"
    );
    await showEditorOperationFailure(error, "AI 生成素材失败", "素材没有生成成功");
  } finally {
    state.openAiAssetLoading = false;
    renderAssetsScreen();
  }
}

function forgetOpenAiAssetKey() {
  if (state.openAiAssetLoading) {
    setSaveStatus("AI 素材正在生成，请稍等...");
    showToast("AI 素材正在生成，请稍等...");
    return;
  }
  state.openAiAssetApiKey = "";
  state.openAiAssetError = "";
  renderAssetsScreen();
  setSaveStatus("已清空本次 AI 生图 Key");
  showToast("已清空本次生图 Key");
}

async function importAssets(files, options = {}) {
  if (!files.length) {
    return;
  }

  if (!options.smartImport) {
    const accept = getAssetImportAccept(state.selectedAssetType);
    const rejectedFiles = getRejectedAssetFilesByAccept(files, accept);
    if (rejectedFiles.length > 0) {
      const message = getFileAcceptMismatchMessage(rejectedFiles, {
        expectedLabel: getAssetReplaceFormatLabel({ type: state.selectedAssetType }),
        actionLabel: `导入${getAssetTypeLabel(state.selectedAssetType)}`,
        fallbackHint: "如果这一批文件本来就混着多种素材，请改用“智能导入”。",
      });
      setSaveStatus("导入素材失败：文件格式不匹配", true);
      showToast("文件格式不匹配", "error");
      await showEngineAlert({
        title: "文件格式不匹配",
        message,
        tone: "warning",
      });
      return;
    }
  }

  try {
    const modeLabel = options.smartImport ? "智能导入" : "导入";
    setSaveStatus(`正在${modeLabel} ${files.length} 个素材...`);
    const payloadFiles = await readFilesAsBase64Payloads(files, { actionLabel: modeLabel });
    const result = await postJson(API_IMPORT_ASSETS, {
      assetType: options.smartImport ? "auto" : state.selectedAssetType,
      fallbackAssetType: state.selectedAssetType,
      files: payloadFiles,
    });

    state.lastExportResult = null;
    await reloadProjectData({
      ...getCurrentUiState(),
      selectedAssetType: result.assetType ?? result.assets?.[0]?.type ?? state.selectedAssetType,
      selectedAssetId: result.assets?.[0]?.id ?? state.selectedAssetId,
      assetFilterMode: "all",
    });

    const groupedLabel = formatGroupedAssetCounts(result.groupedCounts);
    const message = groupedLabel
      ? `已导入 ${result.importedCount} 个素材：${groupedLabel}`
      : `已导入 ${result.importedCount} 个素材`;
    setSaveStatus(message);
    showToast(message);
  } catch (error) {
    const detailMessage = getErrorDetailMessage(error);
    setSaveStatus(getErrorSummaryLine(error, "导入素材失败"), true);
    showToast("导入素材失败，已列出问题文件", "error");
    await showEngineAlert({
      title: "导入素材失败",
      message: `这批素材没有导入成功：\n${detailMessage}`,
      tone: "warning",
      copyable: true,
      confirmLabel: "我知道了",
    });
  }
}

async function replaceSelectedAssetFile(file) {
  const asset = getSelectedAsset();
  if (!asset || !file) {
    return;
  }

  const accept = getAssetReplaceAccept(asset);
  if (!isFileAcceptedByAccept(file, accept)) {
    const message = getFileAcceptMismatchMessage([file], {
      expectedLabel: getAssetReplaceFormatLabel(asset),
      actionLabel: `补/替换${getAssetTypeLabel(asset.type)}`,
      fallbackHint: "如果这个文件其实属于别的素材分类，请先切到对应分类上传，或使用“智能导入”。",
    });
    setSaveStatus("替换素材失败：文件格式不匹配", true);
    showToast("文件格式不匹配", "error");
    await showEngineAlert({
      title: "文件格式不匹配",
      message,
      tone: "warning",
    });
    return;
  }

  try {
    setSaveStatus(`正在替换素材文件：${asset.name}`);
    if (state.activeAssetAudioId === asset.id) {
      stopAssetAudioPreview({ rerender: false });
    }

    const shouldAdvanceAfterReplace = shouldAdvanceAssetSelectionAfterReplace(asset);
    const selectedAssetIdAfterReplace = shouldAdvanceAfterReplace
      ? getNextAssetSelectionAfterDelete(asset.id)
      : asset.id;
    const result = await postJson(API_REPLACE_ASSET, {
      assetId: asset.id,
      file: await readFileAsBase64Payload(file),
    });

    state.lastExportResult = null;
    await reloadProjectData({
      ...getCurrentUiState(),
      selectedAssetType: asset.type,
      selectedAssetId: selectedAssetIdAfterReplace,
    });

    const nextAsset = result.asset ?? asset;
    const advanceMessage = shouldAdvanceAfterReplace
      ? selectedAssetIdAfterReplace
        ? "，已跳到下一个待补素材"
        : "，当前筛选下的缺文件素材已经补完"
      : "";
    setSaveStatus(`已替换素材文件：${nextAsset.name}${advanceMessage}`);
    showToast(`已替换素材文件：${nextAsset.name}${advanceMessage}`);
  } catch (error) {
    const detailMessage = getErrorDetailMessage(error);
    setSaveStatus(getErrorSummaryLine(error, "替换素材失败"), true);
    showToast("替换素材失败，已列出原因", "error");
    await showEngineAlert({
      title: "替换素材失败",
      message: `这个素材文件没有替换成功：\n${detailMessage}`,
      tone: "warning",
      copyable: true,
      confirmLabel: "我知道了",
    });
  }
}

function getRejectedAssetFilesByAccept(files, accept) {
  return Array.from(files ?? []).filter((file) => !isFileAcceptedByAccept(file, accept));
}

function isFileAcceptedByAccept(file, accept) {
  const tokens = String(accept || "")
    .split(",")
    .map((token) => token.trim().toLowerCase())
    .filter(Boolean);

  if (!tokens.length) {
    return true;
  }

  const fileName = String(file?.name || "").toLowerCase();
  const fileType = String(file?.type || "").toLowerCase();
  return tokens.some((token) => {
    if (token.endsWith("/*")) {
      return fileType.startsWith(token.slice(0, -1));
    }
    if (token.startsWith(".")) {
      return fileName.endsWith(token);
    }
    return Boolean(fileType) && fileType === token;
  });
}

function getFileAcceptMismatchMessage(files, options = {}) {
  const names = Array.from(files ?? [])
    .slice(0, 6)
    .map((file) => `- ${file?.name || "未命名文件"}`);
  if ((files?.length ?? 0) > 6) {
    names.push(`- 还有 ${(files?.length ?? 0) - 6} 个文件未展开`);
  }

  return [
    `${options.actionLabel || "处理素材"}前发现有文件格式不匹配。`,
    names.join("\n"),
    `需要的格式：${options.expectedLabel || "与素材类型匹配的文件"}`,
    options.fallbackHint || "",
  ]
    .filter(Boolean)
    .join("\n\n");
}

function shouldAdvanceAssetSelectionAfterReplace(asset) {
  if (!asset || asset.fileExists) {
    return false;
  }

  return state.assetFilterMode === "missing_file" || state.assetFilterMode === "urgent_missing";
}

async function deleteSelectedAsset() {
  const asset = getSelectedAsset();
  if (!asset) {
    setSaveStatus("先选中一个素材");
    return;
  }

  const usageCount = getAssetUsageCount(asset.id);
  if (usageCount > 0) {
    const usages = state.data.assetUsage.get(asset.id) ?? [];
    const usagePreview = formatAssetUsagePreview(usages, { limit: 6, separator: "\n" });
    await showEngineAlert({
      title: "素材仍在使用",
      message: `这个素材还在被 ${usageCount} 个位置使用，暂时不能删除。\n\n先解除这些引用后再删：\n${usagePreview}`,
      tone: "warning",
    });
    setSaveStatus("这个素材还在被使用，不能直接删除", true);
    showToast("这个素材还在被使用，先解除引用", "error");
    return;
  }

  const deletePreview = formatAssetDeletionPreview([asset], { includeFileSize: true });
  const confirmed = await showEngineConfirm({
    title: "删除这个素材？",
    message: `确定要删掉素材「${asset.name}」吗？\n\n将删除：\n${deletePreview}\n\n这个动作不能撤回；如仅需更换或补上传文件，优先使用“补/替换文件”。`,
    tone: "danger",
    confirmLabel: "删除素材",
    cancelLabel: "保留素材",
  });
  if (!confirmed) {
    return;
  }

  try {
    setSaveStatus(`正在删除素材：${asset.name}`);
    if (state.activeAssetAudioId === asset.id) {
      stopAssetAudioPreview({ rerender: false });
    }

    const nextSelectedAssetId = getNextAssetSelectionAfterDelete(asset.id);
    await postJson(API_DELETE_ASSET, {
      assetId: asset.id,
    });

    state.lastExportResult = null;
    await reloadProjectData({
      ...getCurrentUiState(),
      selectedAssetType: asset.type,
      selectedAssetId: nextSelectedAssetId,
    });

    setSaveStatus(`已删除素材：${asset.name}`);
    showToast(`已删除素材：${asset.name}`);
  } catch (error) {
    const detailMessage = getErrorDetailMessage(error);
    setSaveStatus(getErrorSummaryLine(error, "删除素材失败"), true);
    showToast("删除素材失败，已列出原因", "error");
    await showEngineAlert({
      title: "删除素材失败",
      message: `素材「${asset.name}」没有删除成功：\n${detailMessage}`,
      tone: "warning",
      copyable: true,
      confirmLabel: "我知道了",
    });
  }
}

function getNextAssetSelectionAfterDelete(deletedAssetIds) {
  const deletedIdSet = new Set(
    Array.isArray(deletedAssetIds) || deletedAssetIds instanceof Set ? [...deletedAssetIds] : [deletedAssetIds]
  );
  const currentAssets = getCurrentFilteredAssetsOfSelectedType();
  const selectedIndex = currentAssets.findIndex((asset) => asset.id === state.selectedAssetId);
  const firstDeletedIndex = currentAssets.findIndex((asset) => deletedIdSet.has(asset.id));
  const anchorIndex = selectedIndex >= 0 ? selectedIndex : firstDeletedIndex;
  const remainingAssets = currentAssets.filter((asset) => !deletedIdSet.has(asset.id));

  if (!remainingAssets.length) {
    return null;
  }

  if (anchorIndex < 0) {
    return remainingAssets[0].id;
  }

  return remainingAssets[Math.min(anchorIndex, remainingAssets.length - 1)]?.id ?? null;
}

function selectAllVisibleAssets() {
  const visibleAssets = getCurrentFilteredAssetsOfSelectedType();
  if (!visibleAssets.length) {
    setSaveStatus("当前列表里没有可勾选的素材", true);
    return;
  }

  const nextCheckedIds = new Set(getCheckedAssetIds());
  visibleAssets.forEach((asset) => nextCheckedIds.add(asset.id));
  state.assetCheckedIds = Array.from(nextCheckedIds);
  renderAssetsScreen();
  setSaveStatus(`已勾选当前列表 ${visibleAssets.length} 个素材`);
  showToast(`已勾选当前列表 ${visibleAssets.length} 个素材`);
}

function formatAssetDeletionPreview(assets, options = {}) {
  const limit = Math.max(1, Math.floor(Number(options.limit ?? 6)) || 6);
  const includeUsage = Boolean(options.includeUsage);
  const includeFileSize = options.includeFileSize !== false;
  const lines = assets.slice(0, limit).map((asset, index) => {
    const detailParts = [
      getAssetTypeLabel(asset.type),
      asset.path || "",
      includeFileSize && asset.fileExists ? formatFileSize(asset.fileSizeBytes) : "",
      includeUsage ? `已使用 ${getAssetUsageCount(asset.id)} 处` : "",
    ].filter(Boolean);
    return `${index + 1}. ${truncateText(asset.name || asset.id, 40)} · ${detailParts.join(" · ")}`;
  });

  if (assets.length > limit) {
    lines.push(`…还有 ${assets.length - limit} 个未展开`);
  }

  return lines.join("\n");
}

function clearAssetSelection() {
  const checkedCount = getCheckedAssetIds().length;
  state.assetCheckedIds = [];
  renderAssetsScreen();
  setSaveStatus(
    checkedCount > 0 ? `已清空多选：${checkedCount} 个素材` : "当前没有勾选中的素材"
  );
}

async function deleteSelectedUnusedAssets() {
  const checkedAssets = getCurrentCheckedAssetsOfSelectedType();
  if (!checkedAssets.length) {
    setSaveStatus("先勾选当前列表里要处理的素材", true);
    showToast("先勾选素材，再批量删除", "error");
    return;
  }

  const unusedAssets = checkedAssets.filter((asset) => isAssetUnused(asset.id));
  const usedAssets = checkedAssets.filter((asset) => !isAssetUnused(asset.id));

  if (!unusedAssets.length) {
    const usageLines = usedAssets
      .slice(0, 6)
      .map((asset) => {
        const usagePreview = formatAssetUsagePreview(state.data.assetUsage.get(asset.id) ?? [], {
          limit: 2,
          separator: " / ",
        });
        return `${asset.name} · 已使用 ${getAssetUsageCount(asset.id)} 处${
          usagePreview ? ` · ${usagePreview}` : ""
        }`;
      })
      .join("\n");
    await showEngineAlert({
      title: "没有可批量删除的素材",
      message: `当前勾选的 ${checkedAssets.length} 个素材都还在被使用，暂时不能批量删除。\n\n${usageLines}`,
      tone: "warning",
    });
    setSaveStatus("勾选项里没有可删除的未使用素材", true);
    showToast("勾选项都还在被使用", "error");
    return;
  }

  const deletePreview = formatAssetDeletionPreview(unusedAssets);
  const skipPreview = formatAssetDeletionPreview(usedAssets, { includeUsage: true, includeFileSize: false });
  const confirmed = await showEngineConfirm({
    title: "批量删除未使用素材？",
    message: [
      `确定要批量删除当前勾选里的未使用素材吗？`,
      `可删除：${unusedAssets.length} 个\n将删除：\n${deletePreview}`,
      usedAssets.length > 0
        ? `会自动跳过：${usedAssets.length} 个仍在使用的素材\n${skipPreview}`
        : "没有检测到正在使用的勾选项",
    ].join("\n\n"),
    tone: "danger",
    confirmLabel: "批量删除",
    cancelLabel: "先不删除",
  });
  if (!confirmed) {
    return;
  }

  try {
    setSaveStatus(`正在批量删除 ${unusedAssets.length} 个未使用素材...`);
    const result = await postJson(API_BULK_DELETE_ASSETS, {
      assetIds: checkedAssets.map((asset) => asset.id),
    });

    const deletedIds = new Set(result.deletedAssetIds ?? []);
    if (state.activeAssetAudioId && deletedIds.has(state.activeAssetAudioId)) {
      stopAssetAudioPreview({ rerender: false });
    }

    const nextSelectedAssetId = deletedIds.has(state.selectedAssetId)
      ? getNextAssetSelectionAfterDelete(deletedIds)
      : state.selectedAssetId;
    state.lastExportResult = null;
    await reloadProjectData({
      ...getCurrentUiState(),
      selectedAssetType: state.selectedAssetType,
      selectedAssetId: nextSelectedAssetId,
    });

    const message =
      result.deletedCount > 0
        ? `已删除 ${result.deletedCount} 个未使用素材${
            result.skippedUsedCount > 0 ? `，跳过 ${result.skippedUsedCount} 个正在使用的素材` : ""
          }`
        : "这次没有删除到素材";
    setSaveStatus(message, result.deletedCount === 0);
    showToast(message, result.deletedCount === 0 ? "error" : "soft");
  } catch (error) {
    const detailMessage = getErrorDetailMessage(error);
    setSaveStatus(getErrorSummaryLine(error, "批量删除素材失败"), true);
    showToast("批量删除素材失败，已列出原因", "error");
    await showEngineAlert({
      title: "批量删除素材失败",
      message: `这批素材没有批量删除成功：\n${detailMessage}`,
      tone: "warning",
      copyable: true,
      confirmLabel: "我知道了",
    });
  }
}

async function exportBuild(target = "web") {
  const exportTarget =
    target === "native_runtime"
      ? "native_runtime"
      : target === "windows_nwjs"
      ? "windows_nwjs"
      : target === "macos_nwjs"
        ? "macos_nwjs"
        : target === "linux_nwjs"
          ? "linux_nwjs"
      : target === "editor_desktop"
        ? "editor_desktop"
        : target === "editor_desktop_suite"
          ? "editor_desktop_suite"
          : "web";
  const targetLabel =
    exportTarget === "native_runtime"
      ? "原生 Runtime 包"
      : exportTarget === "windows_nwjs"
      ? "Windows 桌面包"
      : exportTarget === "macos_nwjs"
        ? "macOS 桌面包"
        : exportTarget === "linux_nwjs"
          ? "Linux 桌面包"
      : exportTarget === "editor_desktop"
        ? "编辑器桌面包"
        : exportTarget === "editor_desktop_suite"
          ? "三系统编辑器套装"
        : "试玩包";
  try {
    setSaveStatus(`正在导出${targetLabel}...`);
    const result = await postJson(API_EXPORT_BUILD, { target: exportTarget });
    state.lastExportResult = result;
    renderPreviewScreen();
    if (state.currentScreen === "dashboard") {
      renderDashboard();
    }
    if (state.currentScreen === "inspection") {
      renderInspectionScreen();
    }

    if (result.missingAssets > 0) {
      setSaveStatus(`${result.targetLabel ?? targetLabel}已导出，但还有 ${result.missingAssets} 个素材文件没找到`);
      showToast(`${result.targetLabel ?? targetLabel}已导出，缺失 ${result.missingAssets} 个素材`, "error");
      return;
    }

    if (exportTarget === "native_runtime") {
      setSaveStatus("原生 Runtime 包已经导出，里面已包含继续打成独立 App 的脚本");
      showToast("原生 Runtime 包已经导出");
      return;
    }

    if (exportTarget === "windows_nwjs") {
      setSaveStatus("Windows 桌面包已经导出，可以打包发给别人了");
      showToast("Windows 桌面包已经导出");
      return;
    }

    if (exportTarget === "macos_nwjs") {
      setSaveStatus("macOS 桌面包已经导出，可以打包发给别人了");
      showToast("macOS 桌面包已经导出");
      return;
    }

    if (exportTarget === "linux_nwjs") {
      setSaveStatus("Linux 桌面包已经导出，可以打包发给别人了");
      showToast("Linux 桌面包已经导出");
      return;
    }

    if (exportTarget === "editor_desktop") {
      setSaveStatus("编辑器桌面包已经导出，可以把整包发给别的创作者了");
      showToast("编辑器桌面包已经导出");
      return;
    }

    if (exportTarget === "editor_desktop_suite") {
      setSaveStatus("三系统编辑器套装已经导出，可以按平台分别分发了");
      showToast("三系统编辑器套装已经导出");
      return;
    }

    setSaveStatus("试玩包已经导出，可以直接打开");
    showToast("试玩包已经导出，可以直接打开");
  } catch (error) {
    const detailMessage = getErrorDetailMessage(error);
    setSaveStatus(getErrorSummaryLine(error, `导出${targetLabel}失败`), true);
    showToast(`导出${targetLabel}失败，已列出原因`, "error");
    await showEngineAlert({
      title: `导出${targetLabel}失败`,
      message: `${targetLabel}没有导出成功：\n${detailMessage}`,
      tone: "warning",
      copyable: true,
      confirmLabel: "我知道了",
    });
  }
}

async function readFileAsBase64Payload(file) {
  if (!file) {
    throw new Error("没有收到要读取的文件。");
  }

  const fileName = String(file.name || "未命名文件");
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    const rejectRead = () => {
      reject(new Error(`${fileName}：浏览器没有读到这个文件，请确认文件没有被移动、删除或被系统占用。`));
    };
    reader.onerror = rejectRead;
    reader.onabort = rejectRead;
    reader.onload = () => {
      const result = String(reader.result ?? "");
      const dataBase64 = result.includes(",") ? result.split(",").pop() : result;
      resolve({
        name: fileName,
        dataBase64,
      });
    };
    reader.readAsDataURL(file);
  });
}

async function readFilesAsBase64Payloads(files, options = {}) {
  const fileList = Array.from(files ?? []);
  const settledResults = await Promise.allSettled(fileList.map(readFileAsBase64Payload));
  const failedMessages = settledResults
    .filter((result) => result.status === "rejected")
    .map((result) => result.reason?.message || "未知文件读取失败");

  if (failedMessages.length > 0) {
    const preview = failedMessages.slice(0, 6).map((message) => `- ${message}`);
    if (failedMessages.length > 6) {
      preview.push(`- 还有 ${failedMessages.length - 6} 个文件未展开`);
    }
    throw new Error(
      `${options.actionLabel || "读取本地文件"}失败：\n${preview.join("\n")}\n请确认这些文件仍在原位置，然后重新选择。`
    );
  }

  return settledResults.map((result) => result.value);
}

async function saveSelectedScenePlanner() {
  const scene = getSelectedScene();

  if (!scene) {
    setSaveStatus("先选中一个场景，再保存场景规划", true);
    return false;
  }

  const updatedScene = cloneScene(scene);
  updatedScene.status = getSafeSceneStatus(document.getElementById("storySceneStatusSelect")?.value);
  updatedScene.priority = getSafeScenePriority(document.getElementById("storyScenePrioritySelect")?.value);
  updatedScene.notes = String(document.getElementById("storySceneNotesInput")?.value ?? "").trim();

  const success = await persistScene(updatedScene, {
    selectedSceneId: updatedScene.id,
    selectedBlockId: state.selectedBlockId,
    previewSceneId: state.previewSceneId ?? updatedScene.id,
    previewStartSceneId: state.previewStartSceneId,
    previewBlockIndex: state.previewBlockIndex,
    successMessage: `已保存场景规划：${updatedScene.name}`,
  });

  if (success) {
    showToast(`场景规划已保存：${updatedScene.name}`);
  }

  return success;
}

async function updateScenePlanning(sceneId, updates = {}, options = {}) {
  const scene = state.data?.scenesById.get(sceneId);

  if (!scene) {
    setSaveStatus("没有找到要更新的场景", true);
    return false;
  }

  const updatedScene = cloneScene(scene);

  if (Object.prototype.hasOwnProperty.call(updates, "status")) {
    updatedScene.status = getSafeSceneStatus(updates.status);
  }

  if (Object.prototype.hasOwnProperty.call(updates, "priority")) {
    updatedScene.priority = getSafeScenePriority(updates.priority);
  }

  if (Object.prototype.hasOwnProperty.call(updates, "notes")) {
    updatedScene.notes = String(updates.notes ?? "").trim();
  }

  const success = await persistScene(updatedScene, {
    selectedSceneId: state.selectedSceneId,
    selectedBlockId: state.selectedBlockId,
    previewSceneId: state.previewSceneId,
    previewStartSceneId: state.previewStartSceneId,
    previewBlockIndex: state.previewBlockIndex,
    successMessage: options.successMessage ?? `已更新场景规划：${updatedScene.name}`,
  });

  if (success) {
    showToast(options.toastMessage ?? `场景规划已更新：${updatedScene.name}`);
  }

  return success;
}

async function toggleScenePriority(sceneId, priorityValue) {
  const scene = state.data?.scenesById.get(sceneId);
  if (!scene) {
    return false;
  }

  const safePriority = getSafeScenePriority(priorityValue);
  const nextPriority = getSafeScenePriority(scene.priority) === safePriority ? "normal" : safePriority;

  return updateScenePlanning(
    sceneId,
    { priority: nextPriority },
    {
      successMessage: `${scene.name} 的优先级已切到：${getScenePriorityLabel(nextPriority)}`,
      toastMessage: `${scene.name} · ${getScenePriorityLabel(nextPriority)}`,
    }
  );
}

async function toggleSceneStatus(sceneId, statusValue) {
  const scene = state.data?.scenesById.get(sceneId);
  if (!scene) {
    return false;
  }

  const safeStatus = getSafeSceneStatus(statusValue);
  const nextStatus = getSafeSceneStatus(scene.status) === safeStatus ? "drafting" : safeStatus;

  return updateScenePlanning(
    sceneId,
    { status: nextStatus },
    {
      successMessage: `${scene.name} 的制作状态已切到：${getSceneStatusLabel(nextStatus)}`,
      toastMessage: `${scene.name} · ${getSceneStatusLabel(nextStatus)}`,
    }
  );
}

async function saveSelectedBlock(options = {}) {
  const scene = getSelectedScene();
  const block = getSelectedBlock();

  if (!scene || !block) {
    return false;
  }

  const updatedScene = cloneScene(scene);
  const blockIndex = updatedScene.blocks.findIndex((item) => item.id === block.id);

  if (blockIndex < 0) {
    return false;
  }

  updatedScene.blocks[blockIndex] = collectEditedBlock(block);

  const success = await persistScene(updatedScene, {
    selectedSceneId: updatedScene.id,
    selectedBlockId: block.id,
    previewSceneId: updatedScene.id,
    previewBlockIndex: blockIndex,
    successMessage: options.successMessage ?? "这张卡片已经保存",
    reloadAfterSave: !options.autoSave,
    skipAlertOnError: Boolean(options.autoSave),
  });

  if (success) {
    if (options.autoSave) {
      if (options.saveVersion === storyChangeVersion) {
        clearPendingStoryChanges();
      } else {
        queuePendingAutoSave(280);
      }
    } else {
      clearPendingStoryChanges();
    }
  }

  return success;
}

function getReadableTextMetrics(text) {
  return scriptReadabilityTools.getReadableTextMetrics(text);
}

function buildReadableTextSummary(metrics) {
  return scriptReadabilityTools.buildReadableTextSummary(metrics);
}

function getChoiceTextQualityState(text) {
  return scriptReadabilityTools.getChoiceTextQualityState(text);
}

function buildChoiceTextSummary(length) {
  return scriptReadabilityTools.buildChoiceTextSummary(length);
}

function renderChoiceTextQualityTools(text) {
  return scriptReadabilityTools.renderChoiceTextQualityTools(text, { escapeHtml });
}

function buildChoiceCountSummary(optionCount) {
  return scriptReadabilityTools.buildChoiceCountSummary(optionCount);
}

function updateChoiceCountQualityTools(container = document.getElementById("choiceOptionsEditor")) {
  const countTools = document.querySelector("[data-choice-count-tools]");
  const optionCount = container?.querySelectorAll("[data-choice-option]").length ?? 0;
  const isCrowded = optionCount > VN_CHOICE_MANY_OPTIONS;

  if (!countTools) {
    return;
  }

  countTools.classList.toggle("is-warning", isCrowded);
  const summary = countTools.querySelector("[data-choice-count-summary]");
  const status = countTools.querySelector("[data-choice-count-status]");
  if (summary) {
    summary.textContent = buildChoiceCountSummary(optionCount);
  }
  if (status) {
    status.textContent = isCrowded ? "按钮偏多" : "数量舒适";
    status.className = `issue-tag ${isCrowded ? "warn-text" : "good-text"}`;
  }
}

function updateChoiceTextQualityToolsFromInput(input) {
  if (!(input instanceof HTMLInputElement)) {
    return;
  }

  const tools = input.closest(".detail-row")?.querySelector("[data-choice-text-tools]");
  if (!tools) {
    return;
  }

  const toolState = getChoiceTextQualityState(input.value);
  const summary = tools.querySelector("[data-choice-text-summary]");
  const status = tools.querySelector("[data-choice-text-status]");

  tools.classList.toggle("is-warning", toolState.isLong);
  if (summary) {
    summary.textContent = buildChoiceTextSummary(toolState.length);
  }
  if (status) {
    status.textContent = toolState.statusText;
    status.className = `issue-tag ${toolState.toneClass}`;
  }
}

function isReadableTextLong(text) {
  return scriptReadabilityTools.isReadableTextLong(text);
}

function getReadableTextToolState(text) {
  return scriptReadabilityTools.getReadableTextToolState(text);
}

function updateReadableTextQualityToolsFromInput(input) {
  if (!(input instanceof HTMLTextAreaElement)) {
    return;
  }

  const tools = input.closest(".detail-row")?.querySelector("[data-readable-text-tools]");
  if (!tools) {
    return;
  }

  const toolState = getReadableTextToolState(input.value);
  const status = tools.querySelector("[data-readable-status]");
  const summary = tools.querySelector("[data-readable-summary]");
  const splitButton = tools.querySelector("[data-readable-split-button]");

  tools.classList.toggle("is-warning", toolState.isLong);
  if (summary) {
    summary.textContent = buildReadableTextSummary(toolState.metrics);
  }
  if (status) {
    status.textContent = toolState.statusText;
    status.className = `issue-tag ${toolState.toneClass}`;
  }
  if (splitButton) {
    splitButton.disabled = !toolState.canSplit;
  }
}

