function updateSelectedParticleCustomLayers(updater, options = {}) {
  const scene = getSelectedScene();
  const block = getSelectedBlock();

  if (!scene || !block || block.type !== "particle_effect") {
    return;
  }

  const updatedScene = cloneScene(scene);
  const blockIndex = updatedScene.blocks.findIndex((item) => item.id === block.id);
  if (blockIndex < 0) {
    return;
  }

  const currentDraft = collectEditedBlock(block);
  const currentLayers = normalizeParticleCustomComboLayers(currentDraft.customComboLayers);
  const nextLayers = normalizeParticleCustomComboLayers(updater(currentLayers) ?? currentLayers);

  updatedScene.blocks[blockIndex] = {
    ...currentDraft,
    customComboLayers: nextLayers,
  };

  applySceneToLocalState(updatedScene);
  state.selectedSceneId = updatedScene.id;
  state.selectedBlockId = block.id;
  state.previewSceneId = updatedScene.id;
  state.previewBlockIndex = blockIndex;
  renderStoryScreen();
  renderPreviewScreen();
  scheduleAutoSave(300);
  setSaveStatus(options.statusText ?? `自定义叠层已更新，现在共 ${nextLayers.length} 层`);
  if (options.toastText) {
    showToast(options.toastText);
  }
}

function stageSelectedParticleConfig(config, options = {}) {
  const scene = getSelectedScene();
  const block = getSelectedBlock();

  if (!scene || !block || block.type !== "particle_effect") {
    return;
  }

  const updatedScene = cloneScene(scene);
  const blockIndex = updatedScene.blocks.findIndex((item) => item.id === block.id);
  if (blockIndex < 0) {
    return;
  }

  updatedScene.blocks[blockIndex] = {
    ...block,
    ...normalizeParticleEffectConfig(config),
  };

  applySceneToLocalState(updatedScene);
  state.selectedSceneId = updatedScene.id;
  state.selectedBlockId = block.id;
  state.previewSceneId = updatedScene.id;
  state.previewBlockIndex = blockIndex;
  renderStoryScreen();
  renderPreviewScreen();

  const presetSelect = document.getElementById("editorParticleCustomPresetSelect");
  const presetNameInput = document.getElementById("editorParticleCustomPresetName");
  if (presetSelect && options.presetId) {
    presetSelect.value = String(options.presetId);
  }
  if (presetNameInput && options.presetName != null) {
    presetNameInput.value = String(options.presetName);
  }

  scheduleAutoSave(300);
  setSaveStatus(options.statusText ?? "粒子卡片已更新，正在等待自动保存...");
  if (options.toastText) {
    showToast(options.toastText);
  }
}

