function buildBlockDetails(block) {
  const rows = [["卡片类型", BLOCK_LABELS[block.type] ?? block.type]];

  switch (block.type) {
    case "background":
      rows.push([
        "背景素材",
        state.data.assetsById.get(block.assetId)?.name ?? block.assetId,
      ]);
      rows.push(["转场效果", getTransitionLabel(block.transition)]);
      rows.push(["转场时长", `${getSafeTransitionDurationMs(block.transitionDurationMs)} ms`]);
      break;
    case "dialogue":
      rows.push([
        "说话角色",
        state.data.charactersById.get(block.speakerId)?.displayName ?? block.speakerId,
      ]);
      rows.push(["角色表情", getExpressionName(block.speakerId, block.expressionId)]);
      rows.push(["台词内容", block.text]);
      rows.push([
        "文字速度",
        Object.hasOwn(TEXT_SPEED_LABELS, block.textSpeed)
          ? getTextSpeedLabel(block.textSpeed)
          : "跟随全局设置",
      ]);
      rows.push([
        "绑定语音",
        block.voiceAssetId
          ? state.data.assetsById.get(block.voiceAssetId)?.name ?? block.voiceAssetId
          : "未绑定",
      ]);
      if (block.voiceAssetId) {
        rows.push(["语音音量", formatVolumePercent(block.voiceVolume, 100)]);
      }
      break;
    case "narration":
      rows.push(["旁白内容", block.text]);
      rows.push([
        "旁白语音",
        block.voiceAssetId
          ? state.data.assetsById.get(block.voiceAssetId)?.name ?? block.voiceAssetId
          : "未绑定",
      ]);
      if (block.voiceAssetId) {
        rows.push(["语音音量", formatVolumePercent(block.voiceVolume, 100)]);
      }
      rows.push([
        "文字速度",
        Object.hasOwn(TEXT_SPEED_LABELS, block.textSpeed)
          ? getTextSpeedLabel(block.textSpeed)
          : "跟随全局设置",
      ]);
      break;
    case "character_show":
      rows.push([
        "显示角色",
        state.data.charactersById.get(block.characterId)?.displayName ?? block.characterId,
      ]);
      rows.push(["使用表情", getExpressionName(block.characterId, block.expressionId)]);
      rows.push(["显示位置", getPositionLabel(block.position)]);
      rows.push(["舞台微调", getCharacterStageSummary(getCharacterStageFromBlock(block))]);
      rows.push(["转场效果", getTransitionLabel(block.transition)]);
      rows.push(["转场时长", `${getSafeTransitionDurationMs(block.transitionDurationMs)} ms`]);
      break;
    case "character_hide":
      rows.push([
        "隐藏角色",
        state.data.charactersById.get(block.characterId)?.displayName ?? block.characterId,
      ]);
      rows.push(["转场效果", getTransitionLabel(block.transition)]);
      rows.push(["转场时长", `${getSafeTransitionDurationMs(block.transitionDurationMs)} ms`]);
      break;
    case "music_play":
      rows.push([
        "音乐素材",
        state.data.assetsById.get(block.assetId)?.name ?? block.assetId,
      ]);
      rows.push(["循环播放", block.loop ? "是" : "否"]);
      rows.push(["本段音量", formatVolumePercent(block.volume, 100)]);
      rows.push(["播放范围", getMusicEndModeLabel(block.endMode)]);
      if (getSafeMusicEndMode(block.endMode) === "after_block") {
        rows.push(["结束卡片", block.endBlockId || "未选择"]);
      }
      rows.push(["淡入时间", `${block.fadeInMs ?? 0} ms`]);
      rows.push(["范围淡出", `${block.fadeOutMs ?? 600} ms`]);
      break;
    case "music_stop":
      rows.push(["淡出时间", `${block.fadeOutMs ?? 0} ms`]);
      break;
    case "sfx_play":
      rows.push([
        "音效素材",
        state.data.assetsById.get(block.assetId)?.name ?? block.assetId,
      ]);
      rows.push(["本次音量", formatVolumePercent(block.volume, 100)]);
      break;
    case "video_play":
      rows.push([
        "视频素材",
        state.data.assetsById.get(block.assetId)?.name ?? block.assetId,
      ]);
      rows.push(["播放标题", block.title || "未填写"]);
      rows.push(["画面适配", getVideoFitLabel(block.fit)]);
      rows.push(["视频音量", `${getSafeVideoVolume(block.volume)}%`]);
      rows.push([
        "播放片段",
        `${getSafeNonNegativeNumber(block.startTimeSeconds, 0)}s -> ${
          getSafeNonNegativeNumber(block.endTimeSeconds, 0) || "自然结束"
        }`,
      ]);
      rows.push(["允许跳过", block.skippable === false ? "否" : "是"]);
      break;
    case "credits_roll": {
      const creditsLines = getCreditsLines(block.lines);
      rows.push(["片尾标题", block.title || "STAFF"]);
      rows.push(["副标题", block.subtitle || "未填写"]);
      rows.push(["字幕行数", `${creditsLines.length} 行`]);
      rows.push(["滚动时长", `${getSafeCreditsDuration(block.durationSeconds)} 秒`]);
      rows.push(["片尾背景", getCreditsBackgroundLabel(block.background)]);
      rows.push(["允许跳过", block.skippable === false ? "否" : "是"]);
      break;
    }
    case "particle_effect":
      rows.push(
        ...particleEffectTools.buildParticleEffectDetailRows(block, {
          normalizeConfig: normalizeParticleEffectConfig,
          getImageName: getParticleImageName,
        })
      );
      break;
    case "screen_shake":
      rows.push(["震动强度", getShakeIntensityLabel(block.intensity)]);
      rows.push(["持续多久", getEffectDurationLabel(block.duration)]);
      break;
    case "screen_flash":
      rows.push(["闪屏颜色", getFlashColorLabel(block.color)]);
      rows.push(["闪屏强度", getFlashIntensityLabel(block.intensity)]);
      rows.push(["持续多久", getEffectDurationLabel(block.duration)]);
      break;
    case "screen_fade":
      rows.push(["过场动作", getFadeActionLabel(block.action)]);
      rows.push(["过场颜色", getFadeColorLabel(block.color)]);
      rows.push(["持续多久", getEffectDurationLabel(block.duration)]);
      break;
    case "camera_zoom":
      rows.push(["镜头动作", getCameraZoomActionLabel(block.action)]);
      if (getSafeCameraZoomAction(block.action) !== "reset") {
        rows.push(["镜头强度", getCameraZoomStrengthLabel(block.strength)]);
        rows.push(["聚焦位置", getCameraZoomFocusLabel(block.focus)]);
      }
      break;
    case "camera_pan":
      rows.push(["平移目标", getCameraPanTargetLabel(block.target)]);
      if (getSafeCameraPanTarget(block.target) !== "center") {
        rows.push(["平移幅度", getCameraPanStrengthLabel(block.strength)]);
      }
      break;
    case "screen_filter":
      rows.push(["滤镜动作", getScreenFilterActionLabel(block.action)]);
      if (getSafeScreenFilterAction(block.action) !== "clear") {
        rows.push(["滤镜风格", getScreenFilterPresetLabel(block.preset)]);
        rows.push(["滤镜强度", getScreenFilterStrengthLabel(block.strength)]);
        rows.push(["基础调色", getScreenColorGradeSummary(block.grade)]);
      }
      break;
    case "depth_blur":
      rows.push(["景深动作", getDepthBlurActionLabel(block.action)]);
      if (getSafeDepthBlurAction(block.action) !== "clear") {
        rows.push(["清晰重点", getDepthBlurFocusLabel(block.focus)]);
        rows.push(["模糊强度", getDepthBlurStrengthLabel(block.strength)]);
      }
      break;
    case "jump":
      rows.push(["跳转到", state.data.scenesById.get(block.targetSceneId)?.name ?? block.targetSceneId]);
      break;
    case "variable_set":
    case "variable_add":
      rows.push([
        "目标变量",
        state.data.variablesById.get(block.variableId)?.name ?? block.variableId,
      ]);
      rows.push(["变化值", formatVariableValue(block.variableId, block.value)]);
      break;
    case "choice":
      rows.push(["选项数量", block.options.length]);
      block.options.forEach((option, index) => {
        rows.push([
          `选项 ${index + 1}`,
          `${option.text} -> ${
            state.data.scenesById.get(option.gotoSceneId)?.name ?? option.gotoSceneId
          }${(option.effects?.length ?? 0) > 0 ? ` / ${option.effects.length} 条效果` : ""}`,
        ]);
      });
      break;
    case "condition":
      rows.push(["条件分支", block.branches.length]);
      rows.push([
        "否则去哪里",
        state.data.scenesById.get(block.elseGotoSceneId)?.name ?? block.elseGotoSceneId,
      ]);
      break;
    default:
      rows.push(["原始内容", JSON.stringify(block)]);
  }

  return rows;
}

function getTransitionDurationSummary(block = {}) {
  return `${getTransitionLabel(block.transition)} · ${getSafeTransitionDurationMs(block.transitionDurationMs)} ms`;
}

function getBlockSummary(block, scene) {
  switch (block.type) {
    case "background":
      return {
        title: state.data.assetsById.get(block.assetId)?.name ?? block.assetId,
        meta: `切到新背景，${getTransitionDurationSummary(block)}`,
      };
    case "dialogue":
      return {
        title: `${state.data.charactersById.get(block.speakerId)?.displayName ?? block.speakerId}：${
          block.text
        }`,
        meta: block.voiceAssetId ? "这句台词已绑定语音" : "这句台词暂时没有语音",
      };
    case "narration":
      return {
        title: block.text,
        meta: block.voiceAssetId ? "这段旁白已绑定语音" : "这是旁白卡片，不会显示角色名",
      };
    case "character_show":
      return {
        title: `${
          state.data.charactersById.get(block.characterId)?.displayName ?? block.characterId
        } / ${getExpressionName(block.characterId, block.expressionId)} / ${getPositionLabel(
          block.position
        )}`,
        meta: `角色会出现在画面里，${getTransitionDurationSummary(block)}`,
      };
    case "character_hide":
      return {
        title: `${state.data.charactersById.get(block.characterId)?.displayName ?? block.characterId} 离场`,
        meta: `角色会从画面里消失，${getTransitionDurationSummary(block)}`,
      };
    case "music_play":
      return {
        title: state.data.assetsById.get(block.assetId)?.name ?? block.assetId,
        meta: `${getMusicEndModeLabel(block.endMode)} / 淡入 ${block.fadeInMs ?? 0} ms`,
      };
    case "music_stop":
      return {
        title: "停止当前背景音乐",
        meta: `淡出 ${block.fadeOutMs ?? 0} ms`,
      };
    case "sfx_play":
      return {
        title: state.data.assetsById.get(block.assetId)?.name ?? block.assetId,
        meta: "播放一次音效",
      };
    case "video_play":
      return {
        title: block.title || state.data.assetsById.get(block.assetId)?.name || block.assetId || "未选择视频",
        meta: `${getVideoFitLabel(block.fit)} / ${getSafeVideoVolume(block.volume)}% / ${
          block.skippable === false ? "不可跳过" : "可跳过"
        }`,
      };
    case "credits_roll":
      return {
        title: block.title || "STAFF",
        meta: `${getCreditsLines(block.lines).length} 行字幕 / ${getSafeCreditsDuration(
          block.durationSeconds
        )} 秒 / ${getCreditsBackgroundLabel(block.background)}`,
      };
    case "particle_effect":
      return getSafeParticleAction(block.action) === "stop"
        ? {
            title: "关闭当前粒子特效",
            meta: "让雪、雨、花瓣或光尘在这里停下",
          }
        : (() => {
            const particle = normalizeParticleEffectConfig(block);
            return {
              title: `${getParticlePresetLabel(block.preset)} / ${particle.density} 颗 / ${getParticleIntensityLabel(
                block.intensity
              )}`,
              meta: `${getParticleEmissionModeLabel(particle.emissionMode)} / ${getParticleEmitterShapeLabel(
                particle.emitterShape
              )} / ${getParticleComboPresetLabel(particle.comboPreset)} / ${getParticleCustomComboLayerSummary(
                particle.customComboLayers
              )} / ${particle.layerCount} 层 / ${getParticleSizeCurveLabel(
                particle.sizeCurve
              )} / ${getParticleColorCurveLabel(particle.colorCurve)} / ${getParticleImageName(
                block.assetId
              )} / ${formatParticleNumber(
                particle.sizeMin
              )}-${formatParticleNumber(particle.sizeMax)} px / G ${formatParticleNumber(
                particle.gravityX
              )}/${formatParticleNumber(particle.gravityY)}/${formatParticleNumber(particle.gravityZ)}`,
            };
          })();
    case "screen_shake":
      return {
        title: `${getShakeIntensityLabel(block.intensity)}震动`,
        meta: `持续 ${getEffectDurationLabel(block.duration)}`,
      };
    case "screen_flash":
      return {
        title: `${getFlashColorLabel(block.color)} / ${getFlashIntensityLabel(block.intensity)}`,
        meta: `持续 ${getEffectDurationLabel(block.duration)}`,
      };
    case "screen_fade":
      return {
        title: `${getFadeActionLabel(block.action)} / ${getFadeColorLabel(block.color)}`,
        meta: `持续 ${getEffectDurationLabel(block.duration)}`,
      };
    case "camera_zoom":
      return getSafeCameraZoomAction(block.action) === "reset"
        ? {
            title: "镜头恢复正常",
            meta: "取消前面的推近或拉远效果",
          }
        : {
            title: `${getCameraZoomActionLabel(block.action)} / ${getCameraZoomStrengthLabel(block.strength)}`,
            meta: `重点看${getCameraZoomFocusLabel(block.focus)}`,
          };
    case "camera_pan":
      return getSafeCameraPanTarget(block.target) === "center"
        ? {
            title: "镜头回到中间",
            meta: "把前面的镜头平移收回来",
          }
        : {
            title: `${getCameraPanTargetLabel(block.target)} / ${getCameraPanStrengthLabel(block.strength)}`,
            meta: "让画面慢慢偏向一侧",
          };
    case "screen_filter":
      return getSafeScreenFilterAction(block.action) === "clear"
        ? {
            title: "关闭当前回忆滤镜",
            meta: "让画面恢复正常颜色",
          }
        : {
            title: `${getScreenFilterPresetLabel(block.preset)} / ${getScreenFilterStrengthLabel(block.strength)}`,
            meta: getScreenColorGradeSummary(block.grade),
          };
    case "depth_blur":
      return getSafeDepthBlurAction(block.action) === "clear"
        ? {
            title: "关闭景深模糊",
            meta: "让画面恢复清晰",
          }
        : {
            title: `${getDepthBlurFocusLabel(block.focus)} / ${getDepthBlurStrengthLabel(block.strength)}`,
            meta: "把注意力压到你指定的区域上",
          };
    case "jump":
      return {
        title: `跳到 ${state.data.scenesById.get(block.targetSceneId)?.name ?? block.targetSceneId}`,
        meta: "直接切到另一个场景",
      };
    case "variable_set":
      return {
        title: `${
          state.data.variablesById.get(block.variableId)?.name ?? block.variableId
        } = ${formatVariableValue(block.variableId, block.value)}`,
        meta: "直接把变量改成指定值",
      };
    case "variable_add":
      return {
        title: `${
          state.data.variablesById.get(block.variableId)?.name ?? block.variableId
        } ${block.value >= 0 ? "+" : ""}${block.value}`,
        meta: "给数字变量加减数值",
      };
    case "choice":
      return {
        title: block.options.map((option) => option.text).join(" / "),
        meta: `共 ${block.options.length} 个选项，附加效果 ${(block.options ?? []).reduce(
          (total, option) => total + (option.effects?.length ?? 0),
          0
        )} 条`,
      };
    case "condition":
      return {
        title: `满足条件时分到 ${block.branches.length} 条路线`,
        meta: `否则去 ${state.data.scenesById.get(block.elseGotoSceneId)?.name ?? block.elseGotoSceneId}`,
      };
    default:
      return {
        title: block.type,
        meta: "来自较新项目数据或扩展插件的卡片，编辑器会保留它并按原顺序参与导出",
      };
  }
}

function computeVisualState(scene, blockIndex) {
  const visual = {
    backgroundAssetId: null,
    backgroundName: "未设置背景",
    backgroundTransitionEvent: null,
    musicName: "未播放",
    musicAssetId: null,
    musicVolume: 100,
    musicScope: null,
    musicFadeOutMs: 0,
    musicPreviousFadeOutMs: 0,
    particleEffect: null,
    screenShake: null,
    screenFlash: null,
    activeCharacterId: null,
    characterEmphasisEvent: null,
    visibleCharacters: [],
    speakerName: "预览面板",
    dialogueText: "选中不同卡片后，这里会显示对应的画面效果。",
  };

  if (!scene) {
    return visual;
  }

  const visibleMap = new Map();
  const blocks = scene.blocks ?? [];

  blocks.slice(0, blockIndex + 1).forEach((block, index) => {
    clearTransientStageEffects(visual);
    applyMusicScopeBeforeBlock(visual, scene, index);
    switch (block.type) {
      case "background": {
        const asset = state.data.assetsById.get(block.assetId);
        visual.backgroundAssetId = block.assetId;
        visual.backgroundName = asset?.name ?? block.assetId;
        visual.backgroundTransitionEvent =
          getSafeTransition(block.transition) === "none"
            ? null
            : {
                transition: getSafeTransition(block.transition),
                durationMs: getSafeTransitionDurationMs(block.transitionDurationMs),
              };
        visual.scene3dPreview =
          asset?.type === "scene3d" ? getSafeScene3dPreviewConfig(block.scene3dPreview) : null;
        break;
      }
      case "music_play": {
        const asset = state.data.assetsById.get(block.assetId);
        visual.musicAssetId = block.assetId;
        visual.musicName = asset?.name ?? block.assetId;
        visual.musicVolume = getSafeVolumePercent(block.volume, 100);
        visual.musicScope = getMusicScopeFromBlock(block, scene.id);
        break;
      }
      case "music_stop":
        visual.musicFadeOutMs = getSafeNonNegativeNumber(block.fadeOutMs, 600);
        visual.musicAssetId = null;
        visual.musicName = "未播放";
        visual.musicVolume = 100;
        visual.musicScope = null;
        break;
      case "video_play": {
        const asset = state.data.assetsById.get(block.assetId);
        visual.speakerName = "视频播放";
        visual.dialogueText = `${block.title || asset?.name || block.assetId || "未选择视频"} 会以 ${getVideoFitLabel(
          block.fit
        )} 方式播放。`;
        break;
      }
      case "credits_roll":
        visual.speakerName = "片尾字幕";
        visual.dialogueText = `${block.title || "STAFF"} / ${getCreditsLines(block.lines).length} 行 / ${getSafeCreditsDuration(
          block.durationSeconds
        )} 秒。`;
        break;
      case "particle_effect":
        if (getSafeParticleAction(block.action) === "stop") {
          visual.particleEffect = null;
          visual.speakerName = "粒子特效";
          visual.dialogueText = "当前场景里的粒子特效已经关闭。";
        } else {
          const particle = normalizeParticleEffectConfig(block);
          visual.particleEffect = particle;
          visual.speakerName = "粒子特效";
          visual.dialogueText = `${getParticlePresetLabel(particle.preset)}开始出现，${getParticleEmissionModeLabel(
            particle.emissionMode
          )} / ${getParticleEmitterShapeLabel(particle.emitterShape)} / ${getParticleComboPresetLabel(
            particle.comboPreset
          )} / ${getParticleCustomComboLayerSummary(particle.customComboLayers)} / ${getParticleColorCurveLabel(
            particle.colorCurve
          )} / ${particle.density} 颗。`;
        }
        break;
      case "screen_shake":
        visual.screenShake = {
          intensity: getSafeShakeIntensity(block.intensity),
          duration: getSafeEffectDuration(block.duration),
        };
        visual.speakerName = "屏幕演出";
        visual.dialogueText = `这里会让画面${getShakeIntensityLabel(block.intensity)}地震一下。`;
        break;
      case "screen_flash":
        visual.screenFlash = {
          color: getSafeFlashColor(block.color),
          intensity: getSafeFlashIntensity(block.intensity),
          duration: getSafeEffectDuration(block.duration),
        };
        visual.speakerName = "屏幕演出";
        visual.dialogueText = `这里会出现一次${getFlashColorLabel(block.color)}。`;
        break;
      case "screen_fade": {
        const fadeAction = getSafeFadeAction(block.action);
        visual.screenFade =
          fadeAction === "fade_out"
            ? {
                color: getSafeFadeColor(block.color),
                duration: getSafeEffectDuration(block.duration),
              }
            : null;
        visual.speakerName = "画面过场";
        visual.dialogueText =
          fadeAction === "fade_out"
            ? `这里会慢慢淡到${getFadeColorLabel(block.color)}。`
            : `这里会从${getFadeColorLabel(block.color)}亮起。`;
        break;
      }
      case "camera_zoom": {
        const zoomAction = getSafeCameraZoomAction(block.action);
        visual.cameraZoom =
          zoomAction === "reset"
            ? null
            : {
                action: zoomAction,
                strength: getSafeCameraZoomStrength(block.strength),
                focus: getSafeCameraZoomFocus(block.focus),
              };
        visual.speakerName = "镜头演出";
        visual.dialogueText =
          zoomAction === "reset"
            ? "这里会把镜头恢复到正常大小。"
            : `这里会${getCameraZoomActionLabel(block.action)}，重点看${getCameraZoomFocusLabel(block.focus)}。`;
        break;
      }
      case "camera_pan": {
        const target = getSafeCameraPanTarget(block.target);
        visual.cameraPan =
          target === "center"
            ? null
            : {
                target,
                strength: getSafeCameraPanStrength(block.strength),
              };
        visual.speakerName = "镜头演出";
        visual.dialogueText =
          target === "center"
            ? "这里会把镜头拉回中间。"
            : `这里会${getCameraPanTargetLabel(block.target)}。`;
        break;
      }
      case "screen_filter": {
        const filterAction = getSafeScreenFilterAction(block.action);
        visual.screenFilter =
          filterAction === "clear"
            ? null
            : {
                preset: getSafeScreenFilterPreset(block.preset),
                strength: getSafeScreenFilterStrength(block.strength),
                grade: getSafeScreenColorGrade(block.grade),
              };
        visual.speakerName = "画面滤镜";
        visual.dialogueText =
          filterAction === "clear"
            ? "这里会把滤镜关掉。"
            : `这里会套上${getScreenFilterPresetLabel(block.preset)}，调色 ${getScreenColorGradeSummary(block.grade)}。`;
        break;
      }
      case "depth_blur": {
        const blurAction = getSafeDepthBlurAction(block.action);
        visual.depthBlur =
          blurAction === "clear"
            ? null
            : {
                focus: getSafeDepthBlurFocus(block.focus),
                strength: getSafeDepthBlurStrength(block.strength),
              };
        visual.speakerName = "镜头景深";
        visual.dialogueText =
          blurAction === "clear"
            ? "这里会把景深模糊关掉。"
            : `这里会突出${getDepthBlurFocusLabel(block.focus)}。`;
        break;
      }
      case "character_show":
        visibleMap.set(block.characterId, {
          characterId: block.characterId,
          position: block.position ?? getDefaultCharacterPosition(block.characterId),
          expressionId: block.expressionId,
          expressionName: getExpressionName(block.characterId, block.expressionId),
          stage: getCharacterStageFromBlock(block),
        });
        if (getSafeTransition(block.transition) !== "none") {
          visual.characterTransitionEvent = {
            mode: "show",
            characterId: block.characterId,
            transition: getSafeTransition(block.transition),
            durationMs: getSafeTransitionDurationMs(block.transitionDurationMs),
          };
        }
        break;
      case "character_hide": {
        const previousState =
          visibleMap.get(block.characterId) ?? createFallbackPreviewCharacterState(block.characterId);
        visibleMap.delete(block.characterId);
        if (getSafeTransition(block.transition) !== "none") {
          visual.characterTransitionEvent = {
            mode: "hide",
            characterState: previousState,
            transition: getSafeTransition(block.transition),
            durationMs: getSafeTransitionDurationMs(block.transitionDurationMs),
          };
        }
        break;
      }
      case "dialogue": {
        const characterName =
          state.data.charactersById.get(block.speakerId)?.displayName ?? block.speakerId;
        visual.activeCharacterId = block.speakerId;
        visual.characterEmphasisEvent = {
          mode: "dialogue",
          characterId: block.speakerId,
        };
        visual.speakerName = characterName;
        visual.dialogueText = block.text;

        const existing = visibleMap.get(block.speakerId);
        visibleMap.set(block.speakerId, {
          characterId: block.speakerId,
          position: existing?.position ?? getDefaultCharacterPosition(block.speakerId),
          expressionId: block.expressionId,
          expressionName: getExpressionName(block.speakerId, block.expressionId),
          stage: existing?.stage ?? getSafeCharacterStage(),
        });
        break;
      }
      case "narration":
        visual.speakerName = "旁白";
        visual.dialogueText = block.text;
        break;
      case "choice":
        visual.speakerName = "选择分支";
        visual.dialogueText = block.options.map((option) => option.text).join(" / ");
        break;
      case "variable_set": {
        const variable = state.data.variablesById.get(block.variableId);
        visual.speakerName = "系统变量";
        visual.dialogueText = `${variable?.name ?? block.variableId} 设为 ${formatVariableValue(
          block.variableId,
          block.value
        )}`;
        break;
      }
      case "variable_add": {
        const variable = state.data.variablesById.get(block.variableId);
        const delta = normalizeVariableValue(block.variableId, block.value);
        const deltaText = typeof delta === "number" && delta > 0 ? `+${delta}` : `${delta}`;
        visual.speakerName = "系统变量";
        visual.dialogueText = `${variable?.name ?? block.variableId} ${deltaText}`;
        break;
      }
      case "condition":
        visual.speakerName = "系统判断";
        visual.dialogueText = `这里会根据变量结果跳去不同场景。`;
        break;
      case "jump":
        visual.speakerName = "场景跳转";
        visual.dialogueText = `下一步会跳到：${
          state.data.scenesById.get(block.targetSceneId)?.name ?? block.targetSceneId
        }`;
        break;
      default:
        break;
    }
  });

  visual.visibleCharacters = Array.from(visibleMap.values()).sort(
    (left, right) =>
      getPositionOrder(left.position) - getPositionOrder(right.position)
  );

  return visual;
}

function buildAssetUsageMap({ chapters, characters, charactersById }) {
  const usage = new Map();

  function addUsage(assetId, entry) {
    if (!assetId) {
      return;
    }
    const list = usage.get(assetId) ?? [];
    list.push(entry);
    usage.set(assetId, list);
  }

  for (const character of characters ?? []) {
    addUsage(character.defaultSpriteId, {
      kind: "character",
      characterId: character.id,
      label: `角色默认立绘：${character.displayName}`,
      meta: "角色资料页 / 默认立绘",
    });
    const presentation = getCharacterPresentation(character);
    addUsage(presentation.fallbackSpriteAssetId, {
      kind: "character",
      characterId: character.id,
      label: `角色高级表现兜底：${character.displayName}`,
      meta: "角色资料页 / 高级表现",
    });
    addUsage(presentation.live2d.modelAssetId, {
      kind: "character",
      characterId: character.id,
      label: `角色 Live2D 模型：${character.displayName}`,
      meta: "角色资料页 / 高级表现",
    });
    addUsage(presentation.model3d.modelAssetId, {
      kind: "character",
      characterId: character.id,
      label: `角色 3D 模型：${character.displayName}`,
      meta: "角色资料页 / 高级表现",
    });
    for (const expression of character.expressions ?? []) {
      addUsage(expression.spriteAssetId, {
        kind: "character",
        characterId: character.id,
        label: `角色表情：${character.displayName} / ${expression.name}`,
        meta: "角色资料页 / 表情设置",
      });
      (expression.layerAssetIds ?? []).forEach((layerAssetId) => {
        addUsage(layerAssetId, {
          kind: "character",
          characterId: character.id,
          label: `角色差分图层：${character.displayName} / ${expression.name}`,
          meta: "角色资料页 / 表情差分",
        });
      });
    }
  }

  chapters.forEach((chapter) => {
    (chapter.scenes ?? []).forEach((scene) => {
      (scene.blocks ?? []).forEach((block, blockIndex) => {
        if (block.assetId) {
          addUsage(block.assetId, {
            kind: "story",
            sceneId: scene.id,
            blockId: block.id,
            label: `场景：${scene.name} / ${BLOCK_LABELS[block.type] ?? block.type}`,
            meta: `${chapter.name} · 第 ${blockIndex + 1} 张卡片`,
          });
        }
        if (block.voiceAssetId) {
          addUsage(block.voiceAssetId, {
            kind: "story",
            sceneId: scene.id,
            blockId: block.id,
            label: `场景：${scene.name} / ${BLOCK_LABELS[block.type] ?? "正文"}语音`,
            meta: `${chapter.name} · 第 ${blockIndex + 1} 张卡片`,
          });
        }
        if (block.type === "dialogue" || block.type === "character_show") {
          const characterId = block.speakerId ?? block.characterId;
          const expressionId = block.expressionId;
          const character = charactersById.get(characterId);
          const expression = character?.expressions?.find((item) => item.id === expressionId);
          addUsage(expression?.spriteAssetId, {
            kind: "story",
            sceneId: scene.id,
            blockId: block.id,
            label: `场景：${scene.name} / ${character?.displayName ?? characterId} ${
              expression?.name ?? ""
            }`.trim(),
            meta: `${chapter.name} · 第 ${blockIndex + 1} 张卡片`,
          });
        }
      });
    });
  });

  return usage;
}

function runValidation(data) {
  const errors = [];
  const warnings = [];

  const pushIssue = (level, message, location, context = null) => {
    const issue = { message, location, context };
    if (level === "error") {
      errors.push(issue);
    } else {
      warnings.push(issue);
    }
  };

  validateUniqueIds(data.assetList, "素材", pushIssue, "id", (item, id) =>
    data.assetsById.has(id) ? { type: "asset", assetId: id } : { type: "screen", screen: "assets" }
  );
  validateUniqueIds(data.characters, "角色", pushIssue, "id", (item, id) =>
    data.charactersById.has(id)
      ? { type: "character", characterId: id }
      : { type: "screen", screen: "characters" }
  );
  validateUniqueIds(data.variables, "变量", pushIssue, "id", () => ({
    type: "screen",
    screen: "story",
  }));
  data.variables.forEach((variable) => {
    const variableContext = {
      type: "screen",
      screen: "preview",
    };
    if (!isRawVariableValueMatchingType(variable, variable.defaultValue)) {
      pushIssue("error", "变量默认值类型不正确。", `变量 ${variable.name ?? variable.id}`, variableContext);
    }

    if (variable.type === "number") {
      const rawMin = variable.min ?? variable.minValue;
      const rawMax = variable.max ?? variable.maxValue;
      const [minValue, maxValue] = getVariableNumberBounds(variable);
      if (rawMin !== null && rawMin !== undefined && minValue === null) {
        pushIssue(
          "error",
          "数字变量的最小值不是有效数字。",
          `变量 ${variable.name ?? variable.id} -> min`,
          variableContext
        );
      }
      if (rawMax !== null && rawMax !== undefined && maxValue === null) {
        pushIssue(
          "error",
          "数字变量的最大值不是有效数字。",
          `变量 ${variable.name ?? variable.id} -> max`,
          variableContext
        );
      }

      const rangeOrderIsValid = !(minValue !== null && maxValue !== null && minValue > maxValue);
      if (!rangeOrderIsValid) {
        pushIssue(
          "error",
          "数字变量的范围上下限反了。",
          `变量 ${variable.name ?? variable.id} -> min/max`,
          variableContext
        );
      }

      if (rangeOrderIsValid && isRawVariableValueMatchingType(variable, variable.defaultValue)) {
        const defaultValue = Number.parseFloat(variable.defaultValue);
        if (
          (minValue !== null && defaultValue < minValue) ||
          (maxValue !== null && defaultValue > maxValue)
        ) {
          pushIssue(
            "warning",
            "数字变量默认值超出了范围，运行时会自动夹回范围内。",
            `变量 ${variable.name ?? variable.id} -> defaultValue`,
            variableContext
          );
        }
      }
    }
  });
  validateUniqueIds(data.chapters, "章节", pushIssue, "chapterId", (item, id) =>
    data.chaptersById.has(id) ? { type: "chapter", chapterId: id } : { type: "screen", screen: "story" }
  );
  validateUniqueIds(data.scenes, "场景", pushIssue, "id", (item, id) =>
    data.scenesById.has(id) ? { type: "scene", sceneId: id } : { type: "screen", screen: "story" }
  );

  const validChapterIds = new Set(data.chapters.map((chapter) => chapter.chapterId).filter(Boolean));
  const seenChapterOrderIds = new Set();
  (data.project.chapterOrder ?? []).forEach((chapterId, orderIndex) => {
    const safeChapterId = String(chapterId ?? "").trim();
    if (!safeChapterId) {
      return;
    }
    if (seenChapterOrderIds.has(safeChapterId)) {
      pushIssue("warning", "章节排序重复。", `project.json.chapterOrder[${orderIndex}] -> ${safeChapterId}`, {
        type: "chapter",
        chapterId: safeChapterId,
      });
      return;
    }
    seenChapterOrderIds.add(safeChapterId);
    if (!validChapterIds.has(safeChapterId)) {
      pushIssue("error", "章节排序里引用了不存在的章节。", `project.json.chapterOrder[${orderIndex}] -> ${safeChapterId}`, {
        type: "screen",
        screen: "story",
      });
    }
  });
  data.chapters.forEach((chapter) => {
    if (chapter.chapterId && !seenChapterOrderIds.has(chapter.chapterId)) {
      pushIssue("warning", "章节没有进入排序。", `project.json.chapterOrder -> 缺少 ${chapter.chapterId}`, {
        type: "chapter",
        chapterId: chapter.chapterId,
      });
    }
  });

  if (data.scenes.length > 0 && !data.scenesById.has(data.project.entrySceneId)) {
    pushIssue("error", "入口场景不存在。", `project.json -> ${data.project.entrySceneId}`, {
      type: "screen",
      screen: "story",
    });
  }

  data.characters.forEach((character) => {
    const presentation = getCharacterPresentation(character);
    const primaryAdvancedAssetId =
      presentation.mode === "live2d"
        ? presentation.live2d.modelAssetId
        : presentation.mode === "model3d"
          ? presentation.model3d.modelAssetId
          : "";
    const canUseAdvancedAsset = primaryAdvancedAssetId && data.assetsById.has(primaryAdvancedAssetId);
    if (!data.assetsById.has(character.defaultSpriteId) && !canUseAdvancedAsset) {
      pushIssue("error", "角色默认立绘找不到。", `角色 ${character.displayName}`, {
        type: "character",
        characterId: character.id,
      });
    }
    if (presentation.fallbackSpriteAssetId && !data.assetsById.has(presentation.fallbackSpriteAssetId)) {
      pushIssue("warning", "角色高级表现的兜底立绘找不到。", `角色 ${character.displayName}`, {
        type: "character",
        characterId: character.id,
      });
    }
    if (presentation.mode === "live2d") {
      if (!presentation.live2d.modelAssetId) {
        pushIssue("warning", "Live2D 角色还没有绑定模型入口文件。", `角色 ${character.displayName}`, {
          type: "character",
          characterId: character.id,
        });
      } else if (!data.assetsById.has(presentation.live2d.modelAssetId)) {
        pushIssue("error", "Live2D 角色绑定的模型素材找不到。", `角色 ${character.displayName}`, {
          type: "character",
          characterId: character.id,
        });
      }
    }
    if (presentation.mode === "model3d") {
      if (!presentation.model3d.modelAssetId) {
        pushIssue("warning", "3D 角色还没有绑定模型文件。", `角色 ${character.displayName}`, {
          type: "character",
          characterId: character.id,
        });
      } else if (!data.assetsById.has(presentation.model3d.modelAssetId)) {
        pushIssue("error", "3D 角色绑定的模型素材找不到。", `角色 ${character.displayName}`, {
          type: "character",
          characterId: character.id,
        });
      }
    }
    const seenExpressionIds = new Set();
    (character.expressions ?? []).forEach((expression) => {
      if (seenExpressionIds.has(expression.id)) {
        pushIssue("error", "同一角色里有重复表情 ID。", `角色 ${character.displayName}`, {
          type: "character",
          characterId: character.id,
        });
      }
      seenExpressionIds.add(expression.id);
      if (!data.assetsById.has(expression.spriteAssetId)) {
        pushIssue(
          presentation.mode === "sprite" || presentation.mode === "layered_sprite" ? "error" : "warning",
          "角色表情绑定的立绘素材找不到。",
          `角色 ${character.displayName} / 表情 ${expression.name}`,
          {
            type: "character",
            characterId: character.id,
          }
        );
      }
      (expression.layerAssetIds ?? []).forEach((layerAssetId) => {
        if (!data.assetsById.has(layerAssetId)) {
          pushIssue("warning", "角色差分图层绑定的素材找不到。", `角色 ${character.displayName} / 表情 ${expression.name}`, {
            type: "character",
            characterId: character.id,
          });
        }
      });
    });
  });

  data.chapters.forEach((chapter) => {
    const localSceneIds = new Set((chapter.scenes ?? []).map((scene) => scene.id).filter(Boolean));
    const seenSceneOrderIds = new Set();
    (chapter.sceneOrder ?? []).forEach((sceneId, orderIndex) => {
      const safeSceneId = String(sceneId ?? "").trim();
      if (!safeSceneId) {
        return;
      }
      if (seenSceneOrderIds.has(safeSceneId)) {
        pushIssue("warning", "场景排序重复。", `章节 ${chapter.name} -> sceneOrder[${orderIndex}] -> ${safeSceneId}`, {
          type: "chapter",
          chapterId: chapter.chapterId,
        });
        return;
      }
      seenSceneOrderIds.add(safeSceneId);
      if (!localSceneIds.has(safeSceneId)) {
        pushIssue("error", "场景排序里引用了不存在的场景。", `章节 ${chapter.name} -> sceneOrder[${orderIndex}] -> ${safeSceneId}`, {
          type: "chapter",
          chapterId: chapter.chapterId,
        });
      }
    });
    (chapter.scenes ?? []).forEach((scene) => {
      if (scene.id && !seenSceneOrderIds.has(scene.id)) {
        pushIssue("warning", "场景没有进入排序。", `章节 ${chapter.name} -> sceneOrder 缺少 ${scene.id}`, {
          type: "chapter",
          chapterId: chapter.chapterId,
        });
      }
    });

    (chapter.scenes ?? []).forEach((scene) => {
      if (!scene.name?.trim()) {
        pushIssue("warning", "场景还没有名字。", `场景 ${scene.id}`, {
          type: "scene",
          sceneId: scene.id,
        });
      }

      const seenBlockIds = new Set();

      (scene.blocks ?? []).forEach((block) => {
        if (seenBlockIds.has(block.id)) {
          pushIssue("error", "同一场景里有重复卡片 ID。", `场景 ${scene.name}`, {
            type: "scene",
            sceneId: scene.id,
          });
        }
        seenBlockIds.add(block.id);

        validateBlock(block, scene, data, pushIssue);
      });
    });
  });

  return { errors, warnings };
}

function validateUniqueIds(items, label, pushIssue, idKey = "id", contextBuilder = null) {
  const seen = new Set();
  items.forEach((item) => {
    const id = item[idKey];
    if (seen.has(id)) {
      pushIssue(
        "error",
        `${label}里有重复 ID。`,
        `${label} ${id}`,
        typeof contextBuilder === "function" ? contextBuilder(item, id) : null
      );
    }
    seen.add(id);
  });
}

function validateReadableTextLength(text, label, location, context, pushIssue) {
  const safeText = String(text ?? "").trim();
  if (!safeText) {
    return;
  }
  const metrics = getReadableTextMetrics(safeText);
  if (isReadableTextLong(safeText)) {
    pushIssue(
      "warning",
      `${label}偏长，正式发布前建议拆成多张卡片。`,
      `${location} -> ${metrics.length} 字 / ${metrics.lineCount} 行`,
      context
    );
  }
}

function validateBlock(block, scene, data, pushIssue) {
  const location = `场景 ${scene.name} / ${BLOCK_LABELS[block.type] ?? block.type}`;
  const blockContext = {
    type: "story",
    sceneId: scene.id,
    blockId: block.id,
  };

  const requireAsset = (assetId) => {
    if (assetId && !data.assetsById.has(assetId)) {
      pushIssue("error", "引用的素材不存在。", `${location} -> ${assetId}`, blockContext);
    }
  };

  const requireScene = (sceneId, prefix) => {
    if (sceneId && !data.scenesById.has(sceneId)) {
      pushIssue("error", `${prefix}不存在。`, `${location} -> ${sceneId}`, blockContext);
    }
  };

  const requireVariable = (variableId) => {
    if (variableId && !data.variablesById.has(variableId)) {
      pushIssue("error", "引用的变量不存在。", `${location} -> ${variableId}`, blockContext);
    }
  };

  const matchesVariableType = (variableId, value) => {
    const variable = data.variablesById.get(variableId);

    if (!variable) {
      return true;
    }

    if (variable.type === "number") {
      return typeof value === "number" && Number.isFinite(value);
    }

    if (variable.type === "boolean") {
      return typeof value === "boolean";
    }

    return typeof value === "string";
  };

  const requireCharacterExpression = (characterId, expressionId) => {
    const character = data.charactersById.get(characterId);
    if (!character) {
      pushIssue("error", "引用的角色不存在。", `${location} -> ${characterId}`, blockContext);
      return;
    }
    if (!character.expressions.some((expression) => expression.id === expressionId)) {
      pushIssue("error", "角色表情不存在。", `${location} -> ${character.displayName} / ${expressionId}`, blockContext);
    }
  };

  switch (block.type) {
      case "background":
      case "music_play":
      case "sfx_play":
      case "video_play":
        requireAsset(block.assetId);
        if (block.type === "video_play") {
          if (!block.assetId) {
            pushIssue("warning", "视频播放卡片还没有选择视频素材。", location, blockContext);
          }
          if (getSafeVideoFit(block.fit) !== (block.fit ?? "contain")) {
            pushIssue("warning", "视频适配方式不认识，预览时会回退成完整显示。", location, blockContext);
          }
          if (Number(block.endTimeSeconds ?? 0) > 0 && Number(block.endTimeSeconds) <= Number(block.startTimeSeconds ?? 0)) {
            pushIssue("warning", "视频结束秒数需要大于开始秒数，否则会播放到自然结束。", location, blockContext);
          }
        }
        break;
      case "credits_roll":
        if (getCreditsLines(block.lines).length === 0) {
          pushIssue("warning", "片尾字幕还没有填写演职人员内容。", location, blockContext);
        }
        if (getSafeCreditsBackground(block.background) !== (block.background ?? "dark")) {
          pushIssue("warning", "片尾背景样式不认识，预览时会回退成深色电影片尾。", location, blockContext);
        }
        break;
      case "particle_effect":
        if (getSafeParticleAction(block.action) === "start") {
          const particle = normalizeParticleEffectConfig(block);
          requireAsset(block.assetId);
          if (getSafeParticlePreset(block.preset) !== block.preset) {
            pushIssue("warning", "粒子特效类型不认识，预览时会回退成默认雪花。", location, blockContext);
          }
          if (getSafeParticleIntensity(block.intensity) !== block.intensity) {
            pushIssue("warning", "粒子特效强度不认识，预览时会回退成中等。", location, blockContext);
          }
          if (getSafeParticleSpeed(block.speed) !== (block.speed ?? "medium")) {
            pushIssue("warning", "粒子速度不认识，预览时会回退成正常。", location, blockContext);
          }
          if (getSafeParticleWind(block.wind) !== (block.wind ?? "still")) {
            pushIssue("warning", "粒子风向不认识，预览时会回退成几乎无风。", location, blockContext);
          }
          if (getSafeParticleArea(block.area) !== (block.area ?? "full")) {
            pushIssue("warning", "粒子出现区域不认识，预览时会回退成铺满全屏。", location, blockContext);
          }
          if (
            getSafeParticleEmissionMode(block.emissionMode ?? particle.emissionMode) !==
            (block.emissionMode ?? particle.emissionMode)
          ) {
            pushIssue("warning", "粒子发射模式不认识，预览时会回退成持续发射。", location, blockContext);
          }
          if (
            getSafeParticleEmitterShape(block.emitterShape ?? particle.emitterShape) !==
            (block.emitterShape ?? particle.emitterShape)
          ) {
            pushIssue("warning", "粒子发射器形状不认识，预览时会回退成线形发射器。", location, blockContext);
          }
          if (getSafeParticleForceField(block.forceField ?? particle.forceField) !== (block.forceField ?? particle.forceField)) {
            pushIssue("warning", "粒子中心力场不认识，预览时会回退成无中心力场。", location, blockContext);
          }
          if (getSafeParticleComboPreset(block.comboPreset ?? particle.comboPreset) !== (block.comboPreset ?? particle.comboPreset)) {
            pushIssue("warning", "粒子组合方案不认识，预览时会回退成单层粒子。", location, blockContext);
          }
          (Array.isArray(block.customComboLayers) ? block.customComboLayers : []).forEach((layer, index) => {
            if (!layer?.enabled) {
              return;
            }
            const slotLabel = `自定义叠层 ${index + 1}`;
            if (getSafeParticlePreset(layer.preset) !== layer.preset) {
              pushIssue("warning", `${slotLabel} 的粒子类型不认识，预览时会回退成默认叠层。`, location, blockContext);
            }
            if (getSafeParticleEmissionMode(layer.emissionMode ?? "continuous") !== (layer.emissionMode ?? "continuous")) {
              pushIssue("warning", `${slotLabel} 的发射模式不认识，预览时会回退成持续发射。`, location, blockContext);
            }
            if (getSafeParticleFollowTarget(layer.follow ?? "none") !== (layer.follow ?? "none")) {
              pushIssue("warning", `${slotLabel} 的跟随目标不认识，预览时会回退成固定画面。`, location, blockContext);
            }
            if (getSafeParticleFollowAnchor(layer.followAnchor ?? "torso") !== (layer.followAnchor ?? "torso")) {
              pushIssue("warning", `${slotLabel} 的跟随锚点不认识，预览时会回退成身体中段。`, location, blockContext);
            }
            if (getSafeParticleBlendMode(layer.blend ?? "screen") !== (layer.blend ?? "screen")) {
              pushIssue("warning", `${slotLabel} 的混合模式不认识，预览时会回退成滤色发光。`, location, blockContext);
            }
          });
          if (getSafeParticleFollowTarget(block.follow ?? particle.follow) !== (block.follow ?? particle.follow)) {
            pushIssue("warning", "粒子跟随目标不认识，预览时会回退成固定在画面。", location, blockContext);
          }
          if (
            getSafeParticleFollowAnchor(block.followAnchor ?? particle.followAnchor) !==
            (block.followAnchor ?? particle.followAnchor)
          ) {
            pushIssue("warning", "粒子跟随锚点不认识，预览时会回退成身体中段。", location, blockContext);
          }
          if (getSafeParticleSizeCurve(block.sizeCurve ?? particle.sizeCurve) !== (block.sizeCurve ?? particle.sizeCurve)) {
            pushIssue("warning", "粒子尺寸时间曲线不认识，预览时会回退成稳定尺寸。", location, blockContext);
          }
          if (
            getSafeParticleOpacityCurve(block.opacityCurve ?? particle.opacityCurve) !==
            (block.opacityCurve ?? particle.opacityCurve)
          ) {
            pushIssue("warning", "粒子透明度时间曲线不认识，预览时会回退成正常淡出。", location, blockContext);
          }
          if (getSafeParticleColorCurve(block.colorCurve ?? particle.colorCurve) !== (block.colorCurve ?? particle.colorCurve)) {
            pushIssue("warning", "粒子颜色时间曲线不认识，预览时会回退成颜色保持稳定。", location, blockContext);
          }
          if (getSafeParticleBlendMode(block.blend ?? particle.blend) !== (block.blend ?? particle.blend)) {
            pushIssue("warning", "粒子混合模式不认识，预览时会回退成滤色发光。", location, blockContext);
          }
          if (!isValidParticleColor(block.color ?? particle.color)) {
            pushIssue("warning", "粒子主颜色格式不对，预览时会回退成预设颜色。", location, blockContext);
          }
          if (!isValidParticleColor(block.colorAccent ?? particle.colorAccent)) {
            pushIssue("warning", "粒子辅助颜色格式不对，预览时会回退成预设颜色。", location, blockContext);
          }
          if (!isValidParticleColor(block.colorEnd ?? particle.colorEnd)) {
            pushIssue("warning", "粒子结尾颜色格式不对，预览时会回退成辅助颜色。", location, blockContext);
          }
          const numericFields = [
            ["density", particle.density, "粒子数量"],
            ["layerCount", particle.layerCount, "叠加层数"],
            ["emitterX", particle.emitterX, "发射器 X"],
            ["emitterY", particle.emitterY, "发射器 Y"],
            ["emitterZ", particle.emitterZ, "发射器 Z"],
            ["fieldX", particle.fieldX, "力场中心 X"],
            ["fieldY", particle.fieldY, "力场中心 Y"],
            ["attractionX", particle.attractionX, "吸引 / 推离 X"],
            ["attractionY", particle.attractionY, "吸引 / 推离 Y"],
            ["vortex", particle.vortex, "旋涡"],
            ["sizeMin", particle.sizeMin, "最小尺寸"],
            ["sizeMax", particle.sizeMax, "最大尺寸"],
            ["lifeMin", particle.lifeMin, "最短寿命"],
            ["lifeMax", particle.lifeMax, "最长寿命"],
            ["gravityX", particle.gravityX, "重力 X"],
            ["gravityY", particle.gravityY, "重力 Y"],
            ["gravityZ", particle.gravityZ, "重力 Z"],
            ["spreadX", particle.spreadX, "疏散 X"],
            ["spreadY", particle.spreadY, "疏散 Y"],
            ["spreadZ", particle.spreadZ, "疏散 Z"],
            ["opacityMin", particle.opacityMin, "最小透明度"],
            ["opacityMax", particle.opacityMax, "最大透明度"],
            ["rotationMin", particle.rotationMin, "初始旋转最小值"],
            ["rotationMax", particle.rotationMax, "初始旋转最大值"],
            ["spin", particle.spin, "自转速度"],
            ["turbulence", particle.turbulence, "扰动"],
          ];
          numericFields.forEach(([field, safeValue, label]) => {
            const rawValue = block[field];
            if (rawValue != null && Number(rawValue) !== safeValue) {
              pushIssue("warning", `${label}超出可用范围，预览时会自动压回安全值。`, location, blockContext);
            }
          });
        }
        break;
      case "screen_shake":
        if (getSafeShakeIntensity(block.intensity) !== (block.intensity ?? "medium")) {
          pushIssue("warning", "屏幕震动强度不认识，预览时会回退成明显。", location, blockContext);
        }
        if (getSafeEffectDuration(block.duration) !== (block.duration ?? "medium")) {
          pushIssue("warning", "震动持续时间不认识，预览时会回退成正常。", location, blockContext);
        }
        break;
      case "screen_flash":
        if (getSafeFlashColor(block.color) !== (block.color ?? "white")) {
          pushIssue("warning", "闪屏颜色不认识，预览时会回退成白闪。", location, blockContext);
        }
        if (getSafeFlashIntensity(block.intensity) !== (block.intensity ?? "medium")) {
          pushIssue("warning", "闪屏强度不认识，预览时会回退成明显。", location, blockContext);
        }
        if (getSafeEffectDuration(block.duration) !== (block.duration ?? "medium")) {
          pushIssue("warning", "闪屏持续时间不认识，预览时会回退成正常。", location, blockContext);
        }
        break;
      case "screen_fade":
        if (getSafeFadeAction(block.action) !== (block.action ?? "fade_out")) {
          pushIssue("warning", "淡入淡出动作不认识，预览时会回退成慢慢淡出。", location, blockContext);
        }
        if (getSafeFadeColor(block.color) !== (block.color ?? "black")) {
          pushIssue("warning", "淡入淡出颜色不认识，预览时会回退成黑场。", location, blockContext);
        }
        if (getSafeEffectDuration(block.duration) !== (block.duration ?? "medium")) {
          pushIssue("warning", "淡入淡出持续时间不认识，预览时会回退成正常。", location, blockContext);
        }
        break;
      case "camera_zoom":
        if (getSafeCameraZoomAction(block.action) !== (block.action ?? "zoom_in")) {
          pushIssue("warning", "镜头动作不认识，预览时会回退成推近镜头。", location, blockContext);
        }
        if (getSafeCameraZoomAction(block.action) !== "reset") {
          if (getSafeCameraZoomStrength(block.strength) !== (block.strength ?? "medium")) {
            pushIssue("warning", "镜头强度不认识，预览时会回退成明显。", location, blockContext);
          }
          if (getSafeCameraZoomFocus(block.focus) !== (block.focus ?? "center")) {
            pushIssue("warning", "镜头聚焦位置不认识，预览时会回退成中间。", location, blockContext);
          }
        }
        break;
      case "camera_pan":
        if (getSafeCameraPanTarget(block.target) !== (block.target ?? "center")) {
          pushIssue("warning", "镜头平移方向不认识，预览时会回退成回到中间。", location, blockContext);
        }
        if (getSafeCameraPanTarget(block.target) !== "center") {
          if (getSafeCameraPanStrength(block.strength) !== (block.strength ?? "medium")) {
            pushIssue("warning", "镜头平移幅度不认识，预览时会回退成明显。", location, blockContext);
          }
        }
        break;
      case "screen_filter":
        if (getSafeScreenFilterAction(block.action) !== (block.action ?? "apply")) {
          pushIssue("warning", "滤镜动作不认识，预览时会回退成开启滤镜。", location, blockContext);
        }
        if (getSafeScreenFilterAction(block.action) !== "clear") {
          if (getSafeScreenFilterPreset(block.preset) !== (block.preset ?? "memory")) {
            pushIssue("warning", "滤镜风格不认识，预览时会回退成暖色回忆。", location, blockContext);
          }
          if (getSafeScreenFilterStrength(block.strength) !== (block.strength ?? "medium")) {
            pushIssue("warning", "滤镜强度不认识，预览时会回退成正常。", location, blockContext);
          }
          Object.entries(SCREEN_COLOR_GRADE_LIMITS).forEach(([key, [minimum, maximum]]) => {
            const rawValue = block.grade?.[key];
            if (rawValue === undefined || rawValue === null || rawValue === "") {
              return;
            }
            const numericValue = Number(rawValue);
            if (!Number.isFinite(numericValue) || numericValue < minimum || numericValue > maximum) {
              pushIssue("warning", "画面调色参数超出范围，预览时会自动限制到安全值。", location, blockContext);
            }
          });
        }
        break;
      case "depth_blur":
        if (getSafeDepthBlurAction(block.action) !== (block.action ?? "apply")) {
          pushIssue("warning", "景深动作不认识，预览时会回退成开启景深。", location, blockContext);
        }
        if (getSafeDepthBlurAction(block.action) !== "clear") {
          if (getSafeDepthBlurFocus(block.focus) !== (block.focus ?? "center")) {
            pushIssue("warning", "景深重点位置不认识，预览时会回退成中间角色更清楚。", location, blockContext);
          }
          if (getSafeDepthBlurStrength(block.strength) !== (block.strength ?? "medium")) {
            pushIssue("warning", "景深强度不认识，预览时会回退成正常。", location, blockContext);
          }
        }
        break;
      case "dialogue":
        requireCharacterExpression(block.speakerId, block.expressionId);
        validateReadableTextLength(block.text, "台词", location, blockContext, pushIssue);
        if (block.voiceAssetId) {
          requireAsset(block.voiceAssetId);
        } else {
          pushIssue("warning", "这句台词还没有绑定语音。", location, blockContext);
        }
        break;
      case "narration":
        validateReadableTextLength(block.text, "旁白", location, blockContext, pushIssue);
        if (block.voiceAssetId) {
          requireAsset(block.voiceAssetId);
        }
        break;
      case "character_show":
        requireCharacterExpression(block.characterId, block.expressionId);
        break;
      case "character_hide":
        if (!data.charactersById.has(block.characterId)) {
          pushIssue("error", "要隐藏的角色不存在。", `${location} -> ${block.characterId}`, blockContext);
        }
        break;
      case "jump":
        requireScene(block.targetSceneId, "跳转目标场景");
        break;
      case "variable_set":
        requireVariable(block.variableId);
        if (!matchesVariableType(block.variableId, block.value)) {
          pushIssue("error", "变量设置卡片的值类型不对。", location, blockContext);
        }
        break;
      case "variable_add": {
        requireVariable(block.variableId);
        const variable = data.variablesById.get(block.variableId);
        if (variable?.type !== "number" || typeof block.value !== "number") {
          pushIssue("error", "数字变量加减卡片的值不正确。", location, blockContext);
        }
        break;
      }
      case "choice":
      if ((block.options ?? []).length > VN_CHOICE_MANY_OPTIONS) {
        pushIssue(
          "warning",
          `这个选项卡有 ${(block.options ?? []).length} 个选项，按钮区可能会拥挤。`,
          location,
          blockContext
        );
      }
      (block.options ?? []).forEach((option) => {
        if (!option.text?.trim()) {
          pushIssue("error", "有空白选项文案。", `${location} -> ${option.id}`, blockContext);
        } else if (String(option.text).trim().length > VN_CHOICE_LONG_WARNING_LENGTH) {
          pushIssue(
            "warning",
            "选项文案偏长，原生 Runtime 按钮里可能会被截断。",
            `${location} -> ${truncateText(option.text, 48)}`,
            blockContext
          );
        }
        requireScene(option.gotoSceneId, "选项跳转场景");
        (option.effects ?? []).forEach((effect) => {
          requireVariable(effect.variableId);
          if (effect.type === "variable_add") {
            const variable = data.variablesById.get(effect.variableId);
            if (variable?.type !== "number" || typeof effect.value !== "number") {
              pushIssue("error", "选项里的数字变化效果写得不正确。", `${location} -> ${option.id}`, blockContext);
            }
          }
          if (effect.type === "variable_set" && !matchesVariableType(effect.variableId, effect.value)) {
            pushIssue("error", "选项里的变量设置效果值类型不对。", `${location} -> ${option.id}`, blockContext);
          }
        });
      });
      break;
    case "condition":
      (block.branches ?? []).forEach((branch) => {
        (branch.when ?? []).forEach((condition) => {
          requireVariable(condition.variableId);
          if (!matchesVariableType(condition.variableId, condition.value)) {
            pushIssue("error", "条件判断里的比较值类型不对。", `${location} -> ${condition.variableId}`, blockContext);
          }
        });
        requireScene(branch.gotoSceneId, "条件分支目标场景");
      });
      requireScene(block.elseGotoSceneId, "条件未命中时的目标场景");
      break;
    default:
      break;
  }
}

function countAssetsByType(assetList = state.data.assetList) {
  const counts = new Map();
  assetList.forEach((asset) => {
    counts.set(asset.type, (counts.get(asset.type) ?? 0) + 1);
  });
  return counts;
}

function getExpressionName(characterId, expressionId) {
  const character = state.data.charactersById.get(characterId);
  const expression = character?.expressions?.find((item) => item.id === expressionId);
  return expression?.name ?? expressionId ?? "默认";
}

function getPositionLabel(position) {
  return POSITION_LABELS[position] ?? position ?? "未设置";
}

function getPositionOrder(position) {
  if (position === "left") return 0;
  if (position === "center") return 1;
  if (position === "right") return 2;
  return 3;
}

function getDefaultCharacterPosition(characterId) {
  return state.data.charactersById.get(characterId)?.defaultPosition ?? "center";
}

function getAssetTypeLabel(type) {
  return assetCatalogTools?.getAssetTypeLabel?.(type) ?? ASSET_TYPE_LABELS[type] ?? type;
}

function getTemplateLabel(template) {
  return storyTemplateTools.getTemplateLabel(template);
}

function isImageAssetType(type) {
  if (assetCatalogTools?.isImageAssetType) {
    return assetCatalogTools.isImageAssetType(type);
  }

  return ["background", "sprite", "cg", "ui"].includes(type);
}

function isAudioAssetType(type) {
  if (assetCatalogTools?.isAudioAssetType) {
    return assetCatalogTools.isAudioAssetType(type);
  }

  return ["bgm", "sfx", "voice"].includes(type);
}

function isVideoAssetType(type) {
  if (assetCatalogTools?.isVideoAssetType) {
    return assetCatalogTools.isVideoAssetType(type);
  }

  return type === "video";
}

function isScene3dAssetType(type) {
  if (assetCatalogTools?.isScene3dAssetType) {
    return assetCatalogTools.isScene3dAssetType(type);
  }

  return type === "scene3d";
}

function getSafeVideoFit(value) {
  return visualEffectTools?.getSafeVideoFit?.(value) ?? (
    Object.prototype.hasOwnProperty.call(VIDEO_FIT_LABELS, value) ? value : "contain"
  );
}

function getVideoFitLabel(value) {
  return visualEffectTools?.getVideoFitLabel?.(value) ?? VIDEO_FIT_LABELS[getSafeVideoFit(value)] ?? VIDEO_FIT_LABELS.contain;
}

function getSafeVideoVolume(value) {
  if (visualEffectTools?.getSafeVideoVolume) {
    return visualEffectTools.getSafeVideoVolume(value);
  }

  const number = Number(value);
  if (!Number.isFinite(number)) {
    return 100;
  }
  return Math.round(clamp(number, 0, 100));
}

function getSafeCreditsDuration(value) {
  if (visualEffectTools?.getSafeCreditsDuration) {
    return visualEffectTools.getSafeCreditsDuration(value);
  }

  const number = Number(value);
  if (!Number.isFinite(number)) {
    return 18;
  }
  return Math.round(clamp(number, 4, 180));
}

function getSafeCreditsBackground(value) {
  return visualEffectTools?.getSafeCreditsBackground?.(value) ?? (
    Object.prototype.hasOwnProperty.call(CREDITS_BACKGROUND_LABELS, value) ? value : "dark"
  );
}

function getCreditsBackgroundLabel(value) {
  return visualEffectTools?.getCreditsBackgroundLabel?.(value) ?? (
    CREDITS_BACKGROUND_LABELS[getSafeCreditsBackground(value)] ?? CREDITS_BACKGROUND_LABELS.dark
  );
}

function parseCreditsLines(value) {
  if (visualEffectTools?.parseCreditsLines) {
    return visualEffectTools.parseCreditsLines(value);
  }

  return String(value ?? "")
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter(Boolean);
}

function getCreditsLines(blockLines) {
  if (visualEffectTools?.getCreditsLines) {
    return visualEffectTools.getCreditsLines(blockLines);
  }

  if (Array.isArray(blockLines)) {
    return blockLines.map((line) => String(line ?? "").trim()).filter(Boolean);
  }
  return parseCreditsLines(blockLines);
}

function getCreditsLinesText(blockLines) {
  return visualEffectTools?.getCreditsLinesText?.(blockLines) ?? getCreditsLines(blockLines).join("\n");
}

function getAssetPublicUrl(asset) {
  if (!asset) {
    return "";
  }
  return asset.publicPath || buildTemplateAssetUrl(asset.path);
}

function getBackdropStyle(backgroundAssetId, scene3dPreview = null) {
  const asset = state.data?.assetsById?.get(backgroundAssetId);
  const previewUrl = getAssetPublicUrl(asset);
  if (asset?.fileExists && isScene3dAssetType(asset.type)) {
    const preview = getSafeScene3dPreviewConfig(scene3dPreview);
    const pitchGlow = Math.round(clamp((preview.pitch - 12) / 60, 0, 1) * 24 + 22);
    const gridSize = Math.round(clamp(44 / preview.zoom, 24, 76));
    const yawOffset = Math.round(((preview.yaw % 360) / 360) * gridSize);
    return `background: radial-gradient(circle at 50% ${pitchGlow}%, rgba(102, 180, 255, 0.30), transparent 24%), linear-gradient(135deg, rgba(7, 18, 36, 0.92), rgba(28, 42, 76, 0.86)), repeating-linear-gradient(${90 + preview.yaw / 8}deg, rgba(126, 190, 255, 0.12) 0 1px, transparent 1px ${gridSize}px), repeating-linear-gradient(${preview.pitch}deg, rgba(126, 190, 255, 0.10) ${yawOffset}px ${yawOffset + 1}px, transparent ${yawOffset + 1}px ${gridSize}px);`;
  }
  if (asset?.fileExists && previewUrl && isImageAssetType(asset.type)) {
    return `background: linear-gradient(180deg, rgba(255,255,255,0.08), rgba(255,255,255,0.24)), url("${escapeHtml(
      previewUrl
    )}") center / cover no-repeat;`;
  }

  const gradients = {
    bg_classroom_sunset:
      "background: linear-gradient(180deg, rgba(255,255,255,0.08), rgba(255,255,255,0.28)), linear-gradient(180deg, #f1ca93 0%, #f0b27c 36%, #b86d55 100%);",
    bg_hallway_after_school:
      "background: linear-gradient(180deg, rgba(255,255,255,0.08), rgba(255,255,255,0.28)), linear-gradient(180deg, #f6d9ac 0%, #eaa572 45%, #905742 100%);",
    bg_rooftop_evening:
      "background: linear-gradient(180deg, rgba(255,255,255,0.05), rgba(255,255,255,0.18)), linear-gradient(180deg, #f7d7b0 0%, #d39a7a 40%, #70516f 100%);",
  };
  return gradients[backgroundAssetId] ?? gradients.bg_classroom_sunset;
}

state.previewPlayback.uiThemeMode = loadStoredEditorUiThemeMode();
applyEditorUiTheme(state.previewPlayback.uiThemeMode);
scheduleEditorUiThemeAutoRefresh();
